insert into unit_enemy_data values (200100, 'ウキキー', 200100, 0, 0, 270, 800, 1, 3.5, 0, 0, 0, '【物理】遠距離攻撃\\n大きな岩を投げて、遠くから\\n攻撃してくるサルの魔物。');
insert into unit_enemy_data values (200200, 'バルーンバード', 200200, 0, 0, 270, 800, 1, 3.0, 0, 0, 0, '【回復】範囲回復\\nぷっくりお腹に溜めた魔力を、\\n癒しの波動に変えるトリの魔物。');
insert into unit_enemy_data values (200300, 'ゲートキーパー', 200300, 0, 0, 270, 200, 2, 3.5, 0, 0, 0, '【魔法】範囲攻撃\\n地獄のトビラを開き、火傷を伴う\\n炎を吐きだす魔界の番人。');
insert into unit_enemy_data values (200301, 'ゲートキーパー', 200300, 0, 0, 270, 350, 2, 3.5, 0, 0, 0, '【魔法】範囲攻撃\\n地獄のトビラを開き、火傷を伴う\\n炎を吐きだす魔界の番人。');
insert into unit_enemy_data values (200302, 'ゲートキーパー', 200300, 0, 0, 270, 500, 2, 3.5, 0, 0, 0, '【魔法】範囲攻撃\\n地獄のトビラを開き、火傷を伴う\\n炎を吐きだす魔界の番人。');
insert into unit_enemy_data values (200400, 'ウェアウルフ', 200400, 0, 0, 270, 350, 1, 2.5, 0, 0, 0, '【物理】近接攻撃\\nするどいツメで敵を切り刻む、\\nオオカミの魔物。');
insert into unit_enemy_data values (200500, 'ワイルドホーン', 200500, 0, 16, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近接攻撃\\n大きな角を攻撃にも\\n防御にも使う、シカの魔物。');
insert into unit_enemy_data values (200501, 'スノウゴート', 200501, 0, 16, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近接攻撃\\n高山に住み、分厚い毛皮の下に、\\n強靭な体を持つトナカイの魔物。');
insert into unit_enemy_data values (200503, 'ワイルドホーン', 200503, 0, 16, 750, 580, 1, 3.0, 0, 0, 0, '');
