insert into unit_enemy_data values (200600, 'ラットン', 200600, 0, 11, 270, 250, 1, 1.5, 0, 0, 0, '【物理】近接攻撃\\n威力は軽くても、すばしこく\\n何度も攻撃するネズミの魔物。');
insert into unit_enemy_data values (200700, 'ウッドソウル', 200700, 0, 17, 270, 400, 2, 3.0, 0, 0, 0, '【魔法】中距離攻撃\\n魔力の弾を投げつけて、\\n少し後ろを攻撃する朽木の魔物。');
insert into unit_enemy_data values (200701, 'ロックソウル', 200701, 0, 17, 270, 400, 2, 3.0, 0, 0, 0, '【魔法】中距離攻撃\\n燃えさかる炎を投げつけ、火傷の\\n追加ダメージを与える呪いの石像。');
insert into unit_enemy_data values (200800, 'ビッグル', 200800, 0, 15, 270, 1080, 1, 3.5, 0, 0, 0, '【物理】遠距離攻撃\\n岩を食べられるほど頑丈な\\n歯をもつ山の精霊。');
insert into unit_enemy_data values (200801, 'ムックル', 200801, 0, 15, 270, 1080, 1, 3.5, 0, 0, 0, '【物理】遠距離攻撃\\n氷の塊を武器にも食料\\nにもする雪山の精霊。');
insert into unit_enemy_data values (200900, 'スタンプ', 200900, 0, 15, 270, 200, 1, 2.5, 0, 0, 0, '【物理】前衛・近接攻撃\\nしなやかな枝を、ムチのように\\n使い攻撃する木の魔物。');
insert into unit_enemy_data values (200901, 'ネジレアカシア', 200901, 0, 15, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近接攻撃\\nねじれ集まった枝で、冒険者を\\n森の奥に引き込むマメの木の魔物。');
insert into unit_enemy_data values (200902, 'トレント', 200902, 0, 15, 270, 200, 1, 0.5, 0, 0, 0, '【物理】中距離攻撃\\n枝を自在に伸ばし、老練な技で\\n痛いところに手が届く朽木の魔物。');
insert into unit_enemy_data values (200903, 'トレント', 200902, 0, 15, 270, 3000, 1, 0.5, 0, 0, 0, '【物理】中距離攻撃\\n枝を自在に伸ばし、老練な技で\\n痛いところに手が届く朽木の魔物。');
insert into unit_enemy_data values (200904, 'トレント', 200904, 0, 15, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】中距離攻撃\\n枝を自在に伸ばし、老練な技で\\n痛いところに手が届く朽木の魔物。');
insert into unit_enemy_data values (200905, 'トレント', 200905, 0, 15, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】中距離攻撃\\n枝を自在に伸ばし、老練な技で\\n痛いところに手が届く朽木の魔物。');
insert into unit_enemy_data values (201000, 'スカルフレイム', 201000, 0, 17, 270, 1080, 2, 3.0, 0, 0, 0, '【魔法】中距離攻撃\\n地獄の炎をまとい、\\n生者に襲い掛かる怨念の集合体。');
insert into unit_enemy_data values (201100, 'コボルト', 201100, 0, 15, 270, 650, 1, 3.5, 0, 0, 0, '【物理】中距離攻撃\\nブーメランのように組んだ骨を、\\n投げて攻撃する山犬の魔物。');
insert into unit_enemy_data values (201101, 'コボルトアサシン', 201101, 0, 15, 270, 650, 1, 0.5, 0, 0, 0, '【物理】中距離攻撃\\n素早いステップで翻弄し、わずかな\\n隙にナイフを飛ばす、山犬の魔物。');
insert into unit_enemy_data values (201102, 'コボルトアサシン', 201102, 0, 15, 350, 370, 1, 0.5, 0, 0, 0, '【物理】中距離攻撃\\n素早いステップで翻弄し、わずかな\\n隙にナイフを飛ばす、山犬の魔物。');
insert into unit_enemy_data values (201200, 'ゴーレム', 201200, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】近接攻撃\\n頑丈な身体で、攻守を備えた\\n岩の魔物。');
insert into unit_enemy_data values (201201, 'ブルーゴーレム', 201201, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】【魔法防御】近接攻撃\\n魔力を秘めた岩から生まれた、\\n魔法耐性のあるゴーレム。');
insert into unit_enemy_data values (201202, 'ブルーゴーレム', 201202, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】【魔法防御】近接攻撃\\n魔力を秘めた岩から生まれた、\\n魔法耐性のあるゴーレム。');
insert into unit_enemy_data values (201203, 'ゴーレム', 201203, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】近接攻撃\\n頑丈な身体で、攻守を備えた\\n岩の魔物。');
insert into unit_enemy_data values (201204, 'ブルーゴーレム', 201204, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】【魔法防御】近接攻撃\\n魔力を秘めた岩から生まれた、\\n魔法耐性のあるゴーレム。');
insert into unit_enemy_data values (201205, 'ブルーゴーレム', 201201, 0, 16, 270, 50, 1, 5.0, 0, 0, 0, '【物理】【魔法防御】近接攻撃\\n魔力を秘めた岩から生まれた、\\n魔法耐性のあるゴーレム。');
insert into unit_enemy_data values (201300, 'ロックフラワー', 201300, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距離攻撃\\n小石を弾丸のように飛ばして\\n攻撃する、岩でできた動く花。');
insert into unit_enemy_data values (201301, 'マッドフラワー', 201301, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距離攻撃\\n尾の花はひどい臭いを放つが、\\n慣れると案外癖になるらしい。');
insert into unit_enemy_data values (201302, 'カクタスフラワー', 201302, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距離攻撃\\n触ると痺れる針山を無限に\\n飛ばしてくる、動くサボテン。');
insert into unit_enemy_data values (201400, 'エルダークラウド', 201400, 0, 0, 270, 1080, 2, 3.0, 0, 0, 0, '【魔法】【補助】範囲攻撃\\n気象を自在に操り、\\n雷を落とす雲の魔物。');
insert into unit_enemy_data values (201500, 'モグリクラゲ', 201500, 0, 0, 270, 780, 2, 3.0, 0, 0, 0, '【回復】範囲回復\\n拾った潜水服に水を溜め、\\n陸でも戦えるクラゲの魔物。');
insert into unit_enemy_data values (201600, 'ドリアード', 201600, 0, 15, 270, 800, 2, 2.5, 0, 0, 0, '【魔法】【召喚】近接攻撃\\n大地の魔力でキノコの魔物\\nを自在に生やす、森の精霊。');
insert into unit_enemy_data values (201602, 'ニンフ', 201602, 0, 15, 270, 800, 2, 2.5, 0, 0, 0, '【魔法】中距離攻撃\\n遊び相手を見つけては、見境なしに\\nイタズラをする、森の精霊。');
insert into unit_enemy_data values (201700, '動く戦士像', 201700, 0, 16, 270, 150, 1, 4.0, 0, 0, 0, '【物理】【魔法防御】近接攻撃\\nあらゆる魔法攻撃を防ぐ\\n盾をもった、命ある石像。');
insert into unit_enemy_data values (201800, '動く剣士', 201800, 0, 5, 270, 150, 1, 4.0, 0, 0, 0, '【物理】【物理防御】近接攻撃\\nあらゆる物理攻撃を\\n剣ではじき返す、命ある石像。');
insert into unit_enemy_data values (201900, 'ウパルパ', 201900, 0, 0, 270, 1080, 1, 3.0, 0, 0, 0, '【物理】遠距離攻撃\\nヘドロの沼に棲み、口から\\n強力な毒を吐く山椒魚の魔物。');
insert into unit_enemy_data values (201901, 'マグマウパルパ', 201901, 0, 0, 270, 1080, 1, 3.0, 0, 0, 0, '【物理】遠距離攻撃\\n熔岩の海に潜み、近づくものには\\n灼熱の体液を吐く、山椒魚の魔物。');
insert into unit_enemy_data values (202000, 'タートルタイラント', 202000, 0, 16, 270, 150, 1, 5.5, 0, 0, 0, '【物理】【物理防御】近接攻撃\\nあらゆる物理攻撃を\\n甲羅ではじく、巨大ガメの魔物。');
insert into unit_enemy_data values (202100, 'ヒカリタケ', 202100, 0, 14, 270, 200, 1, 2.0, 0, 0, 0, '【物理】近接攻撃\\nドリアードの召喚に応じて、\\n無限に生えてくるキノコの精霊。');
insert into unit_enemy_data values (202101, 'ベニタケ', 202101, 0, 14, 270, 200, 1, 2.0, 0, 0, 0, '【物理】近接攻撃\\n煮込むと意外と美味いという\\nウワサの歩くキノコ。');
insert into unit_enemy_data values (202200, 'ウイングロップ', 202200, 0, 15, 270, 650, 2, 3.5, 0, 0, 0, '【魔法】近接攻撃\\n大きな耳をはばたかせて、\\n勢いよく突き上げるウサギの魔物。');
insert into unit_enemy_data values (202300, 'ファイヤーメイジ', 202300, 0, 17, 270, 1080, 2, 3.5, 0, 0, 0, '【魔法】遠距離攻撃\\n地獄から呼び寄せた炎で\\n魔法を飛ばす上級悪魔。');
insert into unit_enemy_data values (202301, 'ファイヤーメイジ', 202301, 0, 17, 270, 1080, 2, 3.5, 0, 0, 0, '【魔法】遠距離攻撃\\n地獄から呼び寄せた炎で\\n魔法を飛ばす上級悪魔。');
insert into unit_enemy_data values (202400, 'ケイブエイプ', 202400, 0, 12, 270, 750, 1, 3.0, 0, 0, 0, '【物理】近接攻撃\\n強靭な腕の筋肉で、鍾乳石を\\n掴んで渡る大ザルの魔物。');
insert into unit_enemy_data values (202500, 'バットケイブ', 202500, 0, 15, 270, 550, 2, 3.5, 0, 0, 0, '【魔法】近接攻撃\\n洞窟に棲み、獲物の足音を聞いて\\n襲い掛かる、コウモリの魔物。');
insert into unit_enemy_data values (202600, 'ケイブスネイル', 202600, 0, 0, 270, 750, 2, 4.0, 0, 0, 0, '【回復】範囲回復\\n分泌するヌルヌルが美容にいいと\\nウワサの、カタツムリの魔物。');
insert into unit_enemy_data values (202700, 'ハーミットナイト', 202700, 0, 6, 270, 350, 1, 3.0, 0, 0, 0, '【物理】近接攻撃\\n倒した騎士の兜を、貝殻の\\n代わりに被るヤドカリの戦士。');
insert into unit_enemy_data values (202800, 'タビガラス', 202800, 0, 4, 270, 650, 1, 3.0, 0, 0, 0, '【物理】範囲攻撃\\nアストルム中の強い魔物を\\n倒して回ったという放浪カラス。');
