insert into unit_enemy_data values (202900, 'ポイドン', 202900, 0, 14, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近接攻撃\\nするどいキバで咬みつき\\n致命的な傷を残す毒トカゲの魔物。');
insert into unit_enemy_data values (202901, 'ロックリザード', 202901, 0, 14, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近接攻撃\\n頭の皮膚が固くなり\\n鎧のようになった岩トカゲの魔物。');
insert into unit_enemy_data values (202902, 'グラスリザード', 202902, 0, 14, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近接攻撃\\n葉っぱの襟巻が鮮やかな\\nトカゲ魔物界のオシャレ番長。');
insert into unit_enemy_data values (202903, 'ロックリザード', 202903, 0, 14, 270, 2050, 1, 3.0, 0, 0, 0, '【物理】近接攻撃\\n頭の皮膚が固くなり\\n鎧のようになった岩トカゲの魔物。');
insert into unit_enemy_data values (202904, 'サラマンダー', 202904, 0, 14, 270, 200, 1, 0.5, 0, 0, 0, '【物理】近接攻撃\\n尾先の炎を燃やし続けることで\\n常に躰を温め、二連撃を繰り出す\\nトカゲの魔物。');
insert into unit_enemy_data values (202905, 'マインリザード', 202905, 0, 14, 270, 100, 1, 3.0, 0, 0, 0, '【物理】近接攻撃\\nハイ・ガルグのおこぼれにあずかる、岩トカゲ。ルナの魔力でより堅牢な鉱石の表皮に変貌した。');
insert into unit_enemy_data values (203000, 'ゼラチナ', 203000, 0, 15, 270, 200, 2, 2.0, 0, 0, 0, '【魔法】近接攻撃\\n物理攻撃が当たりにくい\\nとってもヌルヌルなゼリーの魔物。');
