insert into unit_enemy_data values (203100, 'コドモオオトカゲ', 203100, 0, 17, 270, 800, 2, 3.5, 0, 0, 0, '【魔法】近接攻撃\\n小さくても強力な炎を吐く、\\nこどものオオトカゲ。');
insert into unit_enemy_data values (203200, 'インプ', 203200, 0, 12, 270, 650, 2, 3.5, 0, 0, 0, '【魔法】近接攻撃\\n身の丈に合わない大きなカギ爪で\\nひっかき攻撃する、見習い悪魔。');
insert into unit_enemy_data values (203300, 'ゴブリンガード', 203300, 0, 15, 270, 150, 1, 4.0, 0, 0, 0, '【物理】近接攻撃\\n身の丈ほどもある、巨大な盾で\\n仲間を護る見習いゴブリン兵。');
insert into unit_enemy_data values (203301, 'ジャングルガード', 203301, 0, 15, 270, 150, 1, 4.0, 0, 0, 0, '【物理】近接攻撃\\n顔にも見える大きな盾で敵を威嚇し\\n侵入者を阻む、ジャングルの護り人。');
insert into unit_enemy_data values (203302, 'ゴブリンガード', 203300, 0, 15, 270, 50, 1, 4.0, 0, 0, 0, '【物理】近接攻撃\\n身の丈ほどもある、巨大な盾で\\n仲間を護る見習いゴブリン兵。');
insert into unit_enemy_data values (203303, 'ゴブリンガード', 203303, 0, 15, 350, 170, 1, 4.0, 0, 0, 0, '【物理】近接攻撃\\n身の丈ほどもある、巨大な盾で\\n仲間を護る見習いゴブリン兵。');
insert into unit_enemy_data values (203400, 'ホオズキムシ', 203400, 0, 0, 270, 800, 2, 4.0, 0, 0, 0, '【回復】単体回復\\nお尻に溜まった蜜が、魔物の\\n栄養源になる、不思議なホタル。');
insert into unit_enemy_data values (203402, 'ホオズキムシ', 203400, 0, 0, 270, 3000, 2, 4.0, 0, 0, 0, '【回復】単体回復\\nお尻に溜まった蜜が、魔物の\\n栄養源になる、不思議なホタル。');
