insert into unit_enemy_data values (203700, 'ナッツシューター', 203700, 0, 15, 270, 350, 1, 2.5, 0, 0, 0, '【物理】範囲攻撃\\n食べたナッツの殻をぶつけてくる\\n意地悪なリスの魔物。');
insert into unit_enemy_data values (203702, 'スティンクスカンク', 203702, 0, 15, 270, 350, 1, 2.5, 0, 0, 0, '【物理】範囲攻撃\\n目にしみる激臭ガス爆弾を、自在に\\n駆使する、スカンクの魔物。');
