insert into unit_enemy_data values (206900, 'スリーピィオウル', 206900, 0, 0, 270, 645, 2, 3.5, 0, 0, 0, '【魔法】中距離攻撃\\n寝不足で気怠げなフクロウの魔物。\\n敵を睨み術をかけ、動きを奪う。');
insert into unit_enemy_data values (206901, 'スリーピィオウル', 206901, 0, 0, 270, 645, 2, 3.5, 0, 0, 0, '【魔法】中距離攻撃\\n寝不足で気怠げなフクロウの魔物。\\n敵を睨み術をかけ、動きを奪う。');
insert into unit_enemy_data values (207000, 'ワッパダヌキ', 207000, 0, 0, 100, 120, 2, 0.5, 0, 0, 0, '【魔法】一定時間無敵・中距離攻撃\\n幼いながらも巧みな変化で\\n攻守を必死にこなす豆狸の魔物。');
insert into unit_enemy_data values (207001, 'ワッパダヌキ', 207000, 0, 0, 100, 120, 2, 0.5, 0, 0, 0, '【魔法】一定時間無敵・中距離攻撃\\n幼いながらも巧みな変化で\\n攻守を必死にこなす豆狸の魔物。');
insert into unit_enemy_data values (207100, 'キラービー', 207100, 0, 0, 270, 550, 1, 0.9, 0, 0, 0, '【物理】遠距離攻撃\\n脅威となる敵をいち早く察知し、\\n的確に狙い穿つハチの魔物。');
insert into unit_enemy_data values (207101, 'キラービー', 207100, 0, 0, 270, 650, 1, 1.2, 0, 0, 0, '【物理】遠距離攻撃\\n脅威となる敵をいち早く察知し、\\n的確に狙い穿つハチの魔物。');
insert into unit_enemy_data values (207102, 'キラービー', 207100, 0, 0, 270, 750, 1, 1.5, 0, 0, 0, '【物理】遠距離攻撃\\n脅威となる敵をいち早く察知し、\\n的確に狙い穿つハチの魔物。');
insert into unit_enemy_data values (207200, 'ウーピーオーク', 207200, 0, 0, 270, 360, 1, 2.5, 0, 0, 0, '【物理】近接攻撃\\n大人を真似て、楽器をたたく、\\n悪戯好きなオークのこども。');
insert into unit_enemy_data values (207201, 'ウーピーオーク', 207200, 0, 0, 270, 120, 1, 5.0, 0, 0, 0, '【物理】近接攻撃\\n大人を真似て、楽器をたたく、\\n悪戯好きなオークのこども。');
insert into unit_enemy_data values (207300, 'イワアライグマ', 207300, 0, 0, 270, 550, 0, 2.5, 0, 0, 0, '【物理】中距離攻撃\\n行き過ぎた綺麗好きのアライグマ。\\n特製のガマ油石鹸を一度浴びると、\\nまともに武器も握れない。');
