insert into unit_enemy_data values (305007, 'ジャック・オー・プリン', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】人間への復讐を企む、霊界の住人。\\n「オイラはジャック！ジャック・オー・プリン！\\n\u3000遊んでくれなきゃ、イタズラしちゃうぞ～」\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理中ダメージを与え、\\n\u3000キャラのＨＰが40%を切っている場合、\\n\u3000誘惑状態にする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000キャラのステータスアップ効果を解除。\\n・最も近い敵に物理大ダメージを与え、\\n\u3000さらに、前から３キャラに、物理中\\n\u3000ダメージ＆スタン。\\n・ジャック・オー・プリン自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。\\n');
insert into unit_enemy_data values (305100, 'メガラパーン', 305100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】巨体を駆使して暴れ回る大ウサギの魔物。\\n繰り出す一撃は消耗が大きく、持てあまし気味。\\n\\n・ユニオンバーストは敵全体に物理大ダメージ\\n\u3000を与え、さらにノックバックさせる。\\n\u3000その後、目を回している間、自身の物理防御\\n\u3000力と魔法防御力が大幅にダウン。\\n・敵全体に物理中ダメージを与え、さらに前方\\n\u3000範囲内の敵をスタンさせる。\\n\u3000このスキルの状態異常はダメージを無効化し\\n\u3000ても付与される。');
insert into unit_enemy_data values (305101, 'メガラパーン', 305100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】巨体を駆使して暴れまわる\\n大ウサギの魔物。繰り出す一撃は\\n消耗が大きく、持てあまし気味。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000さらにノックバックさせる。\\n\u3000その後、目を回している間、\\n\u3000自身の物理防御力と魔法防御力が\\n\u3000大幅にダウン。\\n\\n・敵全体に物理中ダメージを与え、\\n\u3000さらに前方範囲内の敵をスタン\\n\u3000させる。');
insert into unit_enemy_data values (305102, 'メガラパーン', 305102, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】巨体を駆使して暴れ回る大ウサギの魔物。\\n繰り出す一撃は消耗が大きく、持てあまし気味。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与え、さらにノックバックさせる。\\n\u3000目を回している間、自身の物理防御力と魔法防\\n\u3000御力を特大ダウン。\\n\u3000その後、自身の物理防御力と魔法防御力を小ダ\\n\u3000ウン。\\n\u3000このスキルの状態異常はダメージを無効化し\\n\u3000ても付与される。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に物理中ダメージを与え、さらに前方\\n\u3000範囲内の敵をスタンさせる。\\n\u3000その後、自身のＴＰを中回復。\\n\u3000このスキルの状態異常はダメージを無効化し\\n\u3000ても付与される。\\n・通常攻撃は先頭のキャラに物理大ダメージを\\n\u3000与え、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化し\\n\u3000ても付与される。');
insert into unit_enemy_data values (305200, 'オラム', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与えたのち、\\n\u3000自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理中ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (305201, 'オラム', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与えたのち、\\n\u3000自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。');
insert into unit_enemy_data values (305202, 'オラム', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与えたのち、\\n\u3000自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理中ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (305203, 'オラム', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与えたのち、\\n\u3000自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理中ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (305204, 'カース・オラム', 305204, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ルナの塔の魔力で暴走する、古代兵器。\\n古き守護の力は、呪いを振りまく大禍と化した。\\n\\n・敵全体に物理大ダメージを与え、自身の\\n\u3000物理防御力と魔法防御力を大ダウンさせる。\\n・前方１キャラを中心にした範囲内の敵すべてに\\n\u3000物理中ダメージを与え、物理防御力を中ダウン\\n\u3000させる。さらにスタンを与える。\\n・敵全体に物理中ダメージを与え、呪い状態\\n\u3000にする。キャラのＨＰが40％以下の場合、\\n\u3000呪いのダメージが２倍になる。');
insert into unit_enemy_data values (305205, 'オラム', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n最大ＨＰに応じた物理大ダメージを与えた\\nのち、自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理中ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (305206, 'オラム', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・ユニオンバーストは、自身の物理攻撃力を\\n\u3000大ダウンしたのち、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理大ダメージを与える。\\n・前方中範囲内の敵に物理大ダメージを与え、\\n\u3000物理攻撃力を大ダウン。');
insert into unit_enemy_data values (305207, 'オラム', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・ユニオンバーストは、自身の物理攻撃力を\\n\u3000大ダウンしたのち、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理大ダメージを与える。\\n・前方中範囲内の敵に物理大ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理大ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (305208, 'オラム', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・ユニオンバーストは、自身の物理攻撃力を\\n\u3000大ダウンしたのち、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理大ダメージを与える。\\n・前方中範囲内の敵に物理大ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理大ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (305300, 'ハイ・ガルグ', 305300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ルナの魔力を帯び変異した獰猛な魔獣。\\n強靭な歯牙は歴戦の冒険者さえ容易く切り裂く。\\n\\n・ユニオンバーストは敵全体に物理大ダメージを\\n\u3000与え、さらに自分のＨＰを回復する。\\n・後方範囲内の敵に物理ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらに敵全体の物理防御力を中ダウンさせる。\\n・前方範囲内の敵に物理ダメージを与え、毒状態\\n\u3000にする。');
insert into unit_enemy_data values (305301, 'アイスガルグ', 305301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】雪山に棲む獰猛な魔狼。\\n強靭な歯牙は歴戦の冒険者さえ\\n容易く氷塊の墓標へ変える。\\n\\n・ユニオンバーストは敵全体に物\\n\u3000理大ダメージを与える。\\n\\n・一番後ろの敵キャラを中心とし\\n\u3000て、範囲内の敵すべてに物理小\\n\u3000ダメージを与え、スタンさせる。\\n\u3000さらに敵全体の物理防御力を中\\n\u3000ダウンさせる。\\n\\n・前方範囲内の敵すべてに物理小\\n\u3000ダメージを与え、毒状態にする。');
insert into unit_enemy_data values (305302, 'アイスガルグ', 305301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】雪山に棲む獰猛な魔狼。\\n強靭な歯牙は歴戦の冒険者さえ\\n容易く氷塊の墓標へ変える。\\n\\n・ユニオンバーストは敵全体に物\\n\u3000理大ダメージを与える。\\n\\n・一番後ろの敵キャラを中心とし\\n\u3000て、範囲内の敵すべてに物理小\\n\u3000ダメージを与え、スタンさせる。\\n\u3000さらに敵全体の物理防御力を中\\n\u3000ダウンさせる。\\n\\n・前方範囲内の敵すべてに物理小\\n\u3000ダメージを与え、毒状態にする。');
insert into unit_enemy_data values (305400, 'アイスホーン', 305400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】強力な氷の頭突きで\\n堅牢な盾も貫き穿つ一角獣。\\n氷丘押し寄せる北の果てで、\\n冒険者を氷獄へ突き落す。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n\u3000さらに、味方全体のＴＰ上昇率を\\n\u3000上げる。\\n\\n・前方小範囲内に魔法小ダメージを\\n\u3000与え、氷結状態にする。さらに、\\n\u3000全体に魔法小ダメージを与え、\\n\u3000前方3キャラを小さく\\n\u3000吹き飛ばす。');
insert into unit_enemy_data values (305500, 'フォギー', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実態を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法中ダメージを与える。\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）（青）のうち、\\n\u3000いずれか1体を召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法中ダメージを与える。\\n・【物理】分身体（青）は、敵全体に\\n\u3000魔法中ダメージ。\\n\u3000さらに、呪い状態にする。\\n\u3000分身体（青）のＨＰが30％以下になった時、\\n\u3000フォギーのＴＰを300回復させる。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (305501, 'フォギー', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実態を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）のうち、どちらか1体を\\n\u3000召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法中ダメージを与える。');
