insert into unit_enemy_data values (305505, 'フォギー', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実体を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法中ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）のうち、どちらか1体を\\n\u3000召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法大ダメージを与える。');
insert into unit_enemy_data values (305506, 'フォギー', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実体を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法中ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）のうち、どちらか1体を\\n\u3000召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法大ダメージを与える。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (305507, 'フォギー', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実体を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法大ダメージを与える。\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）（青）のうち、\\n\u3000いずれか1体を召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法大ダメージを与える。\\n・【物理】分身体（青）は、敵全体に\\n\u3000物理小ダメージ。\\n\u3000さらに、呪い状態にする。\\n\u3000分身体（青）のＨＰが30％以下になった時、\\n\u3000フォギーのＴＰを300回復させる。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (305508, 'ミストシーカー', 305508, 0, 16, 270, 1000, 2, 3.0, 0, 0, 0, '【魔法】塔の魔力を帯びた霧が実体化した魔物。\\n怨嗟を振りまき、分身とともに冒険者を付け狙う。\\n\\n・敵全体に魔法大ダメージを与える。\\n\u3000敵が呪い状態の場合、ダメージがアップし、呪\\n\u3000詛状態の場合、さらにダメージがアップする。\\n・敵全体に魔法中ダメージを与える。\\n\u3000敵が呪い状態の場合、呪詛状態にする。さらに、\\n\u3000ミストシーカー自身のＨＰが80％未満の場合、\\n\u3000物理攻撃力と魔法攻撃力を短時間大ダウンさせ\\n\u3000る。\\n・分身体を召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・分身体は、敵全体に物理中ダメージを\\n\u3000与え、さらに呪い状態にする。\\n・分身体のＨＰが30％以下になった時、最も魔\\n\u3000法攻撃力が高い味方１キャラのＴＰを1000\\n\u3000回復させる。\\n・ミストシーカー自身のＨＰが80％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。');
insert into unit_enemy_data values (305600, 'ロード・イビリィ', 305600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ルナの魔力欲しさに現れた異界の魔物。\\n魔眼と従えた兵で、ルナの塔の征服を目論む。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000さらに敵全体の魔法防御力を中ダウンさせる。\\n・6回、ランダムで1キャラに魔法小ダメージ\\n\u3000を与える。\\n・後ろから3番目のキャラに魔法中ダメージと、\\n\u3000長時間の拘束を与える。\\n\u3000さらに全体に魔法小ダメージを与える。');
insert into unit_enemy_data values (305700, 'ゴブリングレート', 305700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】豪快に戦斧を振るう熟練のゴブリン戦士。\\n幼き戦士を脇に抱え、魂の技を見せ付ける。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、自身の物理攻撃力を中\\n\u3000アップ、物理防御力を小アップさせ、さらに\\n\u3000目の前の１キャラに物理特大ダメージ。');
insert into unit_enemy_data values (305701, 'ゴブリングレート', 305701, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '豪快に戦斧を振り回す、熟練のゴブリン戦士。\\n幼き戦士を脇に抱え、魂の技を見せ付ける。\\n\\n・ユニオンバーストは、自身の物理攻撃力を中\\n\u3000アップ、物理防御力を小アップさせ、さらに\\n\u3000目の前の１キャラに物理特大ダメージ。');
insert into unit_enemy_data values (305702, 'ゴブリングレート', 305702, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】豪快に戦斧を振るう熟練のゴブリン戦士。\\n幼き戦士を脇に抱え、魂の技を見せ付ける。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、自身の物理攻撃力を中\\n\u3000アップ、物理防御力を小アップさせる。\\n\u3000さらに目の前の１キャラに物理特大ダメージ\\n\u3000を与え、スタンさせる。\\n・目の前の１キャラに物理特大ダメージを与え、\\n\u3000スタンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。');
insert into unit_enemy_data values (305703, '蛮族のリーダー', 305703, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】屈強な体と心で砂漠を\\n生き抜く蛮族の戦士。我が幼子を\\n守るため、戦斧を振るい続ける。\\n\\n・ユニオンバーストは、自身の物理\\n\u3000攻撃力を中アップ、物理防御力を\\n\u3000小アップさせる。\\n\u3000さらに目の前の１キャラに物理特\\n\u3000大ダメージを与える。');
insert into unit_enemy_data values (305707, 'ゴブリングレート', 305707, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ロードの左腕にしてゴブリンの大戦士。\\n巨大な戦斧を豪快に振るい、眼前の敵を打ち砕く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果\\n\u3000で上昇した防御力は、バトル中に受ける防御\\n\u3000力ダウンスキルの影響を受けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て、一度の行動で与えるダメージの値が一定\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ゴブリングレートから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量\\n\u3000を中ダウンさせる。\\n・ユニオンバーストは、前方１キャラに物理特\\n\u3000大ダメージを与え、自身の物理攻撃力と物理\\n\u3000防御力を小アップさせる。\\n・前方１キャラにキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。');
insert into unit_enemy_data values (305800, 'ネプテリオン', 305800, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】海神の使者で、不思議な軟体の魔物。\\n身体のほとんどは魔力を帯びた海水だとか。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ネプテリオンから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、行動速度\\n\u3000を特大ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２番目のキャラに魔法特大ダメージを与\\n\u3000え行動速度特大ダウン、前から３番目のキャラ\\n\u3000に魔法大ダメージを与え行動速度特大ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２番目のキャラを中心にした範囲に、物\\n\u3000理攻撃力と魔法攻撃力を大ダウンさせ、継続魔\\n\u3000法小ダメージを与えるフィールドを展開。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。');
insert into unit_enemy_data values (305801, 'カムツカイ', 305801, 0, 16, 270, 1000, 2, 2.6, 0, 0, 0, '【魔法】ルナの塔で暴れ回る海獣。太古の海神に\\n仕えるが、今や大義なき破壊者となり果てる。\\n\\n・敵全体に魔法ダメージを与える。\\n・一定範囲に、物理攻撃力と魔法防御力を\\n\u3000ダウンさせ、継続魔法ダメージを与える\\n\u3000フィールドを展開する。\\n・前から２番目と３番目のキャラに\\n\u3000魔法大ダメージを与える。');
insert into unit_enemy_data values (305802, 'ネプテリオン', 305802, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】海神に仕える奇体な魔物。\\n水域の平穏を脅かす侵入者を見るや\\n神使いの力を行使し、一掃する。\\n\\n・敵全体に魔法大ダメージ。\\n\\n・前から２番目のキャラに魔法特大\\n\u3000ダメージ、前から３番目のキャラ\\n\u3000に魔法中ダメージ。\\n\\n・一定範囲に、魔法防御力をダウン\\n\u3000させ、継続魔法ダメージを与える\\n\u3000フィールドを展開。');
insert into unit_enemy_data values (305900, 'マダムプリズム', 305900, 0, 16, 270, 1000, 2, 2.2, 0, 0, 0, '【魔法】圧倒的な魅力を放つ麗しき極彩色の艶鳥。\\nその色香に囚われれば、味方を襲う下僕となる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。\\n\u3000さらに、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n\u3000キャラのＨＰが70％未満の場合、誘惑状態を\\n\u3000付与する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・前から２キャラに魔法中ダメージを与え、誘惑\\n\u3000状態を付与する。\\n\u3000さらに、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n\u3000このスキルによる物理攻撃力と魔法攻撃力ダウ\\n\u3000ン効果はダメージを無効化しても付与される。');
insert into unit_enemy_data values (305901, 'マダムプリズム', 305901, 0, 16, 270, 1000, 2, 2.2, 0, 0, 0, '【魔法】圧倒的な魅力を放つ麗しき極彩色の艶鳥。\\nその色香に囚われれば、味方を襲う下僕となる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。\\n\u3000さらに、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n\u3000キャラのＨＰが70％未満の場合、誘惑状態を\\n\u3000付与する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・前から２キャラに魔法中ダメージを与え、誘惑\\n\u3000状態を付与する。\\n\u3000さらに、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n\u3000このスキルによる物理攻撃力と魔法攻撃力ダウ\\n\u3000ン効果はダメージを無効化しても付与される。');
insert into unit_enemy_data values (306000, '邪餅神ガミィ', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u30008秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306001, '邪餅神ガミィ', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。');
insert into unit_enemy_data values (306002, '邪餅神ガミィ', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u30008秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306003, '邪餅神ガミィ', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u30008秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306004, '邪餅神ガミィ', 306004, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【MODE1】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・邪餅神ガミィ自身が攻撃を受けると、\\n\u3000味方全体のＨＰを小回復し、\\n\u3000邪餅神ガミィ自身のＨＰを全回復する。');
insert into unit_enemy_data values (306005, '邪餅神ガミィ', 306005, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・前方1キャラに物理ダメージを与える。\\n・前方範囲内に魔法中ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・6個の邪念を込めてボンノウ（赤）を召喚する。\\n・3個の邪念を込めてボンノウ（紫）を召喚する。\\n・1個の邪念を込めてボンノウ（青）を召喚する。');
insert into unit_enemy_data values (306006, '邪餅神ガミィ', 306006, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【MODE3】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・前方1キャラに物理ダメージを与える。\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u30008秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。');
insert into unit_enemy_data values (306007, '邪餅神ガミィ', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000キャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方３キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を小ダウンさせる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u3000８秒後に大爆発し、範囲内の敵すべてに\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。');
insert into unit_enemy_data values (306008, '邪餅神ガミィ', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000キャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方３キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を小ダウンさせる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u3000８秒後に大爆発し、範囲内の敵すべてに\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306009, '邪餅神ガミィ', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000キャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方３キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を小ダウンさせる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u3000８秒後に大爆発し、範囲内の敵すべてに\\n\u3000物理大ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306010, '邪餅神ガミィ', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000キャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方３キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u3000８秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300060％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306100, 'ジャッカルシーフ', 306100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】闇に紛れ、人里で盗みを\\nはたらく魔物の頭目。\\nくすねたエモノを容赦なく投げつけ\\n開拓の邪魔をするならず者。\\n\\n・前方３キャラに物理中ダメージを\\n\u3000与え、麻痺させる。\\n\\n・敵全体に物理小ダメージを与え、\\n\u3000行動速度を下げる。\\n\u3000さらに、前方小範囲を毒状態\\n\u3000にする。');
insert into unit_enemy_data values (306101, 'ジャッカルシーフ', 306101, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】闇に紛れ、人里で盗みを働く魔物の頭目。\\nくすねたエモノを器用に使って戦う、ならず者。\\n\\n・前方３キャラに物理中ダメージを与え、麻痺さ\\n\u3000せる。\\n・敵全体に物理小ダメージを与え、行動速度をダ\\n\u3000ウンさせる。\\n\u3000さらに、前方小範囲を毒状態にする。\\n\u3000このスキルの毒はダメージを無効化しても付与\\n\u3000される。');
insert into unit_enemy_data values (306102, 'ジャッカルシーフ', 306102, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】闇に紛れ、人里で盗みを働く魔物の頭目。\\nくすねたエモノを器用に使って戦う、ならず者。\\n\\n・前方３キャラに物理中ダメージを与え、麻痺さ\\n\u3000せる。\\n・敵全体に物理小ダメージを与え、行動速度をダ\\n\u3000ウンさせる。\\n\u3000さらに、前方小範囲を毒状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。');
insert into unit_enemy_data values (306200, 'マスター・センリ', 306200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】森奥に座し、周辺一帯を\\n手下と共に支配する老獪な大狸。\\nありもしない幻を見せ、精神を蝕む\\n幻影攻撃を巧みに操る。\\n\\n・敵全体に魔法中ダメージを与え、\\n\u3000ワッパダヌキ２体を召喚する。\\n\\n・敵全体に魔法小ダメージを与え、\\n\u3000無敵状態でない召喚モンスターを\\n\u3000消滅させる。\\n\u3000さらに敵のＨＰが40％以下の\\n\u3000場合、麻痺状態にする。');
insert into unit_enemy_data values (306201, 'マスター・センリ', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】森奥に座し、一帯を支配する老獪な大狸。\\n口寄せした子狸との多彩な連携で敵を惑わせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、ワッパダヌキ２体を召喚する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に魔法小ダメージを与え、ノックバック\\n\u3000し、無敵状態でないワッパダヌキを消滅させる。\\n\u3000さらに敵のＨＰが50％未満の場合、麻痺状態\\n\u3000を付与する。');
insert into unit_enemy_data values (306202, 'マスター・センリ', 306202, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】森奥に座し、一帯を支配する老獪な大狸。\\n口寄せした子狸との多彩な連携で敵を惑わせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、ワッパダヌキ２体を召喚する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に魔法小ダメージを与え、ノックバック\\n\u3000し、無敵状態でないワッパダヌキを消滅させる。\\n\u3000さらに敵のＨＰが50％未満の場合、麻痺状態\\n\u3000を付与する。');
insert into unit_enemy_data values (306203, 'マスター・センリ', 306203, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】森奥に座し、一帯を支配する老獪な大狸。\\n口寄せした子狸との多彩な連携で敵を惑わせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、ワッパダヌキ２体を召喚する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に魔法小ダメージを与え、ノックバック\\n\u3000し、無敵状態でないワッパダヌキを消滅させる。\\n\u3000さらに敵のＨＰが50％未満の場合、麻痺状態\\n\u3000を付与する。');
insert into unit_enemy_data values (306204, 'マスター・センリ', 306204, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】森奥に座し、一帯を支配する老獪な大狸。\\n口寄せした子狸との多彩な連携で敵を惑わせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、ワッパダヌキ２体を召喚する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に魔法小ダメージを与え、ノックバック\\n\u3000し、無敵状態でないワッパダヌキを消滅させる。\\n\u3000さらに敵のＨＰが50％未満の場合、麻痺状態\\n\u3000を付与する。');
insert into unit_enemy_data values (306300, 'マスター・ウキキー', 306300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ルナの魔力を使いウキキーを統べる仙猿。\\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\\n\\n・敵全体に物理大ダメージを与える。\\n\u3000この攻撃は火傷状態の敵に対して、\\n\u3000ダメージが1.8倍になる。\\n・前方中範囲の敵に物理中ダメージを与える。\\n・前方小範囲の敵に魔法中ダメージを与え、\\n\u3000火傷状態にする。');
insert into unit_enemy_data values (306301, 'マスター・ウキキー', 306301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ルナの魔力を使いウキキーを統べる仙猿。\\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000さらに物理攻撃キャラの物理攻撃力を下げる。\\n\u3000この攻撃は火傷状態の敵に対して、\\n\u3000ダメージが1.8倍になる。\\n・前方中範囲の敵に物理中ダメージを与える。\\n・前方小範囲の敵に魔法中ダメージを与え、\\n\u3000火傷状態にする。');
insert into unit_enemy_data values (306400, 'ワイルドクロウ', 306400, 0, 16, 270, 1000, 1, 3.5, 0, 0, 0, '【物理】荒れ山の捕食者として君臨\\nする、凶悪な怪鳥獣。\\n狩りを続けることでつくりあげた\\n膂力と剛爪が、侵入者をつけ狙う。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000ＴＰ上昇をダウンさせる。\\n\u3000発動するたびにダメージがアップ\\n\u3000する。この効果は最大３回まで\\n\u3000累積する。\\n\\n・後ろから２番目の敵を中心にした\\n\u3000小範囲に物理小ダメージを与え、\\n\u3000麻痺状態にする。');
insert into unit_enemy_data values (306500, 'トライバルオーク', 306500, 0, 16, 270, 1000, 1, 0.9, 0, 0, 0, '【物理】辺境の森のオークたちの\\n首魁。独自の民族性の奇怪な\\nリズムを撒き散らす。その怪音は、\\n敵対者を混迷の渦に突き落とす。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000物理防御力と魔法防御力をダウン\\n\u3000さらに自身の物理攻撃力と\\n\u3000魔法攻撃力をアップする。\\n\\n・前方４キャラに魔法小ダメージを\\n\u3000与え、敵のＨＰが70％以下の\\n\u3000場合、混乱状態にする。');
insert into unit_enemy_data values (306501, 'ノイジーオーク', 306501, 0, 16, 270, 1000, 1, 0.9, 0, 0, 0, '【物理】ルナの塔の力に魅せられたオークの首魁。\\n奇怪なリズムの太鼓で、戦場に騒乱を引き起こす。\\n\\n・敵全体に物理大ダメージを与え、物理防御力と\\n\u3000魔法防御力をダウンさせる。さらに、自分の\\n\u3000物理攻撃力と魔法攻撃力をアップさせる。\\n・前方３キャラに魔法小ダメージを与え、\\n\u3000小さく吹き飛ばす。敵のＨＰが70％未満の\\n\u3000場合、混乱状態にする。\\n・敵全体に残りＨＰに応じた魔法大ダメージを\\n\u3000与え、行動速度をダウンさせる。\\n\u3000さらに、敵全体のステータスアップ効果を\\n\u3000解除する。');
insert into unit_enemy_data values (306600, 'ベノムサラマンドラ', 306600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】獲物を求め水辺を猛毒\\nで満たす、サンショウウオの魔物。\\n漏れるほどに溜め込んだ猛毒は、\\n近づくだけで意識を奪う危険物。\\n\\n・敵全体に魔法中ダメージを与え、\\n\u3000毒状態にする。\\n\u3000さらに猛毒状態にする。\\n\\n・前方範囲内の敵に\\n\u3000魔法小ダメージを与え、\\n\u3000猛毒状態にする。');
insert into unit_enemy_data values (306700, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらにキャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。\\n・アグリーラブリー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306701, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらにキャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。');
insert into unit_enemy_data values (306702, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらにキャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。\\n・アグリーラブリー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306703, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらにキャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。\\n・アグリーラブリー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306704, 'アグリーラブリー', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE1】チョコを大噴射し、身を覆い隠す。\\n敵の攻撃を受け続け、憤怒の一撃を炸裂する。\\n\\n・敵全体に物理小ダメージを与え、バトル中の間\\n\u3000火傷状態にする。\\n・チョコドームにこもっている間は、アグリー\\n\u3000ラブリー自身の物理防御力を中アップする。\\n\u3000チョコドーム状態を解除したのち、この状態の\\n\u3000間に受けたダメージ量に応じた\\n\u3000物理ダメージを与える。\\n\u3000さらにアグリーラブリー自身の物理防御力を\\n\u3000大ダウンする。');
insert into unit_enemy_data values (306705, 'アグリーラブリー', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE2】カカオウラは奮起し、\\n 死地に飛び込む。\\n 激化する魔物の攻撃から、\\n 大切な者たちを守るため。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n・カカオウラがキャラの味方として出現する。\\n\u3000カカオウラ出現中は、キャラ全体の物理\\n\u3000攻撃力と魔法攻撃力と行動速度が中アップする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000行動速度を大ダウンさせる。\\n');
insert into unit_enemy_data values (306706, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【MODE3】轟々たる咆哮が、会場を包み込む。\\n愛憎渦巻くバレンタイン事変もいよいよ終局。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000キャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。');
insert into unit_enemy_data values (306708, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方３キャラにキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与え、さらに火傷状態に\\n\u3000する。');
insert into unit_enemy_data values (306709, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方３キャラにキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与え、さらに火傷状態に\\n\u3000する。\\n・アグリーラブリー自身のＨＰが\\n\u300045％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306710, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方３キャラにキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与え、さらに火傷状態に\\n\u3000する。\\n・アグリーラブリー自身のＨＰが\\n\u300045％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306711, 'アグリーラブリー', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE1】チョコを大噴射し、身を覆い隠す。\\n敵の攻撃を受け続け、憤怒の一撃を炸裂する。\\n\\n・敵全体に物理小ダメージを与え、バトル中の間\\n\u3000火傷状態にする。\\n・チョコドームにこもっている間は、アグリー\\n\u3000ラブリー自身の物理防御力を中アップする。\\n\u3000チョコドーム状態を解除したのち、この状態の\\n\u3000間に受けたダメージ量に応じた\\n\u3000物理ダメージを与える。\\n\u3000さらにアグリーラブリー自身の物理防御力を\\n\u3000大ダウンする。');
