insert into unit_enemy_data values (306713, 'アグリーラブリー', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【MODE3】轟々たる咆哮が、会場を包み込む。\\n愛憎渦巻くバレンタイン事変もいよいよ終局。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000キャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。\\n・バトル開始直後に、自身の物理攻撃力と\\n\u3000行動速度をアップさせる。');
insert into unit_enemy_data values (306800, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n・嘆きの女神自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306801, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。');
insert into unit_enemy_data values (306802, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・嘆きの女神自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306803, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・嘆きの女神自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (306804, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】【自警団（カォン）】メンバーをシャドウとして召喚。\\n絆の断絶を目論み、挑みし者の心の弱さを突く。\\n\\n・シャドウを出現させる\\n・嘆きの女神自身は攻撃行動をとらない。');
insert into unit_enemy_data values (306805, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】永久の闇で周囲を満たすべく、\\n\u3000持ちうる呪詛呪言で、冒険者のすべてを\\n\u3000阻み続ける。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方３キャラに魔法小ダメージを与え、\\n\u3000物理防御力を下げ、ＴＰを減少させ\\n\u3000取得率も下げる。\\n\u3000さらに呪い、混乱状態にさせ行動速度を下げる。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・嘆きの女神自身の物理防御力を下げる。\\n\u3000さらに呪い状態になり、ＴＰが減少する。');
insert into unit_enemy_data values (306806, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】狂気に満ちた悲哀は、女王の真の\u3000姿を解き放つ。呪われし願いは、一縷の希望も\u3000赦さない。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。');
insert into unit_enemy_data values (306807, '嘆きの女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n・嘆きの女神自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
