insert into unit_enemy_data values (306812, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】永久の闇で周囲を満たすべく、\\n\u3000持ちうる呪詛呪言で、冒険者のすべてを\\n\u3000阻み続ける。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方３キャラに魔法小ダメージを与え、\\n\u3000物理防御力を下げ、ＴＰを減少させ\\n\u3000ＴＰ上昇をダウンさせる。\\n\u3000さらに呪い、混乱状態にさせ行動速度を上げる。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・嘆きの女神自身の物理防御力を下げる。\\n\u3000さらに呪い状態になり、ＴＰが減少する。');
insert into unit_enemy_data values (306813, '嘆きの女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】狂気に満ちた悲哀は、女王の真の\u3000姿を解き放つ。呪われし願いは、一縷の希望も\u3000赦さない。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・バトル開始直後に、自身の魔法攻撃力と\\n\u3000行動速度をアップさせる。');
insert into unit_enemy_data values (306900, 'トライロッカー', 306900, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】かつて人々に祀られていた三戦士の石像。\\nそれぞれが能力を高め合い、必殺の一撃を放つ。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の\\n影響を受けやすい。\\n・自身の物理攻撃力と魔法攻撃力を\\n\u3000極大アップさせ、敵全体に物理中ダメージと\\n\u3000魔法中ダメージを与える。\\n・前方範囲内の敵に魔法小ダメージ。\\n・敵全体に物理中ダメージ。');
insert into unit_enemy_data values (306901, 'トライロッカー', 306901, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】かつて人々に祀られていた三戦士の石像。\\nそれぞれが能力を高め合い、必殺の一撃を放つ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・トライロッカーから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を小ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、自身の物理攻撃力と魔法\\n\u3000攻撃力を大アップさせ、敵全体に物理中ダメー\\n\u3000ジと魔法中ダメージを与える。\\n・前から１番目の敵を中心とした小範囲に魔法中\\n\u3000ダメージ。\\n・敵全体に物理中ダメージを与え、さらに物理攻\\n\u3000撃力と魔法攻撃力を特大ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。');
insert into unit_enemy_data values (307000, 'コア・ギガース', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (307001, 'コア・ギガース', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。');
insert into unit_enemy_data values (307002, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (307003, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・コア・ギガース自身のＨＰが40％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (307004, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・コア・ギガース自身のＨＰが40％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (307005, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE1】【美食殿】メンバーをシャドウ\\nとして召喚。旅の思い出を盾に、３人の心の\\n弱さを試す。\\n\\n・シャドウを出現させる\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。');
insert into unit_enemy_data values (307006, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE2】強靭な肉体であらゆる攻撃を\\n耐え凌ぐ。その怒りを糧に、巨人は\\n怒涛の大反撃を見舞う。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。');
insert into unit_enemy_data values (307007, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【MODE3】弩級の巨人は、全身全霊の力を\\n解放する。強大無比な破壊力を前に\\n小手先の攻撃は通じない。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。');
