insert into unit_enemy_data values (307009, 'コア・ギガース', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。');
insert into unit_enemy_data values (307010, 'コア・ギガース', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、行動速度をダウンさせる。\\n\u3000さらに、前方２キャラを麻痺させ、自身の\\n\u3000物理攻撃力をアップ。\\n・コア・ギガース自身のＨＰが35％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (307011, 'コア・ギガース', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、行動速度をダウンさせる。\\n\u3000さらに、前方２キャラを麻痺させ、自身の\\n\u3000物理攻撃力をアップ。\\n・コア・ギガース自身のＨＰが35％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (307012, 'コア・ギガース', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、行動速度をダウンさせる。\\n\u3000さらに、前方２キャラを麻痺させ、自身の\\n\u3000物理攻撃力をアップ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・コア・ギガース自身のＨＰが35％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (307013, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE1】【美食殿】メンバーをシャドウ\\nとして召喚。旅の思い出を盾に、３人の心の\\n弱さを試す。\\n\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。');
insert into unit_enemy_data values (307014, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE2】強靭な肉体であらゆる攻撃を\\n耐え凌ぐ。その怒りを糧に、巨人は\\n怒涛の大反撃を見舞う。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理中ダメージ。\\n・前方３キャラに物理大ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。');
insert into unit_enemy_data values (307015, 'コア・ギガース', 307002, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【MODE3】弩級の巨人は、全身全霊の力を\\n解放する。強大無比な破壊力を前に\\n小手先の攻撃は通じない。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理中ダメージ。\\n・前方３キャラに物理大ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。\\n・敵全体に物理大ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・バトル開始直後に、自身の物理攻撃力と\\n\u3000行動速度をアップさせる。');
insert into unit_enemy_data values (307100, 'ロボリマ（MODE1）', 307100, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '堅牢で多彩な技を持つ謎の巨大兵器の第１形態。\\nリンゴ型補給機で未知のエネルギーを充填し、\\n広範囲を焦土と化す連続攻撃に注意せよ！\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方１キャラに物理小ダメージ。\\n・一定範囲に、物理攻撃力と回避をダウンさせ\\n\u3000物理ダメージを与えるフィールドを展開。\\n\u3000同時に前方範囲内のキャラの\\n\u3000ステータスアップ効果を解除。\\n・前方範囲内に物理中ダメージを与え、\\n\u3000自身のＴＰ上昇をアップ。');
insert into unit_enemy_data values (307101, 'ロボリマ（MODE2）', 307101, 0, 16, 270, 3000, 1, 1.2, 0, 0, 0, '全てを攻めへと切替えた謎の巨大兵器の第２形態。\\nコアリマクターの放つ熱線が、全土を焼き尽くす。\\n無防備な巨大兵器に大ダメージを叩き込め！\\n\\n・ユニオンバーストは、前方小範囲に物理\\n\u3000特大ダメージ、中範囲に物理大ダメージ、\\n\u3000広範囲に物理中ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・前方１キャラに物理小ダメージ。\\n・ランダムな１キャラに物理小ダメージ。\\n・一定範囲に、物理攻撃力と魔法攻撃力を\\n\u3000大ダウンさせ、魔法ダメージを与える\\n\u3000フィールドを展開。\\n\u3000同時に、魔法攻撃力の高い２キャラを\\n\u3000沈黙させる。');
insert into unit_enemy_data values (307102, 'ロボリマ（MODE3）', 307102, 0, 16, 270, 3000, 1, 5.5, 0, 0, 0, '損耗を自己修復する謎の巨大兵器の第３形態。\\n隙だらけな本体への攻撃を、防衛ドローンが阻む。\\n範囲攻撃でドローンを蹴散らし、好機を狙え！\\n\\n・敵全体を大きく吹き飛ばし、\\n\u3000ミニロボリマを３体召喚する。\\n・ミニロボリマが、前方１キャラに\\n\u3000物理小ダメージ。\\n・ミニロボリマが、ランダムな１キャラに\\n\u3000魔法中ダメージ。\\n・敵全体に残りＨＰに応じた割合物理\\n\u3000特大ダメージ。');
insert into unit_enemy_data values (307200, 'バジリスク', 307200, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】ルナの魔力を求め飛来した大怪鳥。\\n雛鳥を従え、石化の呪剣を振り下ろす。\\n\\n・石化状態でないキャラ全員に魔法大ダメージ\\n\u3000を与え、短時間石化する。\\n\u3000石化状態のキャラ全員に最大ＨＰの80％の\\n\u3000ダメージを与える。\\n・前から３キャラに魔法小ダメージを与える。\\n\u3000さらにこのスキルでダメージが発生した\\n\u3000毒状態のキャラを長時間石化する。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000さらに毒状態にする。\\n\u3000自身のＨＰが50％以下の場合、さらに敵全体\\n\u3000をノックバックし、コッコーを召喚する。\\n・コッコーは、前方範囲内で物理攻撃力が\\n\u3000一番高い１キャラに物理小ダメージを与え、\\n\u3000さらに毒状態にする。\\n\u3000また自身のＨＰが最大ＨＰの35％以下にな\\n\u3000ると、物理攻撃力が最も高い味方のＴＰを\\n\u3000中アップし、自身は戦闘不能になる。');
insert into unit_enemy_data values (307201, 'バジリスク', 307201, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】石化の呪剣を携えた怪鳥。尾蛇の毒牙で\\n獲物を蝕み、呪剣の石化で冒険者の歩みを止める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、行動不能状態でないキャ\\n\u3000ラ全員に魔法中ダメージを与え、石化状態にす\\n\u3000る。\\n\u3000行動不能状態のキャラ全員に最大ＨＰの80％\\n\u3000の魔法ダメージを与える。\\n\u3000さらに、敵全体のステータスアップ効果を解除。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から３キャラに魔法大ダメージを与える。\\n\u3000さらにこのスキルでダメージが発生した毒状態\\n\u3000のキャラを石化状態にする。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。\\n・敵全体に魔法中ダメージを与え、さらに毒状態\\n\u3000にする。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。\\n\u3000このスキルにより付与された毒のダメージでは、\\n\u3000ＴＰが回復しない。\\n・前方１キャラに物理中ダメージを与える。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。');
insert into unit_enemy_data values (307300, 'アクダイカン', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。');
insert into unit_enemy_data values (307301, 'アクダイカン', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。');
insert into unit_enemy_data values (307302, 'アクダイカン', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。');
insert into unit_enemy_data values (307303, 'アクダイカン', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を0にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが0になると\\n\u3000大爆発し、範囲内の敵すべてに物理中\\n\u3000ダメージを与える。\\n・アクダイカン自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (307304, 'アクダイカン', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】【ヴァイスフリューゲル\\nランドソル支部】メンバーをシャドウ\\nとして召喚。３人の固い絆をあざ笑う\\n欲望の影が強襲する。\\n\\n・シャドウを出現させる\\n・目の前の敵１キャラへの物理攻撃\\n');
insert into unit_enemy_data values (307305, 'アクダイカン', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】物欲で周囲を従えるべく、\\nあらゆる虚構で欲望の渦へ引きずり込む。\\n\\n・目の前の敵１キャラへの物理攻撃\\n・敵全体に物理小ダメージを与え、\\n\u3000誘惑状態にする。\\n');
insert into unit_enemy_data values (307306, 'アクダイカン', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】虚栄に満ちた欲心は、すべて\\nを支配せんと真の力を解放する。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を0にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが0になると\\n\u3000大爆発し、範囲内の敵すべてに物理中\\n\u3000ダメージを与える。\\n');
insert into unit_enemy_data values (307307, 'アクダイカン', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。');
