insert into unit_enemy_data values (307309, 'アクダイカン', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を０にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが０になると\\n\u3000大爆発し、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・アクダイカン自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (307310, 'アクダイカン', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を０にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが０になると\\n\u3000大爆発し、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・アクダイカン自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。');
