insert into unit_enemy_data values (307810, '雨神様', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】古より島の天候を見守ってきた守り神。\\n友の心を求め憂うあまり、禍禍しき姿に変貌する。\\nすべての大地を哀哭の雨で飲み込む。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、前方範囲内の敵すべてにキャラの\\n\u3000最大ＨＰに応じた追加の魔法割合ダメージを\\n\u3000与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。\\n・雨神様自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。');
insert into unit_enemy_data values (307811, '雨神様', 307801, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】悲嘆に暮れるアメきちは\\nみんなの想いを拒絶し、心焦がれるほどに\\n求めたハレきちの声すら今のアメきちには\\n届かない。\\n\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージ量に関係なく、攻撃を\\n\u3000命中させるたびに徐々に耐久性を失っていき、\\n\u3000200回攻撃を命中させるとバリアは破壊\\n\u3000される。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、前方範囲内の敵すべてにキャラの\\n\u3000最大ＨＰに応じた追加の魔法割合ダメージを\\n\u3000与える。\\n・前方範囲内の敵すべてに\\n\u3000魔法中ダメージを与える。\\n');
insert into unit_enemy_data values (307812, '雨神様', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】哀哭の雨が、哀しみとともに\\n降り注ぐ。その漆黒の雫は、悲哀の渇きで\\n人々の心身を蝕む。\\n\\n・バトル開始時に呪いのクリスタルを呼び出す。\\n\u3000呪いのクリスタルがバトル中に存在している間、\\n\u3000敵全体に継続魔法ダメージを与える。さらに、\\n\u3000何らかの効果でＨＰを回復しようとした場合、\\n\u3000その回復を無効にし、本来の回復量の10%の\\n\u3000ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、前方範囲内の敵すべてにキャラの\\n\u3000最大ＨＰに応じた追加の魔法割合ダメージを\\n\u3000与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。');
insert into unit_enemy_data values (307813, '雨神様', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】ハレきちへの贖罪を乞う\\n慟哭の奔流が、対峙する者の心を引き裂く。\\n愛、友情、全ての感情が塵芥へと帰す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、前方範囲内の敵すべてにキャラの\\n\u3000最大ＨＰに応じた追加の魔法割合ダメージを\\n\u3000与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。\\n・雨神様自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。');
insert into unit_enemy_data values (307900, 'ガルグ', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から３番目、４番目、５番目のキャラに\\n\u3000物理中ダメージを与えさらにスタンさせる。');
insert into unit_enemy_data values (307901, 'ガルグ', 307900, 0, 16, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から３番目、４番目、５番目のキャラに\\n\u3000物理中ダメージを与えさらにスタンさせる。');
insert into unit_enemy_data values (307902, 'ガルグ', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から３番目、４番目、５番目のキャラに\\n\u3000物理中ダメージを与えさらにスタンさせる。\\n・前方２キャラに物理中ダメージを与える。\\n・ガルグ自身のＨＰが50%を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (307903, 'ガルグ', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から３番目、４番目、５番目のキャラに\\n\u3000物理中ダメージを与えさらにスタンさせる。\\n・前方２キャラに物理中ダメージを与える。\\n・ガルグ自身のＨＰが50%を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (308000, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大\\n\u3000ダメージ。さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。\\n・マジムンのＨＰが40%を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。');
insert into unit_enemy_data values (308001, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大\\n\u3000ダメージ。さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。');
insert into unit_enemy_data values (308002, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大\\n\u3000ダメージ。さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。\\n・マジムンのＨＰが40%を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。');
insert into unit_enemy_data values (308003, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】黄昏より出でし巨悪の化身は、\\n本能のまま幾百の魂を貪り喰う。\\n\\n・バトル開始と同時に、自身の魔法攻撃力を\\n\u3000特大アップさせ、さらに敵パーティの物理\\n\u3000クリティカルと魔法クリティカルを特大ダウン\\n\u3000させるフィールドを展開する。\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大ダメージ。\\n\u3000さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】の\\n\u3000数が多い程強化される。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が5減少する。');
insert into unit_enemy_data values (308004, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】宵闇より現れし怨霊の叢りは、\\n人々の魂を千々に引き裂く。\\n\\n・分身体を1体倒すたびに、残りマジムン数が\\n\u30001減少する。その後、分身体が再度召喚される。\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。');
insert into unit_enemy_data values (308005, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】暁闇の中で跋扈する魑魅は、\\n遂には三千世界の魂を食らわんと牙を剥く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大\\n\u3000ダメージ。さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。\\n・残り時間が40秒を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。');
insert into unit_enemy_data values (308006, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。\\n・マジムンのＨＰが30%を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。');
insert into unit_enemy_data values (308007, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。');
insert into unit_enemy_data values (308008, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。\\n・マジムンのＨＰが30％を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。');
insert into unit_enemy_data values (308009, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】黄昏より出でし巨悪の化身は、\\n本能のまま幾百の魂を貪り喰う。\\n\\n・バトル開始後に、自身の魔法攻撃力を\\n\u3000特大アップさせ、さらに敵全体の物理\\n\u3000クリティカルと魔法クリティカルを特大ダウン\\n\u3000させるフィールドを展開する。\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】の\\n\u3000数が多い程強化される。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が５減少する。');
insert into unit_enemy_data values (308010, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】宵闇より現れし怨霊の叢りは、\\n人々の魂を千々に引き裂く。\\n\\n・分身体を１体倒すたびに、残りマジムン数が\\n\u3000１減少する。その後、分身体が再度召喚される。\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。');
insert into unit_enemy_data values (308011, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】暁闇の中で跋扈する魑魅は、\\n遂には三千世界の魂を喰らわんと牙を剥く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。\\n・残り時間が30秒を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。');
insert into unit_enemy_data values (308012, 'マジムン', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。');
insert into unit_enemy_data values (308100, 'テンタパス', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・後方範囲内に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。\\n・一定時間経過すると敵単体に\\n\u3000物理超特大ダメージを与える。\\n・テンタパス自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (308101, 'テンタパス', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・後方範囲内に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。');
insert into unit_enemy_data values (308102, 'テンタパス', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・後方範囲内に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。\\n・テンタパス自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (308103, 'テンタパス', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・後方範囲内に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。\\n・一定時間経過すると敵単体に\\n\u3000物理超特大ダメージを与える。\\n・テンタパス自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (308200, 'オオドクマンドラゴラ', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (308201, 'オオドクマンドラゴラ', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】異常発達したアオイのマンドラゴラ。\\n強靭な根と種子の弾丸で眼前の敵を圧倒する。\\n\\n・前方２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージ。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。');
insert into unit_enemy_data values (308202, 'オオドクマンドラゴラ', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】異常発達したアオイのマンドラゴラ。\\n強靭な根と種子の弾丸で眼前の敵を圧倒する。\\n\\n・前方２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージ。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。');
insert into unit_enemy_data values (308203, 'オオドクマンドラゴラ', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】異常発達したアオイのマンドラゴラ。\\n強靭な根と種子の弾丸で眼前の敵を圧倒する。\\n\\n・前方２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージ。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。\\n・マンドラゴラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。');
insert into unit_enemy_data values (308204, 'オオドクマンドラゴラ', 308204, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】猛毒の胞子が降り注ぎ、大地は\\n荒野と化す。\\n数多の骸を苗床に、猛毒の大輪が鮮やかに\\n咲き誇る。\\n\\n下記の行動を順番に繰り返す。\\n・地面に埋まっている間、ダメージを受け付け\\n\u3000ない状態になる。\\n・敵全体を強力な毒状態にする。\\n・自身にかかっているステータスダウン効果を\\n\u3000解除したあと、自身の物理防御力と魔法防御\\n\u3000力を極大ダウン。');
insert into unit_enemy_data values (308205, 'オオドクマンドラゴラ', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE1】触手から滴り落ちる猛毒の雫。\\nその一滴は泉を枯らし、森を腐らせ、命を侵す。\\n\\n・前方２キャラに物理ダメージを与え、さらに\\n\u3000毒状態にする。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n\u3000毒状態のキャラには、ダメージが大アップ。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。');
insert into unit_enemy_data values (308206, 'オオドクマンドラゴラ', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE3】絶命の咆哮、巨腕の蹂躙。\\n花のように散る命。自らの断末魔を子守歌に、\\n亡骸は永遠の眠りにつく。\\n\\n・前方２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージ。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。\\n・残り時間が40秒を切ると、さらに攻撃が\\n\u3000激しく狂暴になる。');
insert into unit_enemy_data values (308207, 'ラフレシアマンドラゴラ', 308207, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】塔の魔力で開花した劇毒を放つ死の大花。\\nその毒は、全ての感覚を狂わせ生ある全てを蝕む。\\n\\n・前方２キャラに物理ダメージを与える。\\n\u3000自身のＨＰが80％を切っている場合、さらに\\n\u3000毒状態にする。\\n・ユニオンバーストは敵全体に物理大ダメージを\\n\u3000与え、毒状態のキャラに割合ダメージを与える。\\n\u3000その後、敵全体の物理攻撃力を大ダウンさせ、\\n\u3000自身の物理攻撃力を大アップさせる。\\n・敵全体に物理中ダメージを与え、物理防御をダ\\n\u3000ウンさせる。\\n・自分の物理攻撃力とＴＰをアップする。\\n・残りＨＰが80％を切ると、さらに攻撃が激し\\n\u3000く狂暴になる。\\n・地面に埋まっている間、ダメージを受け付けな\\n\u3000い状態になり、敵全体に物理中ダメージを与え、\\n\u3000敵全体を長時間、毒状態にする。さらに、毒状\\n\u3000態のキャラを猛毒状態にする。\\n\u3000その後、地面から出てきた際に、物理防御力と\\n\u3000魔法防御力を極大ダウン。');
insert into unit_enemy_data values (308300, '島クジラ', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (308301, '島クジラ', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。');
insert into unit_enemy_data values (308302, '島クジラ', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (308303, '島クジラ', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (308400, 'ファントムバロン', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】我が子への妄執に囚われた亡親の霊。\\n娘と偽りの日々を享受すべく、\\n立ち塞がる者を容赦なく屠る。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。');
insert into unit_enemy_data values (308401, 'ファントムバロン', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】我が子への妄執に囚われた亡親の霊。\\n娘と偽りの日々を享受すべく、\\n立ち塞がる者を容赦なく屠る。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。');
insert into unit_enemy_data values (308402, 'ファントムバロン', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】我が子への妄執に囚われた亡親の霊。\\n娘と偽りの日々を享受すべく、\\n立ち塞がる者を容赦なく屠る。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n・ファントムバロンのＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。');
insert into unit_enemy_data values (308403, 'ファントムバロン', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】我が子への妄執に囚われた亡親の霊。\\n娘と偽りの日々を享受すべく、\\n立ち塞がる者を容赦なく屠る。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n・ファントムバロンのＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。');
insert into unit_enemy_data values (308404, 'ファントムバロン', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ１】【リトルリリカル】の\\nシャドウを召喚。\\n無垢な少女達が手招く先は、亡者が蠢く常夜の国。\\n\\n・前方１キャラに魔法ダメージを与える。');
insert into unit_enemy_data values (308405, 'ファントムバロン', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ２】冥府の門が開かれ、\\n生者の魂は奈落に墜ちる。既に還る術もなく、\\n思い出を標に闇を漂う。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n・前方３キャラに魔法中ダメージを与えて\\n\u3000ＴＰを中ダウンさせ、ファントムバロン\\n\u3000のＴＰを中回復させる。\\n\u3000さらに、物理攻撃をするキャラのうち、\\n\u3000前から３キャラのステータスアップ効果を\\n\u3000解除し、魔法攻撃をするキャラのうち、\\n\u3000前から３キャラに追加の魔法大ダメージを\\n\u3000与える。');
insert into unit_enemy_data values (308406, 'ファントムバロン', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ３】最愛との別離が刻々と近づく。\\n悲しき宿命に抗うべく、\\n怨霊は寂滅の慟哭をあげる。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n・バトル開始直後に、自身の魔法攻撃力と\\n\u3000行動速度をアップさせる。');
insert into unit_enemy_data values (308408, 'マッドファントム', 308408, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】塔の魔力に群がる怨魂が姿を成した亡霊。\\n邪悪な手が生者を呼び込み、冥府へ引き摺り込む。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラに魔法中ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。');
insert into unit_enemy_data values (308500, '水瑚麟', 308500, 0, 16, 270, 1000, 1, 2.8, 0, 0, 0, '【物理】ルナの魔力に魅入られ荒れ狂う水の神獣。\\n自らの役目を忘れ、万物を飲み込む狂獣と化す。\\n\\n・敵全体に魔法大ダメージを与え、畏怖を与える。\\n\u3000畏怖状態のキャラは、一定時間攻撃および\\n\u3000ＨＰ回復のユニオンバーストの効果が半減する。\\n・前方範囲内に魔法中ダメージを与え、\\n\u3000ヒットした数に応じて自身の物理防御力を\\n\u3000小アップ。さらに、魔法ダメージを与える\\n\u3000フィールドを展開する。\\n・前方１キャラに魔法大ダメージを与え、\\n\u3000自身のＨＰを消費し、敵全体に追加の\\n\u3000魔法中ダメージを与える。\\n\u3000さらに、自身の物理攻撃力と魔法攻撃力を\\n\u3000小アップ。');
insert into unit_enemy_data values (308600, 'ドラゴンもどき', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (308601, 'ドラゴンもどき', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ドラゴン？の如き翼で空を舞い\\nドラゴン？の如き灼熱のブレスで敵を焦がす。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間、\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが5000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。');
insert into unit_enemy_data values (308602, 'ドラゴンもどき', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ドラゴン？の如き翼で空を舞い\\nドラゴン？の如き灼熱のブレスで敵を焦がす。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間、\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが20000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。');
insert into unit_enemy_data values (308603, 'ドラゴンもどき', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】ドラゴン？の如き翼で空を舞い\\nドラゴン？の如き灼熱のブレスで敵を焦がす。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間、\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが160000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。\\n・ドラゴンもどきのＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (308604, 'ドラゴンもどき', 308600, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ１】蒼天から降る咆哮が空を裂き、\\n陽光に輝く自慢の翼で巨大な偽竜が降臨する。\\n\\n・ドラゴンもどきの残りＨＰが80％を切ると\\n\u3000次のＭＯＤＥに移行する。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが150000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。\\n・４体のモンスターを呼び寄せ、さらに敵全体\\n\u3000を小さくノックバック。');
insert into unit_enemy_data values (308605, 'ドラゴンもどき', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ２】偽竜の呼びかけに森の魔物たちが\\n集結する。彼を守るべく死力を尽くす。\\n\\n・ゴーレム、トレント、ポイズンポッド\\n\u3000を倒すと、次のＭＯＤＥに移行する。\\n\\n・ドラゴンもどきは、目の前の敵１キャラへの\\n\u3000物理攻撃を行う。');
insert into unit_enemy_data values (308606, 'ドラゴンもどき', 308606, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ３】竜への憧れが石竜子を覚醒\\nさせる。空を統べる覇者の息吹は島を絶やす\\n劫火となる。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間、\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが250000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (309000, 'ランドスロース', 309000, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】夢うつつの狭間で惰眠を貪るナマケモノ。\\n眠りを妨げると怒り狂い、超能力で暴れまわる。\\n\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与え、さらに物理攻撃力と魔法攻撃力\\n\u3000を大ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体に魔法小ダメージを与える。');
insert into unit_enemy_data values (309001, 'ランドスロース', 309001, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】夢うつつの狭間で惰眠を貪るナマケモノ。\\n眠りを妨げると怒り狂い、超能力で暴れまわる。\\n\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与え、さらに物理攻撃力と魔法攻撃力\\n\u3000を大ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体に魔法小ダメージを与え、スタンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。');
insert into unit_enemy_data values (309100, 'ドロゲーター', 309100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】大河に棲む大ワニの魔物。\\nマヌケな顔で、不思議な槍で大地を\\n融解させ冒険者の動きを封じる。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000物理防御力と行動速度をダウン\\n\u3000させる。\\n\\n・前から３番目の敵を中心にした\\n\u3000小範囲に物理小ダメージを与え、\\n\u3000束縛状態にする。');
insert into unit_enemy_data values (309200, 'スカイワルキューレ', 309200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】戦空を駆け舞う、天上の戦乙女。\\n目にも留まらぬ連射で、敵の進行を射止める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、前方範囲内の最大４キャ\\n\u3000ラに物理大ダメージを与え、ＴＰを特大ダウン、\\n\u3000行動速度を大ダウンさせる。\\n・前から３キャラに物理中ダメージを与え、自身\\n\u3000の行動速度を大アップ。');
insert into unit_enemy_data values (309201, 'スカイワルキューレ', 309201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】戦空を駆け舞う、天上の戦乙女。\\n目にも留まらぬ連射で、敵の進行を射止める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、前方範囲内の最大４キャ\\n\u3000ラに物理大ダメージを与え、ＴＰを特大ダウン、\\n\u3000行動速度を大ダウンさせる。\\n・前から４キャラに物理中ダメージを与え、物理\\n\u3000攻撃力と魔法攻撃力を大ダウンさせる。\\n\u3000さらに自身の行動速度を大アップ。');
insert into unit_enemy_data values (309300, 'トナカイ・ヴェンデッタ', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (309301, 'トナカイ・ヴェンデッタ', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】主人へ反逆を決めた、エリートトナカイ。\\n欲深いサンタたちへ、従者の心の鉄槌を下す。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが40％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。');
insert into unit_enemy_data values (309302, 'トナカイ・ヴェンデッタ', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】主人へ反逆を決めた、エリートトナカイ。\\n欲深いサンタたちへ、従者の心の鉄槌を下す。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが40％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。');
insert into unit_enemy_data values (309303, 'トナカイ・ヴェンデッタ', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】主人へ反逆を決めた、エリートトナカイ。\\n欲深いサンタたちへ、従者の心の鉄槌を下す。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが40％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。\\n・トナカイ・ヴェンデッタ自身のＨＰが50％を\\n\u3000切ると、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (309304, 'トナカイ・ヴェンデッタ', 309300, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【ＭＯＤＥ１】クリスティーナ、ノゾミ、\\nイリヤのシャドウを召喚。３人の歪んだ欲望と\\n御節介が、かたちとなり聖夜を渾沌に変えていく。\\n\\n・一番前のキャラに物理ダメージを与える。');
insert into unit_enemy_data values (309305, 'トナカイ・ヴェンデッタ', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ２】聖夜の街に絶望が雪のように\\n降り積る。染まる欲望の袋より、積念の憎悪が\\n溢れだす。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが40％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一定時間、前方にフィールドを発生させる。\\n\u3000このフィールド上にいるキャラに対して、\\n\u3000物理攻撃力と物理クリティカルと\\n\u3000ＴＰ上昇を大きく下げる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。');
insert into unit_enemy_data values (309306, 'トナカイ・ヴェンデッタ', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ３】手負いの巨獣が、反撃の狼煙を\\n上げる。憎悪と憤怒に身を落とし、残虐の限りを\\n尽くす。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが35％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (309400, 'サーヴァント・ブレド（物理）', 309400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】覇瞳皇帝が生み出した動く力の貯蔵庫。\\n膂力の権能を司り、極大の剣戟で全てを斬破する。\\n\\n・スタンと吹き飛ばし効果が有効。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\\n・目の前の敵を中心に、範囲内の敵すべてに\\n\u3000キャラの最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\\n・サーヴァント・ブレド（物理）自身の\\n\u3000ＨＰが40％を切ると、さらに攻撃が\\n\u3000激しく凶暴になる。');
insert into unit_enemy_data values (309500, 'サーヴァント・マギ（魔法）', 309500, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】覇瞳皇帝が生み出した動く力の貯蔵庫。\\n魔道の権能を司り、無尽の魔力で全てを滅却する。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、物理攻撃力と魔法攻撃力を小ダウン。\\n\\n・ランダムな１キャラに魔法ダメージを与え、\\n\u3000さらに呪い、麻痺状態にしてＴＰを大ダウン。\\n\\n・サーヴァント・マギ（魔法）自身の\\n\u3000ＨＰが40％を切ると、さらに攻撃が\\n\u3000激しく凶暴になる。');
insert into unit_enemy_data values (309600, 'サーヴァント・ロクス（複部位）', 309600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】覇瞳皇帝が生み出した動く力の貯蔵庫。\\n双肩の権能を司り、広闊たる領域で全てを屠る。\\n\\n・ユニオンバーストは、目の前の敵を中心に、\\n\u3000範囲内の敵すべてにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、さらに\\n\u3000目の前の敵に物理小ダメージを与える。\\n\\n・目の前の敵を中心にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。\\n\\n・サーヴァント・ロクス（複部位）自身の\\n\u3000ＨＰが40％を切ると、さらに防御力が\\n\u3000上がり頑強になる。');
insert into unit_enemy_data values (309700, 'サーヴァント・ウォル（防衛）', 309700, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】覇瞳皇帝が生み出した動く力の貯蔵庫。\\n守護の権能を司り、不侵の壁で全てを拒絶する。\\n\\n・ユニオンバーストは、自身の物理防御力、\\n\u3000魔法防御力を大アップ。\\n\\n・目の前の敵を中心に、範囲内の敵すべてに\\n\u3000魔法ダメージ。さらに、自身の物理防御力、\\n\u3000魔法防御力を小アップ。\\n\\n・サーヴァント・ウォル（防衛）自身の\\n\u3000ＨＰが40％を切ると、さらに防御力が\\n\u3000上がり頑強になる。');
insert into unit_enemy_data values (309800, '覇瞳皇帝', 309800, 0, 16, 270, 1000, 1, 3.6, 309800, 309800, 0, '王都終末決戦_ベースユニット');
insert into unit_enemy_data values (309801, '覇瞳皇帝', 309801, 0, 16, 270, 1000, 1, 2.4, 309800, 309800, 0, '【MODE１】全てを、拒絶する悲しき王女。\\n自らを神とし、禍禍しき力にその身をのまれる。\\nそして狂乱の刃をアストルムの全てに向ける。\\n欺瞞の王女を守護する壁を、数多の刃で打ち破れ。\\n\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージ量に関係なく、攻撃を\\n\u3000命中させるたびに徐々に耐久性を失っていき、\\n\u3000280回攻撃を命中させるとバリアは破壊\\n\u3000される。\\n\\n・ユニオンバーストは、敵全体に残りＨＰに\\n\u3000応じた割合特大ダメージを与える。\\n\\n・敵全体に、物理小ダメージと魔法\\n\u3000小ダメージを与える。');
insert into unit_enemy_data values (309802, '覇瞳皇帝', 309800, 0, 16, 270, 1000, 1, 1.8, 309800, 309800, 0, '【MODE２】小さき者の反抗に僅かな焦燥を見せる。\\n希望を抱き、対向する全てに自らの理を科す。\\n悲憤の剣を突き立て、その魂を塵芥へと挫く。\\n仮初の神の放つ黒刃に、正しき魔法を以て\\n対抗せよ。\\n\\n・ユニオンバーストは、敵全体に残りＨＰに\\n\u3000応じた割合特大ダメージを与える。\\n\\n・目の前の敵１キャラに物理特大ダメージを与え、\\n\u3000さらにその周囲の敵すべてに魔法中ダメージを\\n\u3000与え、気絶させる。気絶したキャラは、\\n\u3000次に攻撃を受けるまで行動不能になる。\\n\\n・敵全体に、物理小ダメージと魔法\\n\u3000小ダメージを与える。');
insert into unit_enemy_data values (309803, '覇瞳皇帝', 309800, 0, 16, 270, 1000, 1, 1.6, 309800, 309800, 0, '【MODE３】世界を創りし神の、最期の叫声。\\n怨嗟が放つ拒絶の言の葉は呪詛となり、\\n躰を、精神を、魂を削りすべてを闇に帰す。\\n遂に決着の時。皆、剣を取りその手で明日を\\n切り拓け。\\n\\n・ユニオンバーストは、敵全体に残りＨＰに\\n\u3000応じた割合特大ダメージを与える。\\n\\n・目の前の敵１キャラに物理特大ダメージを与え、\\n\u3000さらにその周囲の敵すべてに魔法中ダメージを\\n\u3000与え、気絶させる。気絶したキャラは、\\n\u3000次に攻撃を受けるまで行動不能になる。\\n\\n・敵全体に、物理小ダメージと魔法\\n\u3000小ダメージを与える。\\n\\n・最も後ろの敵１キャラを中心に、物理防御力と\\n\u3000魔法防御力を中ダウンさせるフィールドを\\n\u3000展開し、さらに魔法小ダメージを与え、\\n\u3000呪詛を付与する。呪詛による継続ダメージは、\\n\u3000毎秒ごとに増加する。\\n\\n・バトル開始直後に、自分の行動速度を\\n\u3000大アップさせ、さらに魔法防御力を\\n\u3000小アップさせる。');
insert into unit_enemy_data values (309804, '覇瞳皇帝', 309804, 0, 16, 270, 1000, 1, 1.8, 309800, 309800, 0, 'マップ表示用');
insert into unit_enemy_data values (309900, 'ゴブリンメイスター', 309900, 0, 17, 270, 1100, 2, 1.8, 0, 0, 0, '【魔法】塔の魔力を我が物に画策する小鬼学者。\\n禁術で土塊の人形を操り、全ての自由を強奪する。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000すべての召喚体、分身を即死させる。\\n・前方広範囲に残りＨＰに応じた割合物理\\n\u3000中ダメージを与え、大きく吹き飛ばす。\\n\u3000さらに、泥人形を１体召喚する。\\n\u3000泥人形は最前衛または前から２番目のキャラに\\n\u3000物理ダメージを与え、行動速度を下げる。\\n・前から２番目のキャラを中心とした小範囲に\\n\u3000物理中ダメージと猛毒、スタンを与える。');
insert into unit_enemy_data values (309907, 'ゴブリンメイスター', 309907, 0, 16, 270, 2000, 2, 1.8, 0, 0, 0, '【魔法】ロードの右腕にしてゴブリンの大魔導士。\\n禁忌の魔術を撃ち放ち、抗う全ての敵を滅却する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果\\n\u3000で上昇した防御力は、バトル中に受ける防御\\n\u3000力ダウンスキルの影響を受けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て、一度の行動で与えるダメージの値が一定\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ゴブリンメイスターから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・ダメージを受けるたびに【小鬼の紋章】を\\n\u3000１追加する。【小鬼の紋章】が10の時、\\n\u3000【小鬼の紋章】を10消費し、魔法の壷を爆破\\n\u3000しゴブリングレートとゴブリンメイスターに\\n\u3000魔法特大ダメージを与え、物理防御力と魔法\\n\u3000防御力を特大ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法大\\n\u3000ダメージを与え、全ての召喚体を破壊する。\\n・前方１キャラにキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。\\n・残りＨＰが2400万を下回ると魔法攻撃力と\\n\u3000行動速度が特大アップし、攻撃行動を変更する。\\n・前から２番目のキャラを中心とした範囲内の\\n\u3000敵に魔法中ダメージを与えて、麻痺状態と\\n\u3000猛毒状態にする。');
insert into unit_enemy_data values (310000, '山神様', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】駆走る神と伝承される山の土着神。\\n太古より好敵手を求め大地を雄々しく競奔する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理\\n\u3000特大ダメージを与え、大きく吹き飛ばして\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い１キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰを大きくダウンさせる。\\n・自身のＴＰと行動速度をアップさせる。\\n・山神様自身のＨＰが55％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる代わりに\\n\u3000自身の物理防御力がダウンする。');
insert into unit_enemy_data values (310001, '山神様', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】駆走る神と伝承される山の土着神。\\n太古より好敵手を求め大地を雄々しく競奔する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、ノックバックさせて\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・自身のＴＰと行動速度をアップさせる。');
insert into unit_enemy_data values (310002, '山神様', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】駆走る神と伝承される山の土着神。\\n太古より好敵手を求め大地を雄々しく競奔する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、ノックバックさせて\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い１キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰをダウンさせる。\\n・自身のＴＰと行動速度をアップさせる。\\n・山神様自身のＨＰが55％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる代わりに\\n\u3000自身の物理防御力がダウンする。');
insert into unit_enemy_data values (310003, '山神様', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】駆走る神と伝承される山の土着神。\\n太古より好敵手を求め大地を雄々しく競奔する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、ノックバックさせて\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い１キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰをダウンさせる。\\n・自身のＴＰと行動速度をアップさせる。\\n・山神様自身のＨＰが55％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる代わりに\\n\u3000自身の物理防御力がダウンする。');
insert into unit_enemy_data values (310004, '山神様', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】冒険者の力を試す、内なる影を\\n召喚。寒風吹き荒ぶ天下の険、自身の脆さが\\n試される。\\n\\n・一番前のキャラに物理ダメージを与える。');
insert into unit_enemy_data values (310005, '山神様', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】益荒男の疾駆に大地が揺れる。\\nその様を祝賀するが如く、目出鯛は巌山を舞う。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、大きく吹き飛ばして\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い２キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰを大きくダウンさせる。\\n・後方に物理防御力ダウンフィールドを展開し、\\n\u3000さらに敵全体に物理中ダメージを与える。\\n\u3000目出鯛が背中を離れている間は、山神様の\\n\u3000魔法防御力が特大ダウン。');
insert into unit_enemy_data values (310006, '山神様', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】神と競いし強者への、終の試煉。\\n互いの全てを以て、想い人へ駆け抜ける。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、大きく吹き飛ばして\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い１キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰを大きくダウンさせる。\\n・自身のＴＰと行動速度をアップさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる代わりに、自身の物理防御力が\\n\u3000ダウンする。');
insert into unit_enemy_data values (310100, 'ラースドラゴン', 310100, 0, 14, 270, 1000, 1, 2.6, 0, 0, 0, '【物理】忘却の秘境に、住まう若き巨竜。\\n禁忌に踏み入る冒険者を灼熱の業火で焼き払う。\\n\\n・ユニオンバーストは敵全体に物理割合ダメージ\\n\u3000を与え、さらにＴＰをダウンさせる。\\n・バトル開始時に、自身のＴＰを特大ダウン。\\n・前方1キャラを中心に一定範囲内のキャラに\\n\u3000魔法ダメージを与え、さらに物理防御力を\\n\u3000ダウンさせる。\\n・敵全体に物理ダメージを与え、さらに火傷\\n\u3000状態にする。\\n・敵全体に物理ダメージを与え、ノックバック\\n\u3000させる、さらに、ステータスアップ効果を\\n\u3000打ち消す。\\n\\n・全ターゲットがブレイクされると、自身のＴＰ\\n\u3000を特大ダウン。\\n・ラースドラゴン自身の残りＨＰが10％を切る\\n\u3000とさらに攻撃が激しく強暴になり、ブレイク\\n\u3000されなくなる。\\n・バトルがタイムアップすると、敵全体を戦闘\\n\u3000不能にする。\\n');
insert into unit_enemy_data values (310200, 'シャークヘッドレイ', 310200, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】海蝕洞の支配者として\\n君臨する、サメエイの魔物。凶猛な\\n欲望を全て捕食に注ぐ海の大悪党。\\n\\n・敵全体に物理特大ダメージを与え\\n\u3000物理防御力と魔法攻撃力を\\n\u3000ダウンさせる。\\n\\n・前方範囲内の敵すべてに\\n\u3000魔法小ダメージを与え、ＴＰと\\n\u3000ＴＰ上昇率をダウンさせる。');
insert into unit_enemy_data values (310201, 'シャークグリード', 310201, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】塔の魔力を吸収した、暴食の巨大鮫鱏。\\n音波で感覚を狂わせ、鈍った獲物を喰らい尽くす。\\n\\n・敵全体に物理特大ダメージを与え、物理防御力\\n\u3000と魔法攻撃力をダウンさせる。\\n・最もＴＰの高い敵１キャラに魔法中ダメージを\\n\u3000与え、麻痺させる。\\n\u3000さらに挑発状態にする。\\n・挑発を無視して、最もＨＰの高い敵１キャラに\\n\u3000毎秒増加する継続ダメージを与える。');
insert into unit_enemy_data values (310300, 'アンチビースト', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (310301, 'アンチビースト', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】愛の力を求め顕現した、負の魔法生物。\\n皆の心の中の愛の力を歪め世界に災いをもたらす。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。');
insert into unit_enemy_data values (310302, 'アンチビースト', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】愛の力を求め顕現した、負の魔法生物。\\n皆の心の中の愛の力を歪め世界に災いをもたらす。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。');
insert into unit_enemy_data values (310303, 'アンチビースト', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】愛の力を求め顕現した、負の魔法生物。\\n皆の心の中の愛の力を歪め世界に災いをもたらす。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。\\n・アンチビースト自身のＨＰが50％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (310304, 'アンチビースト', 310304, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【ＭＯＤＥ１】闇の力によって染め上げられた\\n愛と欲望が形となった負の魔法生物。世界を\\n無慈悲にただ歪めはじめる。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。');
insert into unit_enemy_data values (310305, 'アンチビースト', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ２】魔法少女のシャドウを召喚。\\n歪んだ負の絶望影が、魔法少女たちの愛と\\n希望の力を試す。\\n\\n・シャドウの戦いを静かに見守る。');
insert into unit_enemy_data values (310306, 'アンチビースト', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ３】憤怒する負の魔法生物はとうとう\\n真の力を解放する。魔法少女の心を打ち砕かん\\nと、歪んだ愛の力ですべてを捻じ伏せる。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (310400, 'カメレオプス', 310400, 0, 11, 270, 1000, 1, 2.4, 0, 0, 0, '【物理】湿林に潜み獲物を付け狙う\\nカメレオンの魔物。臆病で狡猾な気\\n性だが、怒るとツノを向け猛突進。\\n\\n・ユニオンバーストは、敵全体に物\\n\u3000理大ダメージを与え、物理防御力\\n\u3000を大ダウンさせる。\\n\\n・ランダムな１キャラに\\n\u3000物理中ダメージを与える。\\n\\n・カメレオプスが一定時間背景に擬\\n\u3000態し、回避を極大アップ、行動速\\n\u3000度を特大アップ、物理防御力が大\\n\u3000ダウンする。\\n\\n・前方３キャラに物理中ダメージを\\n\u3000与える。');
insert into unit_enemy_data values (310401, 'カメレオプス', 310401, 0, 11, 270, 1000, 1, 2.4, 0, 0, 0, '【物理】湿林に潜み獲物を付け狙う\\nカメレオンの魔物。臆病で狡猾な気\\n性だが、怒るとツノを向け猛突進。\\n\\n・ユニオンバーストは、敵全体に物\\n\u3000理大ダメージを与え、物理防御力\\n\u3000を大ダウンさせる。\\n\\n・ランダムな１キャラに\\n\u3000物理中ダメージを与える。\\n\\n・カメレオプスが一定時間背景に擬\\n\u3000態し、回避を極大アップ、行動速\\n\u3000度を特大アップ、物理防御力が大\\n\u3000ダウンする。\\n\\n・前方３キャラに物理中ダメージを\\n\u3000与える。');
insert into unit_enemy_data values (310500, 'ラウドラパーン', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (310501, 'ラウドラパーン', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ポップな体色をした大ウサギの魔物。\\n見た目とは裏腹に迷惑極まりないその歌声は、\\n大地を震わせ冒険者の心をも折る。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。その後、目を\\n\u3000回している間、自身の物理・魔法防御力が\\n\u3000大幅にダウンする。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000物理中ダメージを与え、さらに行動速度を\\n\u3000ダウンさせる。');
insert into unit_enemy_data values (310502, 'ラウドラパーン', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ポップな体色をした大ウサギの魔物。\\n見た目とは裏腹に迷惑極まりないその歌声は、\\n大地を震わせ冒険者の心をも折る。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。その後、目を\\n\u3000回している間、自身の物理・魔法防御力が\\n\u3000大幅にダウンする。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000物理中ダメージを与え、さらに行動速度を\\n\u3000ダウンさせる。\\n・前から３キャラに物理小ダメージを与え、\\n\u3000さらに物理防御力を大ダウンさせる。');
insert into unit_enemy_data values (310503, 'ラウドラパーン', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ポップな体色をした大ウサギの魔物。\\n見た目とは裏腹に迷惑極まりないその歌声は、\\n大地を震わせ冒険者の心をも折る。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。その後、目を\\n\u3000回している間、自身の物理・魔法防御力が\\n\u3000大幅にダウンする。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000物理中ダメージを与え、さらに行動速度を\\n\u3000ダウンさせる。\\n・前から３キャラに物理小ダメージを与え、\\n\u3000さらに物理防御力を大ダウンさせる。\\n・ラウドラパーン自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (310504, 'ラウドラパーン', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】ニュージェネレーションズの\\nシャドウを召喚。森で出会った大ウサギ。\\n３人は夢をあきらめない心を貫き通せるか、\\n大ウサギは各個の弱さを見せつける。\\n\\n・一番前のキャラに物理ダメージを与える。');
insert into unit_enemy_data values (310505, 'ラウドラパーン', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】森の人気者の歌声に魔物たちが\\n大挙する。血沸き肉躍る野生の宴会が今、\\n開幕する。\\n\\n・ブルーゴーレム、スリーピィオウル、\\n\u3000ツキツキを倒すと次のＭＯＤＥに移行する。\\n\\n・ラウドラパーンは、一番前のキャラに\\n\u3000物理ダメージを与える。');
insert into unit_enemy_data values (310506, 'ラウドラパーン', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】宴も終焉、大兎が最後の力を振り\\n絞る。咆哮にも似た壊震の歌声が、３人の夢道を\\n阻む。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。その後、目を\\n\u3000回している間、自身の物理・魔法防御力が\\n\u3000大幅にダウンする。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000物理中ダメージを与え、さらに行動速度を\\n\u3000ダウンさせる。\\n・前から３キャラに物理小ダメージを与え、\\n\u3000さらに物理防御力を大ダウンさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (310600, '葛藤のうえきちゃん', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '');
insert into unit_enemy_data values (310601, '葛藤のうえきちゃん', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】魔物かはたまた精霊なのか、謎多き巨躯\\nのいきもの。如何ともし難いその表情のまま謎の\\n花粉を噴霧し、市中を混乱へと誘い落とす。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。');
insert into unit_enemy_data values (310602, '葛藤のうえきちゃん', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】魔物かはたまた精霊なのか、謎多き巨躯\\nのいきもの。如何ともし難いその表情のまま謎の\\n花粉を噴霧し、市中を混乱へと誘い落とす。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・きゅうこんちゃんを召喚。\\n\u3000きゅうこんちゃんは攻撃の対象にならず、一定\\n\u3000時間が経つと自爆して前方範囲内のキャラに魔\\n\u3000法ダメージを与える。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。');
insert into unit_enemy_data values (310603, '葛藤のうえきちゃん', 310603, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】魔物かはたまた精霊なのか、謎多き巨躯\\nのいきもの。如何ともし難いその表情のまま謎の\\n花粉を噴霧し、市中を混乱へと誘い落とす。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・きゅうこんちゃんを召喚。\\n\u3000きゅうこんちゃんは攻撃の対象にならず、一定\\n\u3000時間が経つと自爆して前方範囲内のキャラに魔\\n\u3000法ダメージを与える。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・うえきちゃん自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (310604, '葛藤のうえきちゃん', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '');
insert into unit_enemy_data values (310605, '葛藤のうえきちゃん', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【MODE１】終に極大化した謎のいきもの。\\nまたしても如何ともし難い表情で、大滝の涙が\\n大地を濡らしその涙は意思なく皆を蝕んでゆく。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・敵全体のＴＰを上昇させたのち、継続魔法ダメ\\n\u3000ージを与えるフィールドを展開する。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。');
insert into unit_enemy_data values (310606, '葛藤のうえきちゃん', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【MODE２】冒険者の抵抗に怯んだか、両葉と\\nその巨躯を晒しつつ佇む。だが、その表情は相も\\n変わらず、如何ともし難い表情のまま。\\n\\n・全てのターゲットがブレイク無効。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・きゅうこんちゃんを召喚。\\n\u3000きゅうこんちゃんは攻撃の対象にならず、一定\\n\u3000時間が経つと自爆して前方範囲内のキャラに魔\\n\u3000法ダメージを与える。\\n');
insert into unit_enemy_data values (310607, '葛藤のうえきちゃん', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【MODE３】その変わらぬ表情は、終にも\\n変わらず冒険者は、そのいきものの狂気と畏怖に\\n慄く。果たしていきものの謎は解かれるのか…。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・きゅうこんちゃんを召喚。\\n\u3000きゅうこんちゃんは攻撃の対象にならず、一定\\n\u3000時間が経つと自爆して前方範囲内のキャラに魔\\n\u3000法ダメージを与える。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。');
insert into unit_enemy_data values (310700, 'なかよしＸ', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '');
insert into unit_enemy_data values (310701, 'なかよしＸ', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】規格外のアイデアと歪んだ情熱から爆誕\\nした鋼鉄の巨人。礎となった者の特性を、異常な\\n解釈で再構築し敵の言語中枢と精神を破壊する。\\n\\n・自身が毒、猛毒、呪い、呪詛、火傷の効果を\\n\u3000受けると、自身の物理防御力と魔法防御力と\\n\u3000行動速度が大ダウンする。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・自身の物理攻撃力をアップさせたあと、\\n\u3000敵全体に物理ダメージを与える。\\n・前方３キャラに最大ＨＰに応じた魔法割合\\n\u3000ダメージを与え、行動速度をダウンさせる。');
insert into unit_enemy_data values (310702, 'なかよしＸ', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】規格外のアイデアと歪んだ情熱から爆誕\\nした鋼鉄の巨人。礎となった者の特性を、異常な\\n解釈で再構築し敵の言語中枢と精神を破壊する。\\n\\n・自身が毒、猛毒、呪い、呪詛、火傷の効果を\\n\u3000受けると、自身の物理防御力と魔法防御力と\\n\u3000行動速度が大ダウンする。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・自身の物理攻撃力をアップさせたあと、\\n\u3000敵全体に物理ダメージを与える。\\n・前方３キャラに最大ＨＰに応じた魔法割合\\n\u3000ダメージを与え、行動速度をダウンさせる。');
insert into unit_enemy_data values (310703, 'なかよしＸ', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】規格外のアイデアと歪んだ情熱から爆誕\\nした鋼鉄の巨人。礎となった者の特性を、異常な\\n解釈で再構築し敵の言語中枢と精神を破壊する。\\n\\n・自身が毒、猛毒、呪い、呪詛、火傷の効果を\\n\u3000受けると、自身の物理防御力と魔法防御力と\\n\u3000行動速度が大ダウンする。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・自身の物理攻撃力をアップさせたあと、\\n\u3000敵全体に物理ダメージを与える。\\n・前方３キャラに最大ＨＰに応じた魔法割合\\n\u3000ダメージを与え、行動速度をダウンさせる。\\n・なかよしＸ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (310704, 'なかよしＸ', 310700, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【ＭＯＤＥ１】【メルクリウス財団】の\\nシャドウを召喚。自分たちの過ちを\\n嘲笑うかのように、影の姿で皆を翻弄する。\\n\\n・自身が毒、猛毒、呪い、火傷の効果を受けると、\\n\u3000自身の物理防御力と魔法防御力と行動速度\\n\u3000が大ダウンする。\\n・目の前の敵１キャラに物理ダメージを与える。');
insert into unit_enemy_data values (310705, 'なかよしＸ', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【ＭＯＤＥ２】鋼鉄の球体が、完璧なちぇる語で\\n囁きかける。「ちぇる～ん」。心を掴み離さない\\n洗脳の言の葉は、確実に世界をちぇるへと誘う。\\n\\n・ランダムな１キャラに魔法中ダメージを与え、\\n\u3000沈黙と誘惑状態にする。');
insert into unit_enemy_data values (310706, 'なかよしＸ', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【ＭＯＤＥ３】鋼鉄の絡繰が再び大地に立つ。\\n諸刃の剣・ファイナルモードを解放し、\\nなかよし部の３人を追い詰める。\\n\\n・自身が毒、猛毒、呪い、火傷の効果を受けると、\\n\u3000自身の物理防御力と魔法防御力と行動速度\\n\u3000が大ダウンする。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・自身の物理攻撃力をアップさせたあと、\\n\u3000敵全体に物理ダメージを与える。\\n・前方３キャラに最大ＨＰに応じた魔法割合\\n\u3000ダメージを与え、行動速度をダウンさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (310800, '忍びの頭領ハンゾウ', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】悪徳監査官に雇われた忍びの頭領。\\n義を失った忍びは、その身を金に落とす。だが\\nしかし、円熟の業は健在で皆の行く手を阻む。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して毒を吐き、敵全体を毒状態に\\n\u3000する。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与える。');
insert into unit_enemy_data values (310801, '忍びの頭領ハンゾウ', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】悪徳監査官に雇われた忍びの頭領。\\n義を失った忍びは、その身を金に落とす。だが\\nしかし、円熟の業は健在で皆の行く手を阻む。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して毒を吐き、敵全体を毒状態に\\n\u3000する。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与える。');
insert into unit_enemy_data values (310802, '忍びの頭領ハンゾウ', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】悪徳監査官に雇われた忍びの頭領。\\n義を失った忍びは、その身を金に落とす。だが\\nしかし、円熟の業は健在で皆の行く手を阻む。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して毒を吐き、敵全体を毒状態に\\n\u3000する。自身のＨＰが30%以下の場合、敵全体\\n\u3000を猛毒状態にする。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与える。自身のＨＰ\\n\u3000が30%以下の場合、さらに敵全体をスタンさ\\n\u3000せる。\\n・忍びの頭領ハンゾウ自身のＨＰが30％を切る\\n\u3000と、スキルの効果が変化する。');
insert into unit_enemy_data values (310803, '忍びの頭領ハンゾウ', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】悪徳監査官に雇われた忍びの頭領。\\n義を失った忍びは、その身を金に落とす。だが\\nしかし、円熟の業は健在で皆の行く手を阻む。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して毒を吐き、敵全体を毒状態に\\n\u3000する。自身のＨＰが30%以下の場合、敵全体\\n\u3000を猛毒状態にする。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与える。自身のＨＰ\\n\u3000が30%以下の場合、さらに敵全体をスタンさ\\n\u3000せる。\\n・忍びの頭領ハンゾウ自身のＨＰが30％を切る\\n\u3000と、スキルの効果が変化する。');
insert into unit_enemy_data values (310804, '忍びの頭領ハンゾウ', 310801, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【ＭＯＤＥ１】【牧場（エリザベスパーク）】の\\nシャドウを召喚。幻術で造りだした四農士の幻影\\nが皆の帰る場所を再び窮地に陥れる。\\n\\n・目の前の敵１キャラに物理ダメージを与える。');
insert into unit_enemy_data values (310805, '忍びの頭領ハンゾウ', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【ＭＯＤＥ２】秘伝の口寄せで忍蛙に化け、\\nガマの猛毒をあたり一帯に噴霧する。その猛毒は\\nひと吸いで全身を蝕み、徐々に躰を爛れ落とす。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して猛毒を吐き、敵全体を猛毒状\\n\u3000態にする。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与え、さらに敵全体\\n\u3000をスタンさせる。');
insert into unit_enemy_data values (310806, '忍びの頭領ハンゾウ', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【ＭＯＤＥ３】最期は、忍びとしての尊厳を取り\\n戻し、己が真の力を発揮する。紫電一閃の早業に\\n叫声を上げる間もなく屍と化す。\\n\\n・バトル開始直後に、自身のスキル威力をアップ\\n\u3000させる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して猛毒を吐き、敵全体を猛毒状\\n\u3000態にする。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与え、さらに敵全体\\n\u3000をスタンさせる。');
insert into unit_enemy_data values (310900, 'ランドソル各地に襲来した謎の円盤', 310900, 0, 16, 270, 3000, 1, 0.1, 0, 0, 0, '【物理】平和な収穫祭を急襲する、謎の飛行物体。\\nランドソル各地に突如現れ、破壊と略奪を行う。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方１キャラに物理小ダメージ。\\n・残りＨＰの高い１キャラに物理小ダメージ。\\n・ランダムな１キャラに物理小ダメージ。');
insert into unit_enemy_data values (311000, 'トレントキャッスル', 311000, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】塔の魔力で変異し要塞と化した巨大魔樹。\\n大地の力を砲弾に変え、堅牢なその身を以って\\n破壊の限りを尽くす。\\n\\n・敵全体に物理大ダメージを与える。\\n・範囲内の敵すべてに継続魔法ダメージを与え\\n\u3000物理防御力を下げるフィールドを展開する。\\n・後ろから２番目のキャラを中心とした小範囲内\\n\u3000に物理中ダメージを与え、ＴＰを下げる。\\n\u3000その後、味方全体のＴＰを回復する。');
insert into unit_enemy_data values (311100, '黒の王ジャバウォック', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】世界を歪ませ狭界より顕現した黒の王。\\n暗黒の瘴気を纏い不思議の国を蹂躙せんとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰをダウンさせる。');
insert into unit_enemy_data values (311101, '黒の王ジャバウォック', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】世界を歪ませ狭界より顕現した黒の王。\\n暗黒の瘴気を纏い不思議の国を蹂躙せんとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰを中ダウンさせる。');
insert into unit_enemy_data values (311102, '黒の王ジャバウォック', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】世界を歪ませ狭界より顕現した黒の王。\\n暗黒の瘴気を纏い不思議の国を蹂躙せんとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰを中ダウンさせる。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000魔法防御力を大ダウンさせる。\\n\u3000さらにキャラのＨＰが50％未満の場合、行動\\n\u3000速度をダウンさせる。');
insert into unit_enemy_data values (311103, '黒の王ジャバウォック', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】世界を歪ませ狭界より顕現した黒の王。\\n暗黒の瘴気を纏い不思議の国を蹂躙せんとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰを中ダウンさせる。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000魔法防御力を大ダウンさせる。\\n\u3000さらにキャラのＨＰが50％未満の場合、行動\\n\u3000速度をダウンさせる。\\n・黒の王ジャバウォック自身のＨＰが35％を切\\n\u3000ると、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (311104, '黒の王ジャバウォック', 311101, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【ＭＯＤＥ１】瘴黒の幕を身に纏い、黒の王が再\\n臨する。闇と混沌を集約した障壁は、救世主の光\\nの一射をも耐えるという。\\n\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージを与えるたびに徐々に耐久性\\n\u3000を失っていき、2400000ダメージを与え\\n\u3000るとバリアは破壊される。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000魔法防御力を大ダウンさせる。');
insert into unit_enemy_data values (311105, '黒の王ジャバウォック', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【ＭＯＤＥ２】リノ、アユミ、ヒヨリのシャドウ\\nを召喚。心の闇が具現化し、自己の弱さを露見さ\\nせる。希望の心を取り戻せるか？今、問われる。\\n\\n・目の前の敵１キャラに物理ダメージを与える。');
insert into unit_enemy_data values (311106, '黒の王ジャバウォック', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【ＭＯＤＥ３】黒の王が終の力を解放し、世界は\\n常闇へと堕ちていく。本の殆どの頁は黒に染まり\\n救世主の物語は終焉を迎えようとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰをダウンさせる。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000魔法防御力を大ダウンさせる。\\n\u3000さらにキャラのＨＰが50％未満の場合、行動\\n\u3000速度を大ダウンさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。');
insert into unit_enemy_data values (311200, 'フラワーシュバリエ', 311200, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】大輪の花に擬態する魔物。\\nその美しさに惹かれた、不用意な\\n獲物の前に絶望の光が花開く。\\n\\n・前方３キャラに物理大ダメージを\\n\u3000与え、さらに敵全体に物理大\\n\u3000ダメージを与える。\\n\\n・前方２キャラに物理小ダメージを\\n\u3000与え、さらに自分の物理攻撃力を\\n\u3000中アップさせる。\\n\\n・前から１番目のキャラに物理中\\n\u3000ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。\\n\\n・前から２番目のキャラに物理中\\n\u3000ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。');
insert into unit_enemy_data values (311201, 'フラワーシュバリエ', 311200, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】大輪の花に擬態する魔物。\\nその美しさに惹かれた、不用意な\\n獲物の前に絶望の光が花開く。\\n\\n・前方３キャラに物理大ダメージを\\n\u3000与え、さらに敵全体に物理大\\n\u3000ダメージを与える。\\n\\n・前方２キャラに物理小ダメージを\\n\u3000与え、さらに自分の物理攻撃力を\\n\u3000中アップさせる。\\n\\n・前から１番目のキャラに物理中\\n\u3000ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。\\n\\n・前から２番目のキャラに物理中\\n\u3000ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。');
insert into unit_enemy_data values (311300, '覚醒・浮気星', 311300, 0, 16, 270, 3000, 2, 2.8, 0, 0, 0, '');
insert into unit_enemy_data values (311301, '覚醒・浮気星', 311300, 0, 16, 270, 3000, 2, 2.8, 0, 0, 0, '【魔法】ぽっかり空いた心のスキマに取り憑く\\n星の精霊。過剰な自意識とピュアな下心で相手\\nを惑わせる。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、浮気星の残りＨＰが50％未満の場合、\\n\u3000さらに与えるダメージがアップする。\\n\u3000スキル発動後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・一番後ろの敵を中心として、一定範囲に\\n\u3000魔法小ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力を小アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。\\n・前方範囲内の敵をノックバックさせ、\\n\u3000魔法小ダメージを与える。\\n\u3000さらに誘惑状態にして物理攻撃力と魔法攻撃力\\n\u3000を小アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。');
insert into unit_enemy_data values (311302, '覚醒・浮気星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【魔法】ぽっかり空いた心のスキマに取り憑く\\n星の精霊。過剰な自意識とピュアな下心で相手\\nを惑わせる。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、浮気星の残りＨＰが50％未満の場合、\\n\u3000さらに与えるダメージがアップする。\\n\u3000スキル発動後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・一番後ろの敵を中心として、一定範囲に\\n\u3000魔法小ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力を小アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。\\n・前方範囲内の敵をノックバックさせ、\\n\u3000魔法小ダメージを与える。\\n\u3000さらに誘惑状態にして物理攻撃力を小アップ、\\n\u3000魔法攻撃力を中アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。');
insert into unit_enemy_data values (311303, '覚醒・浮気星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【魔法】ぽっかり空いた心のスキマに取り憑く\\n星の精霊。過剰な自意識とピュアな下心で相手\\nを惑わせる。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、浮気星の残りＨＰが50％未満の場合、\\n\u3000さらに与えるダメージがアップする。\\n\u3000スキル発動後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。\\n・一番後ろの敵を中心として、一定範囲に\\n\u3000魔法中ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力を大アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。\\n・前方範囲内の敵をノックバックさせ、\\n\u3000魔法中ダメージを与える。\\n\u3000さらに誘惑状態にして物理攻撃力と魔法攻撃力\\n\u3000を大アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。');
insert into unit_enemy_data values (311304, '覚醒・浮気星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【ＭＯＤＥ１】自身のハーレムドリームを築き\\n上げるため手当たり次第、乙女たちを強制的に\\n惑わす。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000ダメージを与えた後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。\\n・挑発を無視して、最も後ろの敵１キャラに魔法\\n\u3000ダメージを与え、さらに引き寄せる。\\n・一番前の敵を中心として、一定範囲に\\n\u3000魔法ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力をアップさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルの攻撃対象の数だけ、浮気星に\\n\u3000一定時間【ふた心】を追加する。');
insert into unit_enemy_data values (311305, '覚醒・浮気星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【ＭＯＤＥ２】綺羅星すらも霞ませると、己の\\n輝きに自信をのぞかせ、その盲信と乙女への思い\\nが銀河を巻き込み、全てを幻惑させる。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、浮気星の残りＨＰが60％未満の場合、\\n\u3000さらに与えるダメージがアップする。\\n\u3000ダメージを与えた後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・一番前の敵を中心として、一定範囲に\\n\u3000魔法ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力をアップさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルの攻撃対象の数だけ、浮気星に\\n\u3000一定時間【ふた心】を追加する。');
insert into unit_enemy_data values (311306, '覚醒・浮気星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【ＭＯＤＥ３】夢見たハーレムが潰え、全てを\\n無に還そうと真の力を解放する。銀河の星々を\\n天の川に沈めるべく、全ての下心をブチ撒ける。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、バトル開始直後に、さらに与えるダメー\\n\u3000ジがアップする。\\n\u3000ダメージを与えた後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。\\n・一番後ろの敵を中心として、一定範囲に\\n\u3000魔法ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力をアップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。\\n・前方範囲内の敵をノックバックさせ、\\n\u3000魔法ダメージを与える。\\n\u3000さらに誘惑状態にして物理攻撃力と魔法攻撃力\\n\u3000をアップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。');
insert into unit_enemy_data values (311400, '渚の暴君・鮫吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '');
insert into unit_enemy_data values (311401, '渚の暴君・鮫吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】ビーチ一帯の近海をシメる海洋族の暴君。\\n売られた喧嘩には、ただの一度も背を向けず、\\nシマを荒らすヤツは絶対に許さない。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力をダウンさせ、物理攻撃力をアップさ\\n\u3000せる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力をダウンさせる。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000鮫吉が毒、猛毒、呪い、火傷の効果を受けてい\\n\u3000ると、自身の物理防御力と魔法防御力がアップ\\n\u3000する時間が短くなる。');
insert into unit_enemy_data values (311402, '渚の暴君・鮫吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】ビーチ一帯の近海をシメる海洋族の暴君。\\n売られた喧嘩には、ただの一度も背を向けず、\\nシマを荒らすヤツは絶対に許さない。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力をダウンさせ、物理攻撃力をアップさ\\n\u3000せる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力をダウンさせる。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000鮫吉が毒、猛毒、呪い、火傷の効果を受けてい\\n\u3000ると、自身の物理防御力と魔法防御力がアップ\\n\u3000する時間が短くなる。\\n・鮫吉自身のＨＰが20％を切ると、敵全体に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与え、一定時間、ユニオンバーストのみ使用で\\n\u3000きない状態にし、魔法攻撃力をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (311403, '渚の暴君・鮫吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】ビーチ一帯の近海をシメる海洋族の暴君。\\n売られた喧嘩には、ただの一度も背を向けず、\\nシマを荒らすヤツは絶対に許さない。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力を大ダウンさせ、物理攻撃力をアップ\\n\u3000させる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力をダウンさせる。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000鮫吉が毒、猛毒、呪い、火傷の効果を受けてい\\n\u3000ると、自身の物理防御力と魔法防御力がアップ\\n\u3000する時間が短くなる。\\n・鮫吉自身のＨＰが20％を切ると、敵全体に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与え、一定時間、ユニオンバーストのみ使用で\\n\u3000きない状態にし、魔法攻撃力をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (311404, '渚の暴君・鮫吉', 311404, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【ＭＯＤＥ１】シマを荒らす不届きモノには、幾\\n千もの抗争を潜り抜けた鋼の肉体から繰り出す、\\n全身全霊のガチンコタックルをブチかます。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力をダウンさせ、物理攻撃力をアップさ\\n\u3000せる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。\\n・前方３キャラに物理大ダメージを与える。さら\\n\u3000に、自身にも物理ダメージを与え、物理防御力\\n\u3000と魔法防御力を一定時間極大ダウンさせる。');
insert into unit_enemy_data values (311405, '渚の暴君・鮫吉', 311405, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【ＭＯＤＥ２】圧倒的なカリスマ性と絶望的な暴\\n力につき従う、舎弟たちが集結する。海洋族の精\\n鋭によるカチコミが、いま幕を開ける。\\n\\n・鮫吉は目の前の敵１キャラへの物理攻撃を行う。\\n・前方３キャラに物理大ダメージを与える。さら\\n\u3000に、自身にも物理ダメージを与え、物理防御力\\n\u3000と魔法防御力を一定時間極大ダウンさせる。');
insert into unit_enemy_data values (311406, '渚の暴君・鮫吉', 311404, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【ＭＯＤＥ３】獰猛な雄叫びとともに、暴君は追\\n撃を繰り出す。刃向かう者を完膚なきまでに殴り\\n潰すまで、降り注ぐ轟拳の嵐は決してやまない。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力を大ダウンさせ、物理攻撃力をアップ\\n\u3000させる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力をダウンさせる。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000鮫吉が毒、猛毒、呪い、火傷の効果を受けてい\\n\u3000ると、自身の物理防御力と魔法防御力がアップ\\n\u3000する時間が短くなる。\\n・鮫吉自身のＨＰが10％を切ると、敵全体に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与え、一定時間、ユニオンバーストのみ使用で\\n\u3000きない状態にし、魔法攻撃力をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (311500, '暴走のイノセントボウ', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '');
insert into unit_enemy_data values (311501, '暴走のイノセントボウ', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】過大な無垢なる願いにより暴走した聖弓。\\nその矢に貫かれると、非力なエンジェルと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、エンジェ\\n\u3000ル状態のキャラに呪いを付与する。\\n\u3000この効果により付与された呪いのダメージでは、\\n\u3000ＴＰが回復しない。\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。');
insert into unit_enemy_data values (311502, '暴走のイノセントボウ', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】過大な無垢なる願いにより暴走した聖弓。\\nその矢に貫かれると、非力なエンジェルと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、エンジェ\\n\u3000ル状態のキャラに呪いを付与する。\\n\u3000この効果により付与された呪いのダメージでは、\\n\u3000ＴＰが回復しない。\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。\\n・ＨＰが高い２キャラに魔法中ダメージを与え、\\n\u3000行動速度をダウンさせる。\\n・イノセントボウ自身のＨＰが50％を切ると、\\n\u3000魔法攻撃力がアップし、さらに攻撃が激しく凶\\n\u3000暴になる。');
insert into unit_enemy_data values (311503, '暴走のイノセントボウ', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】過大な無垢なる願いにより暴走した聖弓。\\nその矢に貫かれると、非力なエンジェルと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、エンジェ\\n\u3000ル状態のキャラに呪いを付与する。\\n\u3000この効果により付与された呪いのダメージでは、\\n\u3000ＴＰが回復しない。\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。\\n・ＨＰが高い２キャラに魔法中ダメージを与え、\\n\u3000行動速度をダウンさせる。\\n・イノセントボウ自身のＨＰが50％を切ると、\\n\u3000魔法攻撃力とＴＰがアップし、さらに攻撃が激\\n\u3000しく凶暴になる。');
insert into unit_enemy_data values (311504, '暴走のイノセントボウ', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【ＭＯＤＥ１】歪みし願いは結晶となり、人々を\\n狂わせる。その結晶はすべての進攻を封殺する。\\n\\n・バトル開始時に歪願のクリスタルを呼び出す。\\n・歪願のクリスタルがバトル中に存在している間、\\n\u3000イノセントボウの物理防御力と魔法防御力を大\\n\u3000幅にアップさせる。\\n・歪願のクリスタルが破壊されると、イノセント\\n\u3000ボウの物理防御力と魔法防御力を大幅にダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n・ＨＰが高い２キャラに魔法中ダメージを与え、\\n\u3000行動速度をダウンさせ、さらに魔法防御力を\\n\u3000ダウンさせる。');
insert into unit_enemy_data values (311505, '暴走のイノセントボウ', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【ＭＯＤＥ２】ヨリとアカリのシャドウを召喚。\\n自分たちの負の姿に、双子の真の絆が試される。\\n\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。');
insert into unit_enemy_data values (311506, '暴走のイノセントボウ', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【ＭＯＤＥ３】叶わぬ願いに囚われ、聖弓の権能\\nは極致に至る。解放された力は天地を揺るがし、\\n一切の邪念を滅却する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、エンジェ\\n\u3000ル状態のキャラに呪いを付与する。\\n\u3000この効果により付与された呪いのダメージでは、\\n\u3000ＴＰが回復しない。\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。\\n・ＨＰが高い２キャラに魔法中ダメージを与え、\\n\u3000行動速度をダウンさせ、さらに魔法防御力を\\n\u3000ダウンさせる。\\n・残り時間が35秒を切ると、魔法攻撃力とＴＰ\\n\u3000がアップし、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (311600, '叫怖のゴーストファーザー', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】人間を恐怖に慄かせるお化けたちの首領。\\n手下をけしかけ、シマの拡大を密かに画策する。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。');
insert into unit_enemy_data values (311601, '叫怖のゴーストファーザー', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】人間を恐怖に慄かせるお化けたちの首領。\\n手下をけしかけ、シマの拡大を密かに画策する。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。');
insert into unit_enemy_data values (311602, '叫怖のゴーストファーザー', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】人間を恐怖に慄かせるお化けたちの首領。\\n手下をけしかけ、シマの拡大を密かに画策する。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。\\n・ゴーストファーザー自身のＨＰが40％を切る\\n\u3000と、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (311603, '叫怖のゴーストファーザー', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】人間を恐怖に慄かせるお化けたちの首領。\\n手下をけしかけ、シマの拡大を密かに画策する。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。\\n・ゴーストファーザー自身のＨＰが40％を切る\\n\u3000と、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (311604, '叫怖のゴーストファーザー', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【ＭＯＤＥ１】美味な魂を求め、お化けたちの首\\n領が再び姿を現す。残虐なファミリーを従え、\\n人々を蹂躙することで街を極上の悲鳴で満たす。\\n\\n・バトル開始時、ゴーストミニオンズを３体召喚\\n\u3000する。\\n・ゴーストミニオンズを１体倒すたびに、残り\\n\u3000ゴーストミニオンズ数が１減少する。\\n\u3000その後、ゴーストミニオンズが再度召喚される。\\n・ゴーストミニオンズは、目の前の敵１キャラの\\n\u3000ＴＰを減少させ、ゴーストファーザーのＴＰを\\n\u3000回復させる。\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。');
insert into unit_enemy_data values (311605, '叫怖のゴーストファーザー', 311600, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '【ＭＯＤＥ２】シマを荒らす、すべてに制裁を\\n下す。ひとたび彼のシマに踏み入れば、はびこる\\n魍魎が命を蝕み、生きながら地獄の苦しみを\\n与える。\\n\\n・バトル開始時、キャラの最大ＨＰが35％減少\\n\u3000する。減少したＨＰは、バトル終了まで解除\\n\u3000できない。\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。');
insert into unit_enemy_data values (311606, '叫怖のゴーストファーザー', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【ＭＯＤＥ３】蓄えた力をすべて吐き出し、真の\\n力を解放する。この世界を支配すべく、残虐非道\\nの限りを尽くし、地獄へと染め上げる。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。\\n・自身に物理/魔法無効バリアを展開する。\\n・ゴーストファーザー自身のＨＰが40％を\\n\u3000切ると、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (311700, 'ゴーストブラザーズ', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, 'ゴーストファーザーの側近の手下。\\n自身の体を盾にして、一切の攻撃から首領を守る。');
insert into unit_enemy_data values (311701, 'ゴーストブラザーズ', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, 'ゴーストファーザーの側近の手下。\\n鍛え上げた鉄砲玉で、街に特攻をしかける。血気\\n盛んに突撃し、逃げ惑う人々を恐怖の底に陥れる。\\n\\n・ゴーストブラザーズは攻撃の対象にならない。');
insert into unit_enemy_data values (311702, 'ゴーストブラザーズ', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, 'ゴーストファーザーの側近の手下。\\n鉄砲玉たちと集めた上質な精気を首領へ献上する。\\n\\n・ゴーストブラザーズは攻撃の対象にならない。\\n・ゴーストファーザーのＴＰを回復させる。\\n\u3000ゴーストファーザーが行動不能状態のときは、\\n\u3000ＴＰを回復しない。');
insert into unit_enemy_data values (311703, 'ゴーストブラザーズ', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, 'いよいよ訪れた出番に、鼻息荒く推参する。\\n気合十分の最強の盾が、歯向かう相手の心を折る。');
insert into unit_enemy_data values (311800, 'ゴーストブラザーズ', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, 'ゴーストファーザーの側近の手下。\\n取り立てた精気を首領へ渡し、補佐を務めあげる。\\n\\n・ゴーストファーザーのＴＰを回復させる。');
insert into unit_enemy_data values (311801, 'ゴーストブラザーズ', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, 'ゴーストファーザーの側近の手下。\\n首領の近辺を警護し、一分の隙も見せない。裏で\\nは密かに街の人々を絶望へ追い込もうと暗躍する。\\n\\n・ゴーストブラザーズは攻撃の対象にならない。');
insert into unit_enemy_data values (311802, 'ゴーストブラザーズ', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, 'ゴーストファーザーの側近の手下。\\n部下と取り立てた極上の精気を首領へ差し出す。\\n\\n・ゴーストブラザーズは攻撃の対象にならない。\\n・ゴーストファーザーのＴＰを回復させる。\\n\u3000ゴーストファーザーが行動不能状態のときは、\\n\u3000ＴＰを回復しない。');
insert into unit_enemy_data values (311803, 'ゴーストブラザーズ', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, 'ファミリーの危機を守るべく、冷静に戦況を見極\\nめる。命尽きる直前まで、首領の忠実なる右腕と\\nして補佐に徹する。\\n\\n・ゴーストファーザーのＴＰを回復させる。');
insert into unit_enemy_data values (311900, 'ブライトホーン', 311900, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】霞を食み、自身の姿も霞の\\n如く掴みどころがない。人を嫌い、\\n近づく者は容赦なく踏み潰す。\\n\\n・敵全体に魔法大ダメージを与え\\n\u3000る。さらに、火傷状態の敵はダ\\n\u3000メージがアップする。\\n\\n・最も物理攻撃力が高い敵を中心に\\n\u3000した範囲内に魔法中ダメージを与\\n\u3000え、火傷状態にする。');
insert into unit_enemy_data values (312000, 'オブシダンワイバーン', 312000, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】魔力を宿せし黒曜の結晶竜。美しい体躯\\nの輝きは冥府を彷徨いし魂の嘆きといわれている。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・オブシダンワイバーンから受けるすべてのダメ\\n\u3000ージで発生する、パーティキャラのＴＰ回復量\\n\u3000を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000キャラのＨＰが60％未満の場合、ＴＰを大ダ\\n\u3000ウン。\\n・敵全体のＨＰ吸収を特大ダウンし、さらに物理\\n\u3000防御力を大ダウン。\\n・最も魔法攻撃力が高い１キャラに物理大ダメー\\n\u3000ジ。\\n\u3000さらに、最も魔法攻撃力が高い１キャラを中心\\n\u3000とした範囲内の敵すべてに物理中ダメージを与\\n\u3000え、ＴＰを中ダウン。');
insert into unit_enemy_data values (312100, 'アンチビースト de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】人々の夢を奪い去る、負の魔法生物。\\n陰鬱な黒い霧で希望を覆い、人々の心を蝕む。');
insert into unit_enemy_data values (312101, 'アンチビースト de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】人々の夢を奪い去る、負の魔法生物。\\n陰鬱な黒い霧で希望を覆い、人々の心を蝕む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法中ダメージを与える。さらに、物理防御力\\n\u3000を小ダウン、魔法防御力を中ダウンさせ、\\n\u3000一定時間ＨＰ回復量を70％ダウンさせる。\\n・前方２キャラに物理中ダメージを与える。');
insert into unit_enemy_data values (312102, 'アンチビースト de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】人々の夢を奪い去る、負の魔法生物。\\n陰鬱な黒い霧で希望を覆い、人々の心を蝕む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法中ダメージを与える。さらに、物理防御力\\n\u3000を小ダウン、魔法防御力を中ダウンさせ、\\n\u3000一定時間ＨＰ回復量を70％ダウンさせる。\\n・前方２キャラに物理中ダメージを与える。');
insert into unit_enemy_data values (312103, 'アンチビースト de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】人々の夢を奪い去る、負の魔法生物。\\n陰鬱な黒い霧で希望を覆い、人々の心を蝕む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法中ダメージを与える。さらに、物理防御力\\n\u3000と魔法防御力を中ダウンさせ、一定時間ＨＰ回\\n\u3000復量を70％ダウンさせる。\\n・前方２キャラに物理大ダメージを与える。\\n・アンチビースト de M自身のＨＰが15％\\n\u3000を切ると、自分のＴＰを中アップさせ、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (312104, 'アンチビースト de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【ＭＯＤＥ１】街から愛と希望を吸い上げ奪う\\nアンチビースト。魔法少女たちをもねじ伏せ、\\n街中の全ての輝く力を取り込もうとする。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法大ダメージを与える。さらに、物理防御力\\n\u3000と魔法防御力を大ダウンさせ、一定時間ＨＰ回\\n\u3000復量を70％ダウンさせる。\\n・最も後ろの敵１キャラに最大ＨＰに応じた物理\\n\u3000割合ダメージを与え、束縛状態にし、ＴＰを\\n\u3000特大ダウンさせる。\\n\u3000さらに、アンチビースト de M自身のＴＰ\\n\u3000を中アップ。');
insert into unit_enemy_data values (312105, 'アンチビースト de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【ＭＯＤＥ２】魔法少女たちの猛攻をも取り込み\\nさらに膨れ上がるアンチビーストの渇望。更には\\n人々を守るための勇気までも溶蝕されてゆく。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法大ダメージを与える。さらに、物理防御力\\n\u3000と魔法防御力を大ダウンさせ、一定時間ＨＰ回\\n\u3000復量を70％ダウンさせる。\\n・敵全体のバリアを解除し、最大ＨＰに応じた\\n\u3000魔法割合ダメージを与え、毒状態にする。');
insert into unit_enemy_data values (312106, 'アンチビースト de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【ＭＯＤＥ３】負の情念は最高潮に達し、歪んだ\\n渇望が一帯を包み込む。魔法少女たちの信念を\\n挫き、守護者なき街を我が一部とせんとする。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法大ダメージを与える。さらに、物理防御力\\n\u3000と魔法防御力を大ダウンさせ、一定時間ＨＰ回\\n\u3000復量を70％ダウンさせる。\\n・前方２キャラに物理大ダメージを与える。\\n・アンチビースト de M自身のＨＰが12％\\n\u3000を切ると、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (312200, 'ドミネイテッドスノーマン', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】でっぷりとした眼光鋭い最恐雪ダルマ。\\n狂気をその身に纏いながら聖夜の街中を縷々転々。\\n年に一度の特別な夜がブラッククリスマスと化す。');
insert into unit_enemy_data values (312201, 'ドミネイテッドスノーマン', 312200, 0, 16, 270, 3000, 1, 4.0, 0, 0, 0, '【物理】でっぷりとした眼光鋭い最恐雪ダルマ。\\n狂気をその身に纏いながら聖夜の街中を縷々転々。\\n年に一度の特別な夜がブラッククリスマスと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。自身のターゲットがブレイク\\n\u3000していない場合、追加でスタン状態を付与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・残り時間が20秒を切ると、プレゼント型爆弾\\n\u3000を取り出し、その後一定時間が経過で、敵全体\\n\u3000にキャラの最大ＨＰに応じた物理割合ダメージ\\n\u3000を与える。\\n\u3000さらに、ドミネイテッドスノーマンにも自身の\\n\u3000残りＨＰに応じた物理割合ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・頭部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。');
insert into unit_enemy_data values (312202, 'ドミネイテッドスノーマン', 312200, 0, 16, 270, 3000, 1, 3.6, 0, 0, 0, '【物理】でっぷりとした眼光鋭い最恐雪ダルマ。\\n狂気をその身に纏いながら聖夜の街中を縷々転々。\\n年に一度の特別な夜がブラッククリスマスと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。自身のターゲットがブレイク\\n\u3000していない場合、追加でスタン状態を付与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・残り時間が20秒を切ると、プレゼント型爆弾\\n\u3000を取り出し、その後一定時間が経過で、敵全体\\n\u3000にキャラの最大ＨＰに応じた物理割合ダメージ\\n\u3000を与える。\\n\u3000さらに、ドミネイテッドスノーマンにも自身の\\n\u3000残りＨＰに応じた物理割合ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・頭部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。');
insert into unit_enemy_data values (312203, 'ドミネイテッドスノーマン', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】でっぷりとした眼光鋭い最恐雪ダルマ。\\n狂気をその身に纏いながら聖夜の街中を縷々転々。\\n年に一度の特別な夜がブラッククリスマスと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体にキャラの最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。自身のターゲットがブレ\\n\u3000イクしていない場合、追加でスタン状態を付与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。\\n・残り時間が20秒を切ると、プレゼント型爆弾\\n\u3000を取り出し、その後一定時間が経過で、敵全\\n\u3000体にキャラの最大ＨＰに応じた物理割合ダメ\\n\u3000ージを与える。\\n\u3000さらに、ドミネイテッドスノーマンにも自身\\n\u3000の残りＨＰに応じた物理割合ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・頭部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。');
insert into unit_enemy_data values (312204, 'ドミネイテッドスノーマン', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【ＭＯＤＥ１】パーティー会場を大混乱の渦に落\\nとす巨大雪ダルマ。もとは人々から愛された心優\\nしきマスコット。みんなの声援が攻略のカギとなる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体に魔法大ダメージを与え、凍結状態にす\\n\u3000る。\\n\u3000さらに、行動速度と物理防御力を大ダウンさせ\\n\u3000る。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・頭部のブレイク時、物理防御力と魔法防御力が\\n\u3000小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力が\\n\u3000小ダウン。\\n・バトル中、ドミネイテッドスノーマン自身に付\\n\u3000与されている状態異常効果およびステータスダ\\n\u3000ウン効果の数に応じて、与えられるダメージの\\n\u3000量が大きく上昇する。');
insert into unit_enemy_data values (312205, 'ドミネイテッドスノーマン', 312200, 0, 16, 270, 3000, 1, 20.0, 0, 0, 0, '【ＭＯＤＥ２】聖夜に浮かれる３人娘のシャドウ\\nを召喚。それは巨大雪ダルマの作った虚像。\\n自身の名誉のために、今こそ立ち上がれ乙女たち！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。自身のターゲットがブレイク\\n\u3000していない場合、追加でスタン状態を付与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・頭部のブレイク時、物理防御力と魔法防御力が\\n\u3000小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力が\\n\u3000小ダウン。');
insert into unit_enemy_data values (312206, 'ドミネイテッドスノーマン', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【ＭＯＤＥ３】すべての思いを轢殺せんと転がり\\n続ける巨大雪ダルマ。すべての寂しき人々へ、爆\\n炎の贈物を優しくプレゼントフォー・ユー♪\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体にキャラの最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。自身のターゲットがブレ\\n\u3000イクしていない場合、追加でスタン状態を付\\n\u3000与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。\\n・残り時間が20秒を切ると、プレゼント型爆弾\\n\u3000を取り出し、その後一定時間が経過で、敵全\\n\u3000体にキャラの最大ＨＰに応じた物理割合ダメ\\n\u3000ージを与える。\\n\u3000さらに、ドミネイテッドスノーマンにも自身\\n\u3000の残りＨＰに応じた物理割合ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・頭部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。');
insert into unit_enemy_data values (312300, 'グレートトゥンヌス', 312300, 0, 16, 270, 3000, 1, 1.1, 0, 0, 0, '');
insert into unit_enemy_data values (312301, 'グレートトゥンヌス', 312300, 0, 16, 270, 3000, 1, 4.0, 0, 0, 0, '【物理】オーマの漁師に古くから伝わる幻の巨魚。\\n巨躯超速の突進は、全ての船を海の藻屑と化す。\\nしかしその身はこの世のものと思えぬ絶品らしい。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。');
insert into unit_enemy_data values (312302, 'グレートトゥンヌス', 312302, 0, 16, 270, 3000, 1, 3.3, 0, 0, 0, '【物理】オーマの漁師に古くから伝わる幻の巨魚。\\n巨躯超速の突進は、全ての船を海の藻屑と化す。\\nしかしその身はこの世のものと思えぬ絶品らしい。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n・残り時間が35秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312303, 'グレートトゥンヌス', 312302, 0, 16, 270, 3000, 1, 1.1, 0, 0, 0, '【物理】オーマの漁師に古くから伝わる幻の巨魚。\\n巨躯超速の突進は、全ての船を海の藻屑と化す。\\nしかしその身はこの世のものと思えぬ絶品らしい。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n・残り時間が35秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312304, 'グレートトゥンヌス', 312302, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【ＭＯＤＥ１】数多の漁師を波間に沈めた海の王。\\n黄金に輝くヒレで大漁船の竜骨をも圧し折る。\\nその様はさながら大海原の解体ショー\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000さらに後ろから２キャラに物理中ダメージを\\n\u3000与える。また、自身の物理攻撃力を小アップ\\n\u3000させる。');
insert into unit_enemy_data values (312305, 'グレートトゥンヌス', 312305, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '【ＭＯＤＥ２】海を駆ける怪魚はさらに力を増す。\\nひと泳ぎで自身を鼓舞するかのように大渦をおこ\\nし大海を分かつ巨大な砲弾となって敵に激突する。\\n\\n・ユニオンバーストは、前から３キャラに\\n\u3000物理特大ダメージを与え\\n\u3000さらにノックバックさせる。\\n・自身の物理攻撃力を大アップ、行動速度を\\n\u3000中アップ、ＴＰを小アップさせる。');
insert into unit_enemy_data values (312306, 'グレートトゥンヌス', 312302, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '【ＭＯＤＥ３】幾度もその黒い巨体に銛を受けよ\\nうとも、伝説の巨魚の猛進は止められない。\\n永きにわたる海の漢たちとの勝負の決着の時。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n・自身の物理攻撃力を大アップ、行動速度を\\n\u3000中アップ、ＴＰを大アップさせる。\\n・残り時間が35秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312400, 'アイスグリフォン', 312400, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】氷翼を広げ、冒険者を威嚇\\nする大鷲。縄張りに踏み込んだ者\\nを、容赦なく氷漬けにし子どもたち\\nの贄とする。\\n\\n・ユニオンバーストは、前方小範囲\\n\u3000に物理大ダメージを与え、さらに\\n\u3000大きく吹き飛ばし、氷結状態に\\n\u3000する。');
insert into unit_enemy_data values (312401, 'アイスグリフォン', 312400, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】氷翼を広げ、冒険者を威嚇\\nする大鷲。縄張りに踏み込んだ者\\nを、容赦なく氷漬けにし子どもたち\\nの贄とする。\\n\\n・ユニオンバーストは、前方小範囲\\n\u3000に物理大ダメージを与え、さらに\\n\u3000大きく吹き飛ばし、氷結状態に\\n\u3000する。');
insert into unit_enemy_data values (312500, 'マダムエレクトラ', 312500, 0, 6, 270, 1000, 2, 1.6, 0, 0, 0, '【魔法】塔の魔力を蓄え雷撃として放電する怪鳥。\\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\\n\\n・敵全体に魔法大ダメージを与え、自分の魔法\\n\u3000攻撃力と、行動速度を小アップさせる。\\n\u3000物理攻撃をする敵にはさらに追加ダメージ。\\n・前方範囲内の敵すべてに魔法中ダメージを与え\\n\u3000物理防御力と魔法防御力を中ダウンさせる。\\n・物理攻撃力が最も高い敵１キャラに魔法大\\n\u3000ダメージを与え、長時間麻痺状態にする。\\n\u3000自分のＨＰが85％を切ると、魔法攻撃力が\\n\u3000最も高い敵にもこの攻撃を行う。');
insert into unit_enemy_data values (312600, 'ジェネラルホーン', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '');
insert into unit_enemy_data values (312601, 'ジェネラルホーン', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】立派な麋角をもつ大型魔物。大岩をも\\n軽々粉砕する大角で冒険者をまとめて薙ぎ払う。\\n\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。');
insert into unit_enemy_data values (312602, 'ジェネラルホーン', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】立派な麋角をもつ大型魔物。大岩をも\\n軽々粉砕する大角で冒険者をまとめて薙ぎ払う。\\n\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312603, 'ジェネラルホーン', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】立派な麋角をもつ大型魔物。大岩をも\\n軽々粉砕する大角で冒険者をまとめて薙ぎ払う。\\n\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312604, 'ジェネラルホーン', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【ＭＯＤＥ１】首領の雄たけびで、手先の牡鹿が\\n群れを成し押し寄せる。捨て身の突進を食い止め\\nられるか？\\n\\n・バトル開始時、ワイルドホーンを３体召喚し、\\n\u3000さらにノックバックさせる。\\n・ワイルドホーンを１体倒すたびに、残りワイル\\n\u3000ドホーン数が１減少する。\\n\u3000その後、ワイルドホーンが再度召喚され、ノッ\\n\u3000クバックさせる。\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。');
insert into unit_enemy_data values (312605, 'ジェネラルホーン', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【ＭＯＤＥ２】朽木の魔物を従え、冒険者を追い\\n詰める。共生の朽木を失うとその身もともに破滅\\nへと向かう。朽木の撃滅が攻略のカギとなる。\\n\\n・バトル開始時、トレントを２体召喚し、さらに\\n\u3000ノックバックさせる。\\n・前方のトレントのＨＰが０になった時、ジェネ\\n\u3000ラルホーンの物理・魔法防御力を小ダウンさせ\\n\u3000る。\\n・後方のトレントのＨＰが０になった時、ジェネ\\n\u3000ラルホーンの物理・魔法防御力を極大ダウンさ\\n\u3000せる。\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。');
insert into unit_enemy_data values (312606, 'ジェネラルホーン', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【ＭＯＤＥ３】手負いの角獣が死力を振り絞る。\\n命を賭した突進は体躯を紫電に変え、光の如き\\n一閃は歴戦の冒険者一行を瓦解させる。\\n\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312700, '黒風の精霊', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '');
insert into unit_enemy_data values (312701, '黒風の精霊', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】使役者の真の力を試す黒き風の精霊。\\nそこには悪意はなく、純粋に己の内に秘めた想い\\nと絆が試される。\\n\\n・ユニオンバーストは、敵全体に黒風の精霊\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。さらに、\\n\u3000残りＨＰが最も低い１キャラにカウントダウン\\n\u3000を付与し、５秒後に最大ＨＰの80%の魔法\\n\u3000割合ダメージを与える。');
insert into unit_enemy_data values (312702, '黒風の精霊', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】使役者の真の力を試す黒き風の精霊。\\nそこには悪意はなく、純粋に己の内に秘めた想い\\nと絆が試される。\\n\\n・ユニオンバーストは、敵全体に黒風の精霊\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。さらに、\\n\u3000残りＨＰが最も低い１キャラにカウントダウン\\n\u3000を付与し、５秒後に最大ＨＰの80%の魔法\\n\u3000割合ダメージを与える。\\n・敵全体を猛毒状態にし、さらに物理・魔法攻撃\\n\u3000力を大ダウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312703, '黒風の精霊', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】使役者の真の力を試す黒き風の精霊。\\nそこには悪意はなく、純粋に己の内に秘めた想い\\nと絆が試される。\\n\\n・ユニオンバーストは、敵全体に黒風の精霊\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。さらに、\\n\u3000残りＨＰが最も低い１キャラにカウントダウン\\n\u3000を付与し、５秒後に最大ＨＰの80%の魔法\\n\u3000割合ダメージを与える。\\n・敵全体を猛毒状態にし、さらに物理・魔法攻撃\\n\u3000力を大ダウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312704, '黒風の精霊', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【ＭＯＤＥ１】第一の試練。黒き風の精霊の暴風\\nの継ぎ目を見切れば、自ずと己の進むべき道が\\n切り拓かれん。\\n\\n・敵全体に物理ダメージとスタンを与え、ノック\\n\u3000バックさせる。\\n\u3000黒風の精霊が眠っている間、自身の物理防御力\\n\u3000が大幅にダウンし、その間に100000以上\\n\u3000のダメージを与えると、防御力ダウンが延長さ\\n\u3000れ行動速度もダウンする。');
insert into unit_enemy_data values (312705, '黒風の精霊', 312705, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【ＭＯＤＥ２】第二の試練。己の弱き心と対峙\\nせよ。いつも答えは己の内にある。今一度、仲間\\nの力を信じ立ち向かえ。\\n\\n・前から２キャラに物理小ダメージを与え、さら\\n\u3000にノックバックさせ、スタンを与える。');
insert into unit_enemy_data values (312706, '黒風の精霊', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【ＭＯＤＥ３】第三の試練。終の試練は、己の\\nすべてを懸け黒き風の精霊に本当の想いと絆を\\n顕現し、己の想いを確かめよ。\\n\\n・ユニオンバーストは、敵全体に黒風の精霊\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。さらに、\\n\u3000残りＨＰが最も低い１キャラにカウントダウン\\n\u3000を付与し、５秒後に最大ＨＰの80%の魔法\\n\u3000割合ダメージを与える。\\n・敵全体を猛毒状態にし、さらに物理・魔法攻撃\\n\u3000力を大ダウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (312800, '魔物の姫', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (312801, '魔物の姫', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】辺境の城に座する、孤高な魔物の姫君。\\n悲哀なる恋慕を胸に、自らに挑む者を打ち砕く。\\n\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n\u3000力を溜めることに成功した場合、ダメージが\\n\u3000アップし、敵全体を畏怖状態にする。\\n\u3000畏怖状態のキャラは、一定時間攻撃およびＨＰ\\n\u3000回復のユニオンバーストとスキルの効果が\\n\u3000ダウン。\\n・物理防御力と魔法防御力が大幅にダウンした後、\\n\u3000一定時間、力を溜める。\\n\u3000力が溜まると、ＴＰが特大回復する。\\n\u3000力を溜めている間に魔物の姫が7000以上の\\n\u3000ダメージを受けると、力を溜めることに失敗し、\\n\u3000ＴＰが大ダウン。 \\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。');
insert into unit_enemy_data values (312802, '魔物の姫', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】辺境の城に座する、孤高な魔物の姫君。\\n悲哀なる恋慕を胸に、自らに挑む者を打ち砕く。\\n\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n\u3000力を溜めることに成功した場合、ダメージが\\n\u3000アップし、敵全体を畏怖状態にする。\\n\u3000畏怖状態のキャラは、一定時間攻撃およびＨＰ\\n\u3000回復のユニオンバーストとスキルの効果が\\n\u3000ダウン。\\n・物理防御力と魔法防御力が大幅にダウンした後、\\n\u3000一定時間、力を溜める。\\n\u3000力が溜まると、ＴＰが特大回復する。\\n\u3000力を溜めている間に魔物の姫が21000以上\\n\u3000のダメージを受けると、力を溜めることに失敗\\n\u3000し、ＴＰが大ダウン。 \\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。');
insert into unit_enemy_data values (312803, '魔物の姫', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】辺境の城に座する、孤高な魔物の姫君。\\n悲哀なる恋慕を胸に、自らに挑む者を打ち砕く。\\n\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n\u3000力を溜めることに成功した場合、ダメージが\\n\u3000アップし、敵全体を畏怖状態にする。\\n\u3000畏怖状態のキャラは、一定時間攻撃およびＨＰ\\n\u3000回復のユニオンバーストとスキルの効果が\\n\u3000ダウン。\\n・物理防御力と魔法防御力が大幅にダウンした後、\\n\u3000一定時間、力を溜める。\\n\u3000力が溜まると、ＴＰが特大回復する。\\n\u3000力を溜めている間に魔物の姫が260000\\n\u3000以上のダメージを受けると、力を溜めることに\\n\u3000失敗し、ＴＰが大ダウン。 \\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・魔物の姫自身のＨＰが25％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (312804, '魔物の姫', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ１】高潔なる姫君は従兵を以て対敵を\\n拒絶する。さながら内なる嘆きを虚飾するが如く。\\n\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。');
insert into unit_enemy_data values (312805, '魔物の姫', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ２】姫君は更なる力を解き放つ。\\n歪曲した強き恋慕で、全てを拒み屠らんとする。\\n\\n・敵からの攻撃による麻痺、スタン、束縛、凍結、\\n\u3000時間停止、行動速度低下効果への耐性を持たな\\n\u3000い。\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・短時間無敵状態になり、敵全体のステータス\\n\u3000アップ効果を解除した後、一定時間バトルフ\\n\u3000ィールドを展開する。\\n\\n【バトルフィールド効果】\\n・敵全体の物理攻撃力と魔法攻撃力を100％\\n\u3000ダウンした後、物理攻撃力と魔法攻撃力を\\n\u3000特大アップ。\\n・魔物の姫の物理攻撃力を特大アップ。');
insert into unit_enemy_data values (312806, '魔物の姫', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ３】大いなる悲哀に呼応して、姫君の\\n進攻は苛烈を極める。乙女の熱情を以て、その\\n悲しみに救いをもたらさん。\\n\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n\u3000力を溜めることに成功した場合、ダメージが\\n\u3000アップし、敵全体を畏怖状態にする。\\n\u3000畏怖状態のキャラは、一定時間攻撃およびＨＰ\\n\u3000回復のユニオンバーストとスキルの効果が\\n\u3000ダウン。\\n・物理防御力と魔法防御力が大幅にダウンした後、\\n\u3000一定時間、力を溜める。\\n\u3000力が溜まると、ＴＰが特大回復する。\\n\u3000力を溜めている間に魔物の姫が600000\\n\u3000以上のダメージを受けると、力を溜めることに\\n\u3000失敗し、ＴＰが大ダウン。 \\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・魔物の姫自身のＨＰが25％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (312900, '黒月の守護像', 312900, 0, 16, 270, 3000, 1, 2.5, 0, 0, 0, '【物理】天上の聖域を護る、黒月に祝福されし像。\\n聖域に踏み入る、冒険者を常世の闇に葬り去る。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・敵全体に物理大ダメージを与え、ステータス\\n\u3000アップ効果を解除する。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・自身の物理攻撃力と魔法攻撃力を大アップさ\\n\u3000せる。白陽の守護像が討伐されている場合、\\n\u3000このスキルを使用する。\\n・黒月の守護像のＨＰが50％を切ると、物理\\n\u3000攻撃力を大アップさせ、物理防御力を中アップ\\n\u3000する。\\n・黒月の守護像のターゲットがブレイクしてい\\n\u3000る場合、物理防御力と魔法防御力が小ダウンす\\n\u3000る。\\n・白陽の守護像が討伐されていた場合、バトルス\\n\u3000タートの際、もしくは黒月の守護像が通常攻撃\\n\u3000を行った際に、黒月の守護像の攻撃行動を変更\\n\u3000する。');
insert into unit_enemy_data values (313000, '白陽の守護像', 313000, 0, 16, 270, 3000, 2, 2.5, 0, 0, 0, '【魔法】天上の聖域を護る、白陽に祝福されし像。\\n全てを浄化する白雷で、冒険者に審判を下す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n・敵全体に魔法大ダメージを与え、ステータス\\n\u3000アップ効果を解除する。さらに白陽の守護像の\\n\u3000魔法攻撃力を大アップする。このスキルの効果\\n\u3000はダメージを無効化しても付与される。黒月の\\n\u3000守護像が討伐されている場合、このスキルを使\\n\u3000用する。\\n・味方全体の物理防御力と魔法防御力を中アップ\\n\u3000させる。\\n・白陽の守護像のＨＰが50％を切ると、魔法攻\\n\u3000撃力を特大アップさせ、魔法防御力を小アップ\\n\u3000する。\\n・白陽の守護像のターゲットがブレイクしている\\n\u3000場合、物理防御力と魔法防御力が小ダウンする。\\n・黒月の守護像が討伐されていた場合、バトルス\\n\u3000タートの際、もしくは白陽の守護像が通常攻撃\\n\u3000を行った際に、白陽の守護像の攻撃行動を変更\\n\u3000する。');
insert into unit_enemy_data values (313100, 'バースト・タイムラーベ', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '');
insert into unit_enemy_data values (313101, 'バースト・タイムラーベ', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】ホマレ所蔵の魔道具が、臨界を超え暴走\\nした姿。本来の役目も忘れ、冒険者を混沌へと\\n導く水先案内人と化す。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。');
insert into unit_enemy_data values (313102, 'バースト・タイムラーベ', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】ホマレ所蔵の魔道具が、臨界を超え暴走\\nした姿。本来の役目も忘れ、冒険者を混沌へと\\n導く水先案内人と化す。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。');
insert into unit_enemy_data values (313103, 'バースト・タイムラーベ', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】ホマレ所蔵の魔道具が、臨界を超え暴走\\nした姿。本来の役目も忘れ、冒険者を混沌へと\\n導く水先案内人と化す。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・残り時間が25秒を切ると、自分のTPを大アッ\\n\u3000プさせ、さらに攻撃が激しく凶暴になる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。');
insert into unit_enemy_data values (313104, 'バースト・タイムラーベ', 313104, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【ＭＯＤＥ１】暴走した魔道具は、すべてのもの\\nを自身の領域に留めようとする。幾重もの障壁に\\nも屈せず、己を信じ未来を切り拓け。\\n\\n・このバトルでは、全てのターゲットがブレイク\\n\u3000無効。\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージを与えるたびに徐々に耐久性\\n\u3000を失っていき、一定量のダメージを与えるとバ\\n\u3000リアは破壊される。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。');
insert into unit_enemy_data values (313105, 'バースト・タイムラーベ', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【ＭＯＤＥ２】イノリとカヤのシャドウを召喚。\\n自身の「もしも」の姿に二人は何を見るのか。\\n虚構を打ち破り己の道筋の正しさを証明する時。\\n\\n・このバトルでは、全てのターゲットがブレイク\\n\u3000無効。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。');
insert into unit_enemy_data values (313106, 'バースト・タイムラーベ', 313100, 0, 16, 270, 3000, 2, 0.8, 0, 0, 0, '【ＭＯＤＥ３】主を失った魔道具はコントロール\\nを失い、暴走を続ける。降り注ぐ絶望に抗い続け\\nれば、一筋の希望の光の道が開かれん。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・残り時間が25秒を切ると、自分のTPを大アッ\\n\u3000プさせ、さらに攻撃が激しく凶暴になる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。');
insert into unit_enemy_data values (313200, '名もなき芸術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '');
insert into unit_enemy_data values (313201, '名もなき芸術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】制作者の深淵が表出した？異形の芸術\\n作品の魔物。その風貌は常人の尺度では到底理解\\n不能で、分かる人には分かる、とは制作者の談。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前から３番目のキャラを中心とした範囲に、\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、火傷状態のキャラには追加で最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。');
insert into unit_enemy_data values (313202, '名もなき芸術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】制作者の深淵が表出した？異形の芸術\\n作品の魔物。その風貌は常人の尺度では到底理解\\n不能で、分かる人には分かる、とは制作者の談。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前から３番目のキャラを中心とした範囲に、\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、火傷状態のキャラには追加で最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。');
insert into unit_enemy_data values (313203, '名もなき芸術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】制作者の深淵が表出した？異形の芸術\\n作品の魔物。その風貌は常人の尺度では到底理解\\n不能で、分かる人には分かる、とは制作者の談。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前から３番目のキャラを中心とした範囲に、\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、火傷状態のキャラには追加で最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・残り時間が30秒を切ると、自分のＴＰを\\n\u3000小アップさせ、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (313204, '名もなき芸術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【ＭＯＤＥ１】命を宿した粘土人形は止まらない。\\n内なる異形の魔力を放出し、繰り出される光線に\\n少女たちは、レジスト済みの校舎は耐えられるか？\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前方範囲内の敵のバリアを解除し、最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000さらに、束縛状態にする。\\n\u3000ただし、名もなき芸術が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けている場合、束縛は付与\\n\u3000されない。\\n・自分が毒、猛毒、呪い、火傷、呪詛の効果を\\n\u3000受けると、自分の物理・魔法防御力が特大\\n\u3000ダウンする。');
insert into unit_enemy_data values (313205, '名もなき芸術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【ＭＯＤＥ２】粘土人形が描くはこれまた独創的\\nなデザインの魔法陣。そのビジュアルに騙される\\nことなかれ、気を抜けば一瞬にしてぺしゃんこに。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・通常攻撃は、前方１キャラに物理中ダメージを\\n\u3000与える。\\n\u3000名もなき芸術が保持している【せんす】の数が\\n\u3000多いほどダメージがアップする。\\n・前から３番目のキャラを中心とした範囲に\\n\u3000物理中ダメージを与える。\\n\u3000名もなき芸術が保持している【せんす】の数が\\n\u3000多いほどダメージがアップする。\\n・バトル開始時、魔法陣を展開する。\\n\\n【魔法陣効果】\\n・名もなき芸術に毎秒【せんす】を３つ追加する。\\n・名もなき芸術がダメージを受けるたびに\\n\u3000名もなき芸術の【せんす】を１つ減少させる。');
insert into unit_enemy_data values (313206, '名もなき芸術', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【ＭＯＤＥ３】残された力を振り絞り、最期の狂\\n気をまき散らす粘土人形。彼女らの輝かしい学生\\n生活は守れるのか。立ち向かえ、なかよし部！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前から３番目のキャラを中心とした範囲に、\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、火傷状態のキャラには追加で最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・残り時間が30秒を切ると、自分のＴＰを\\n\u3000大アップさせ、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (313300, '究極玩具王 メガトイキング', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '');
insert into unit_enemy_data values (313301, '究極玩具王 メガトイキング', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【物理】忘れられ暴走する悲しき玩具の王さま。\\n三度、子供たちに忘れられる、恐怖と悲しみに\\n震える。さぁ！今こそBB団の立ち上がるとき！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、目の\\n\u3000前の敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。');
insert into unit_enemy_data values (313302, '究極玩具王 メガトイキング', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【物理】忘れられ暴走する悲しき玩具の王さま。\\n三度、子供たちに忘れられる、恐怖と悲しみに\\n震える。さぁ！今こそBB団の立ち上がるとき！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、目の\\n\u3000前の敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。');
insert into unit_enemy_data values (313303, '究極玩具王 メガトイキング', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【物理】忘れられ暴走する悲しき玩具の王さま。\\n三度、子供たちに忘れられる、恐怖と悲しみに\\n震える。さぁ！今こそBB団の立ち上がるとき！\\n\\n・究極玩具王 メガトイキング自身のＨＰが40％\\n\u3000を切ると両腕が輝き出し、攻撃が激しく凶暴\\n\u3000になる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、目の\\n\u3000前の敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n\u3000両腕が輝いている場合、ダメージがアップし、\\n\u3000さらに目の前の敵１キャラに物理大ダメージ\\n\u3000を与える\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n\u3000両腕が輝いている場合、ダメージがアップし、\\n\u3000このスキルによるダメージではＴＰが回復し\\n\u3000ない。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000両腕が輝いている場合、このスキルによる\\n\u3000ダメージではＴＰが回復しない。');
insert into unit_enemy_data values (313304, '究極玩具王 メガトイキング', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【ＭＯＤＥ１】暴走する友の前に小さきヒーロー\\nが立ちはだかる。彼を悲しみから救い出せるか？\\nマイフレくんと共にさぁ立ち向かえ、BB団！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、目の\\n\u3000前の敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n・マイフレンドくんがキャラの味方として一定\\n\u3000時間現れ、究極玩具王 メガトイキングが行動\\n\u3000不能になる。\\n\u3000さらにマイフレンドくんを中心に、範囲内の\\n\u3000キャラの物理攻撃力と物理クリティカルと\\n\u3000ＴＰ上昇を特大アップさせるフィールドを\\n\u3000展開する。');
insert into unit_enemy_data values (313305, '究極玩具王 メガトイキング', 313305, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【ＭＯＤＥ２】悲しき玩具王がみせる虚像。自分\\n自身と向き合うのは怖いもの。一人じゃない！\\nそんな強い思いを胸に、負けるな、BB団！\\n\\n・アオイ、ミフユ、タマキのシャドウを召喚。\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。');
insert into unit_enemy_data values (313306, '究極玩具王 メガトイキング', 313300, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【ＭＯＤＥ３】悲しき玩具王の最後の抵抗。\\n忘却の寂しさに支配された力は破滅的で強大。\\n友を思う気持ちを力に変え、救い出せ、BB団！\\n\\n・究極玩具王 メガトイキング自身のＨＰが20％\\n\u3000を切ると両腕が輝き出す。物理防御力と魔法\\n\u3000防御力が特大ダウンし、攻撃が激しく凶暴に\\n\u3000なる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、目の\\n\u3000前の敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n\u3000両腕が輝いている場合、ダメージがアップし、\\n\u3000さらに目の前の敵１キャラに物理大ダメージ\\n\u3000を与える。\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n\u3000両腕が輝いている場合、ダメージがアップし、\\n\u3000このスキルによるダメージではＴＰが回復し\\n\u3000ない。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000両腕が輝いている場合、このスキルによる\\n\u3000ダメージではＴＰが回復しない。');
insert into unit_enemy_data values (313400, 'ソードコブラ', 313400, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【物理】紅き邪剣を尾に宿す、凶暴な大毒蛇。\\n獲物を毒息で弱らせ、一撃必殺の剣で葬り去る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ソードコブラから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も魔法攻撃力の高い敵\\n\u3000１キャラに物理大ダメージを与える。\\n\u3000猛毒状態の場合はさらに追加ダメージ。\\n\u3000その後、敵全体のＨＰ吸収を特大ダウン。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。\\n\u3000既に毒状態の敵には猛毒状態を付与する。\\n・前から１番目の敵に物理中ダメージを与え、毒\\n\u3000状態を付与する。\\n・ソードコブラの付与する毒および猛毒のダメー\\n\u3000ジでは、キャラのＴＰが回復しない。');
insert into unit_enemy_data values (313500, 'カリザ', 313500, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '魔物を意のままに操り、強化する辣鞭の少年。\\n赤青黄のスライムを従え、機敏なる猛攻を行う。\\n\\n・ユニオンバーストは、前方範囲内の敵にカリザ\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え\\n\u3000る。\\n・カリザの物理攻撃力を大アップ。\\n・前から１番目のキャラにカリザの物理攻撃力に\\n\u3000応じた物理割合ダメージを与える。');
insert into unit_enemy_data values (313501, 'カリザ', 313501, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '魔物を意のままに操り、強化する辣鞭の少年。\\n赤青黄のスライムを従え、機敏なる猛攻を行う。\\n\\n・ユニオンバーストは、前方範囲内の敵にカリザ\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え\\n\u3000る。\\n・カリザの物理攻撃力を大アップ。\\n・前から１番目のキャラにカリザの物理攻撃力に\\n\u3000応じた物理割合ダメージを与える。');
insert into unit_enemy_data values (313600, 'ランファ', 313600, 0, 16, 270, 3001, 2, 3.0, 0, 0, 0, '天稟の才と過敏な感覚に懊悩する、幽寂の歌姫。\\n争いは好まないが、願いと仲間のため奮戦する。\\n\\n・ユニオンバーストは、前方範囲内の敵に魔法中\\n\u3000ダメージを与え、結晶化状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000結晶化状態では行動不能になり、継続ダメージ\\n\u3000を受ける。\\n\u3000結晶化状態はＨＰが全回復するか、一定時間経\\n\u3000過すると解除される。\\n・前方範囲内の敵に猛毒状態を付与する。\\n\u3000結晶化状態の敵には追加の魔法大ダメージを与\\n\u3000える。\\n・前から１番目のキャラに魔法小ダメージ。');
insert into unit_enemy_data values (313601, 'ランファ', 313601, 0, 16, 270, 3001, 2, 3.0, 0, 0, 0, '天稟の才と過敏な感覚に懊悩する、幽寂の歌姫。\\n争いは好まないが、願いと仲間のため奮戦する。\\n\\n・ユニオンバーストは、前方範囲内の敵に魔法中\\n\u3000ダメージを与え、結晶化状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000結晶化状態では行動不能になり、継続ダメージ\\n\u3000を受ける。\\n\u3000結晶化状態はＨＰが全回復するか、一定時間経\\n\u3000過すると解除される。\\n・前方範囲内の敵に猛毒状態を付与する。\\n\u3000結晶化状態の敵には追加の魔法大ダメージを与\\n\u3000える。\\n・前から１番目のキャラに魔法小ダメージ。');
insert into unit_enemy_data values (313700, 'ミソラ', 313700, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '常に明朗快活、誰とでも友達になれる溌溂少女。\\n回転式銃を愛用し、単独で飽和攻撃を仕掛ける。\\n\\n・バトル開始時、ぺんぽこりんを召喚する。\\n\u3000召喚時、前方範囲内の敵全てをノックバックす\\n\u3000る。\\n\u3000ぺんぽこりんは前から２キャラに物理大ダメー\\n\u3000ジを与える。\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。\\n\u3000さらに、ぺんぽこりんの物理攻撃力と行動速度\\n\u3000を大アップ。\\n・ぺんぽこりんのＨＰを回復する。\\n・前から１番目のキャラに物理小ダメージを与え\\n\u3000る。');
insert into unit_enemy_data values (313701, 'ミソラ', 313701, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '常に明朗快活、誰とでも友達になれる溌溂少女。\\n回転式銃を愛用し、単独で飽和攻撃を仕掛ける。\\n\\n・バトル開始時、ぺんぽこりんを召喚する。\\n\u3000召喚時、前方範囲内の敵全てをノックバックす\\n\u3000る。\\n\u3000ぺんぽこりんは前から２キャラに物理大ダメー\\n\u3000ジを与える。\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。\\n\u3000さらに、ぺんぽこりんの物理攻撃力と行動速度\\n\u3000を大アップ。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。\\n・ぺんぽこりんのＨＰを回復する。\\n・前から１番目のキャラに物理小ダメージを与え\\n\u3000る。');
insert into unit_enemy_data values (313800, 'アゾールド', 313800, 0, 16, 270, 3000, 1, 1.5, 0, 0, 0, '常に幾つもの奥の手を隠し持つ、大食の紳士。\\n万能人形を駆使し、知略戦略で敵を追い詰める。\\n\\n・ユニオンバーストは、敵全体にアゾールドの物\\n\u3000理攻撃力に応じた物理割合ダメージを与える。\\n\u3000さらに、アゾールドの物理防御力と魔法防御力\\n\u3000を大ダウン。\\n・万能人形を召喚し敵全体をノックバックさせる。\\n\u3000万能人形は前から１番目のキャラに物理小ダメー\\n\u3000ジを与える。\\n\u3000万能人形のＨＰが一定値以下になった時、アゾー\\n\u3000ルドの物理防御力と魔法防御力を大ダウンさせ\\n\u3000る。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (313801, 'アゾールド', 313801, 0, 16, 270, 3000, 1, 1.5, 0, 0, 0, '常に幾つもの奥の手を隠し持つ、大食の紳士。\\n万能人形を駆使し、知略戦略で敵を追い詰める。\\n\\n・ユニオンバーストは、敵全体にアゾールドの物\\n\u3000理攻撃力に応じた物理割合ダメージを与える。\\n\u3000さらに、アゾールドの物理防御力と魔法防御力\\n\u3000を大ダウン。\\n・万能人形を召喚し敵全体をノックバックさせる。\\n\u3000万能人形は前から１番目のキャラに物理小ダメー\\n\u3000ジを与える。\\n\u3000万能人形のＨＰが一定値以下になった時、アゾー\\n\u3000ルドの物理防御力と魔法防御力を大ダウンさせ\\n\u3000る。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (313900, 'ゼーン', 313900, 0, 16, 270, 3000, 1, 1.0, 313900, 313900, 0, '一騎当千、万夫不当の実力を揮う寡黙な剣士。\\n覚醒することで、龍は更なる高みへと昇る。\\n\\n・ユニオンバーストは、敵全体にゼーンの物理\\n\u3000攻撃力と残りＨＰに応じた物理割合ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰ回復量\\n\u3000は減少する。\\n・敵全体に物理中ダメージを与え、スタンさせ\\n\u3000る。\\n・ゼーンのＴＰ上昇、行動速度、物理攻撃力を\\n\u3000大アップ。\\n\u3000このスキルの効果は発動するたびにアップす\\n\u3000る。\\n\u3000３回目の発動時は、さらにＴＰ1000アップ。\\n・前から１番目のキャラに物理中ダメージを与\\n\u3000え、小さく吹き飛ばす。');
insert into unit_enemy_data values (313901, 'ゼーン', 313901, 0, 16, 270, 3000, 1, 1.0, 313900, 313900, 0, '');
insert into unit_enemy_data values (314000, '宿題', 314000, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '');
insert into unit_enemy_data values (314001, '得意な宿題', 314001, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, 'まずは手始めに得意な宿題を終わらせよう。\\nここでつまづいてはいられない。夏休みの宿題は\\nほかにもまだまだあるぞ！！\\n\\n・バトル開始後、大量の宿題が降り注ぎ、\\n\u3000敵全体にダメージ。\\n・バトル中、一定時間が経過するごとに\\n\u3000モンスターが押し寄せてくる。');
insert into unit_enemy_data values (314002, 'ちょっと苦手な宿題', 314002, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '誰にでもある苦手科目の宿題。ついつい後回しに\\nしがちで、溜まってしまうとなかなか大変。\\nここで立ち止まるわけにはいかないぞ！\\n\\n・バトル開始後、大量の宿題が降り注ぎ、\\n\u3000敵全体にダメージ。\\n・バトル中、一定時間が経過するごとに\\n\u3000モンスターが押し寄せてくる。');
insert into unit_enemy_data values (314003, 'すごく苦手な宿題', 314003, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '眺めているだけで眩暈のするいや～な宿題。\\nペンを置いて外に飛び出したくなる衝動を耐え、\\nコツコツ進めていくことが攻略のカギ！\\n\\n・バトル開始後、大量の宿題が降り注ぎ、\\n\u3000敵全体にダメージ。\\n・バトル中、一定時間が経過するごとに\\n\u3000モンスターが押し寄せてくる。');
insert into unit_enemy_data values (314004, '夏休み最後まで残りし宿題', 314004, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, 'SP MODE1');
insert into unit_enemy_data values (314005, '夏休み最後まで残りし宿題', 314005, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, 'SP MODE2');
insert into unit_enemy_data values (314006, '夏休み最後まで残りし宿題', 314006, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '夏休みの間ずっと、目を背けてきた最後の宿題。\\nここまで放置してきた後悔が一気に襲い掛かる。\\nすべてやり遂げて笑顔で登校できるか！？\\n\\n・バトル開始後、大量の宿題が降り注ぎ、\\n\u3000敵全体にダメージ。\\n・バトル中、一定時間が経過するごとに\\n\u3000モンスターが押し寄せてくる。');
insert into unit_enemy_data values (314100, 'クイーンウタクラゲ', 314100, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314101, 'クイーンウタクラゲ', 314100, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】華のように大海をゆらめき、歌声を奏で\\nるウタクラゲの女王。美しく飾られたその姿の内\\nには猛毒の体液を隠し持つ。\\n\\n・ユニオンバーストは、敵全体にキャラのＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000猛毒状態の敵にはダメージがアップする。\\n\u3000さらに敵に毒状態を付与し、既に毒か猛毒状態\\n\u3000の敵には猛毒状態を付与する。\\n・目の前の敵１キャラに魔法大ダメージを与える。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。\\n\u3000敵が猛毒状態の場合、スタンさせる。\\n・クイーンウタクラゲの付与する毒および猛毒の\\n\u3000ダメージでは、キャラのＴＰが回復しない。');
insert into unit_enemy_data values (314102, 'クイーンウタクラゲ', 314100, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】華のように大海をゆらめき、歌声を奏で\\nるウタクラゲの女王。美しく飾られたその姿の内\\nには猛毒の体液を隠し持つ。\\n\\n・ユニオンバーストは、敵全体にキャラのＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000猛毒状態の敵にはダメージがアップする。\\n\u3000さらに敵に毒状態を付与し、既に毒か猛毒状態\\n\u3000の敵には猛毒状態を付与する。\\n・目の前の敵１キャラに魔法大ダメージを与える。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。\\n\u3000敵が猛毒状態の場合、スタンさせる。\\n・クイーンウタクラゲの付与する毒および猛毒の\\n\u3000ダメージでは、キャラのＴＰが回復しない。');
insert into unit_enemy_data values (314103, 'クイーンウタクラゲ', 314100, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】華のように大海をゆらめき、歌声を奏で\\nるウタクラゲの女王。美しく飾られたその姿の内\\nには猛毒の体液を隠し持つ。\\n\\n・ユニオンバーストは、敵全体にキャラのＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000猛毒状態の敵にはダメージがアップする。\\n\u3000さらに敵に毒状態を付与し、既に毒か猛毒状態\\n\u3000の敵には猛毒状態を付与する。\\n・目の前の敵１キャラに魔法大ダメージを与える。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。\\n\u3000敵が猛毒状態の場合、スタンさせる。\\n・クイーンウタクラゲの付与する毒および猛毒の\\n\u3000ダメージでは、キャラのＴＰが回復しない。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (314104, 'クイーンウタクラゲ', 314104, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ１】襲い来る無数の魔物たち。その歌\\n声は轟然とこだまし舞台を脅かす。ファンの笑顔\\nを守るため、少女たちは歌い踊り、そして戦う。\\n\\n・バトル開始時、ウタクラゲを３体召喚する。\\n・ウタクラゲを１体倒すたびに、残りウタクラゲ\\n\u3000数が１減少する。\\n\u3000その後、ウタクラゲが再度召喚され、パーティ\\n\u3000キャラ全体をノックバックさせる。\\n・ウタクラゲは、残りＨＰが最も高い敵１キャラ\\n\u3000に魔法中ダメージを与え、毒状態を付与する。\\n・ユニオンバーストは、敵全体にキャラのＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000猛毒状態の敵にはダメージがアップする。\\n\u3000さらに敵に毒状態を付与し、既に毒か猛毒状態\\n\u3000の敵には猛毒状態を付与する。\\n・目の前の敵１キャラに魔法大ダメージを与える。\\n・クイーンウタクラゲとウタクラゲの付与する毒\\n\u3000および猛毒のダメージでは、キャラのＴＰが回\\n\u3000復しない。');
insert into unit_enemy_data values (314105, 'クイーンウタクラゲ', 314105, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ２】目の前に現れたのは、過去の\\n自分たち。成長の果て、少女たちは過去を越え、\\nその一瞬一瞬の輝きを歌声に乗せる。\\n\\n・カルミナのシャドウを召喚。\\n・目の前の敵１キャラに魔法大ダメージを与える。');
insert into unit_enemy_data values (314106, 'クイーンウタクラゲ', 314104, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ３】優艶なる華は乱れ、内なる魔性\\nを解き放つ。劇毒の雨音をメロディーに、\\n歌姫は歌う――最期の歌を。\\n\\n・ユニオンバーストは、敵全体にキャラのＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000猛毒状態の敵にはダメージがアップする。\\n\u3000さらに敵に毒状態を付与し、既に毒か猛毒状態\\n\u3000の敵には猛毒状態を付与する。\\n・目の前の敵１キャラに魔法大ダメージを与える。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。\\n\u3000敵が猛毒状態の場合、スタンさせる。\\n・クイーンウタクラゲの付与する毒および猛毒の\\n\u3000ダメージでは、キャラのＴＰが回復しない。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (314200, 'ドクターギグル', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314201, 'ドクターギグル', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】卑劣なる本性を現したオーエドの怪医。\\n研究で手にした究極の肉体で、世界への復讐を\\n果たさんとする。\\n\\n・ユニオンバーストは、敵全体にドクターギグル\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000毒状態にする。\\n・デモンフラスコを召喚し敵全体をノックバック\\n\u3000させる。\\n・デモンフラスコは、一定時間経過すると\\n\u3000ドクターギグルの物理攻撃力を中アップさせ、\\n\u3000ＴＰを特大回復させたあと、消滅する。\\n\u3000ただしデモンフラスコのＨＰが一定値以下に\\n\u3000なった場合は、パーティ全体の物理攻撃力と魔\\n\u3000法攻撃力を特大アップさせ、ＴＰを特大回復さ\\n\u3000せたあと、消滅する。\\n\u3000またその時に、次にドクターギグルが召喚する\\n\u3000デモンフラスコが1段階強化される。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力が\\n\u3000最も高い敵１キャラに物理大ダメージを与え、\\n\u3000さらに行動速度をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。');
insert into unit_enemy_data values (314202, 'ドクターギグル', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】卑劣なる本性を現したオーエドの怪医。\\n研究で手にした究極の肉体で、世界への復讐を\\n果たさんとする。\\n\\n・ユニオンバーストは、敵全体にドクターギグル\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000毒状態にする。\\n・デモンフラスコを召喚し敵全体をノックバック\\n\u3000させる。\\n・デモンフラスコは、一定時間経過すると\\n\u3000ドクターギグルの物理攻撃力を中アップさせ、\\n\u3000ＴＰを特大回復させたあと、消滅する。\\n\u3000ただしデモンフラスコのＨＰが一定値以下に\\n\u3000なった場合は、パーティ全体の物理攻撃力と魔\\n\u3000法攻撃力を特大アップさせ、ＴＰを特大回復さ\\n\u3000せたあと、消滅する。\\n\u3000またその時に、次にドクターギグルが召喚する\\n\u3000デモンフラスコが1段階強化される。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力が\\n\u3000最も高い敵１キャラに物理大ダメージを与え、\\n\u3000さらに行動速度をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。');
insert into unit_enemy_data values (314203, 'ドクターギグル', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】卑劣なる本性を現したオーエドの怪医。\\n研究で手にした究極の肉体で、世界への復讐を\\n果たさんとする。\\n\\n・ユニオンバーストは、敵全体にドクターギグル\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000毒状態にする。\\n・デモンフラスコを召喚し敵全体をノックバック\\n\u3000させる。\\n・デモンフラスコは、一定時間経過すると\\n\u3000ドクターギグルの物理攻撃力を特大アップさせ、\\n\u3000ＴＰを特大回復させたあと、消滅する。\\n\u3000ただしデモンフラスコのＨＰが一定値以下に\\n\u3000なった場合は、パーティ全体の物理攻撃力と魔\\n\u3000法攻撃力を特大アップさせ、ＴＰを特大回復さ\\n\u3000せたあと、消滅する。\\n\u3000またその時に、次にドクターギグルが召喚する\\n\u3000デモンフラスコが1段階強化される。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力が\\n\u3000最も高い敵１キャラに物理大ダメージを与え、\\n\u3000さらに行動速度をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ドクターギグル自身のＨＰが30％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (314204, 'ドクターギグル', 314204, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】幻薬により見せられるは己の虚像。\\n眼前に立ち塞がる邪道の具現を、誠なる医道を\\n以って打ち崩せ。\\n\\n・ミツキとユキのシャドウと魔物を召喚。\\n・目の前の敵１キャラに物理中ダメージを与える。');
insert into unit_enemy_data values (314205, 'ドクターギグル', 314205, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【ＭＯＤＥ２】魔腕から放たれる妖光が地を駆け\\nる。その魔性に呑まれし実験体たちは、我を忘れ\\nて猛り狂う。\\n\\n・魔物を召喚し、敵全体をノックバックさせる。\\n・召喚された魔物を１体倒すたびに、\\n\u3000残りターゲット数が１減少する。\\n\u3000その後、魔物が再度召喚され、敵全体をノック\\n\u3000バックさせる。\\n・ドクターギグルを除く味方全体の物理防御力と\\n\u3000魔法防御力を特大アップ。\\n\u3000ドクターギグルのＨＰが、バトル開始から\\n\u30005000以上と10000以上減少すると、ド\\n\u3000クターギグルの姿が変化し、このスキルの効果\\n\u3000がダウン。');
insert into unit_enemy_data values (314206, 'ドクターギグル', 314200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】肉体の進化は極限へと昇華する。\\n進化の果て、野望の果て、この魔腕で世界を掴ま\\nんと、怪医の激憤が轟く。\\n\\n・ユニオンバーストは、敵全体にドクターギグル\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000毒状態にする。\\n・デモンフラスコを召喚し敵全体をノックバック\\n\u3000させる。\\n・デモンフラスコは、一定時間経過すると\\n\u3000ドクターギグルの物理攻撃力と物理防御力と魔\\n\u3000法防御力を特大アップさせ、ＴＰを特大回復さ\\n\u3000せたあと、消滅する。\\n\u3000ただしデモンフラスコのＨＰが一定値以下に\\n\u3000なった場合は、パーティ全体の物理攻撃力と魔\\n\u3000法攻撃力をバトル終了まで中アップさせ、\\n\u3000ＴＰを特大回復させたあと、消滅する。\\n\u3000またその時に、次にドクターギグルが召喚する\\n\u3000デモンフラスコが1段階強化される。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力が\\n\u3000最も高い敵１キャラに物理特大ダメージを与え、\\n\u3000さらに行動速度をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ドクターギグル自身のＨＰが30％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (314300, '哀暴のわたあめちゃん', 314300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314301, '哀暴のわたあめちゃん', 314301, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】独り心細いなか、金儲けの道具にされ\\n悲哀の感情が暴走し、真の力を解き放った魔犬。\\nその暴走は全てを押し潰すまで止まらない。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。\\n・目の前の敵１キャラに物理ダメージを与える。\\n・前から３キャラの物理/魔法攻撃力を大ダウン\\n\u3000させ、さらにバトル終了まで物理防御力を大\\n\u3000ダウンさせる。\\n・自身の物理攻撃力を小アップさせる。');
insert into unit_enemy_data values (314302, '哀暴のわたあめちゃん', 314301, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】独り心細いなか、金儲けの道具にされ\\n悲哀の感情が暴走し、真の力を解き放った魔犬。\\nその暴走は全てを押し潰すまで止まらない。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。\\n・目の前の敵１キャラに物理ダメージを与える。\\n・前から３キャラの物理/魔法攻撃力を大ダウン\\n\u3000させ、さらにバトル終了まで物理防御力を大\\n\u3000ダウンさせる。\\n・自身の物理攻撃力を小アップさせる。');
insert into unit_enemy_data values (314303, '哀暴のわたあめちゃん', 314300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】独り心細いなか、金儲けの道具にされ\\n悲哀の感情が暴走し、真の力を解き放った魔犬。\\nその暴走は全てを押し潰すまで止まらない。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。この攻撃は物理攻撃力\\n\u3000アップ・ダウン効果の影響を受けやすい。\\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前から３キャラの物理/魔法攻撃力を大ダウン\\n\u3000させ、さらにバトル終了まで物理防御力を大\\n\u3000ダウンさせる。\\n・自身の物理攻撃力を大アップさせる。\\n・残り時間が30秒を切ると、敵全体の物理防御\\n\u3000力を大ダウン、自身の物理/魔法防御力を大\\n\u3000アップさせ、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (314304, '哀暴のわたあめちゃん', 314304, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】異界から迷い込んだ霊が写し鏡\\nの如く皆に化け立ちはだかる。見事勝利をおさ\\nめ世界を救えるか、ハロウィンセイバーズ。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。この攻撃は物理攻撃力\\n\u3000アップ・ダウン効果の影響を受けやすい。\\n・目の前の敵１キャラに物理ダメージを与える。');
insert into unit_enemy_data values (314305, '哀暴のわたあめちゃん', 314305, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】暴走から一転、球体のように丸\\nまってあらゆる攻撃を遮断する。全力を賭した\\n一撃も、この姿の前では一撫でに等しいだろう。\\n\\n・バトル開始時、自身の物理/魔法防御力を大幅\\n\u3000に上昇させる。\\n・バトル中、哀暴のわたあめちゃんは行動しない。');
insert into unit_enemy_data values (314306, '哀暴のわたあめちゃん', 314300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】超特級妖魔としての霊力を最大\\n解放し、世界の均衡を崩す勢いでじゃれる\\nわたあめちゃん。その愛情を全て包み込めるか。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。この攻撃は物理攻撃力\\n\u3000アップ・ダウン効果の影響を受けやすい。\\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前から３キャラの物理/魔法攻撃力を大ダウン\\n\u3000させ、さらにバトル終了まで物理防御力を大\\n\u3000ダウンさせる。\\n・自身の物理攻撃力を大アップさせる。\\n・残り時間が30秒を切ると、敵全体の物理防御\\n\u3000力を大ダウン、自身の物理/魔法防御力を大\\n\u3000アップさせ、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (314400, 'アンチビースト・トリニティ', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314401, 'アンチビースト・トリニティ', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】魔法少女たちのパワーを吸い取って進化\\nしたアンチビースト。ランドソルはこのまま魔の\\n手に堕ちてしまうのか！？負けるなノワールズ！\\n\\n・ユニオンバーストは、前方３キャラのうち、\\n\u3000ＨＰが80％以下のキャラを誘惑状態にする。\\n\u3000その後、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・アンチビーストの下僕を召喚し敵全体をノック\\n\u3000バックさせる。\\n\u3000アンチビーストの下僕は、一定時間経過すると\\n\u3000目の前の敵１キャラを誘惑状態にしたあと、消\\n\u3000滅する。\\n\u3000ただしアンチビーストの下僕のＨＰが一定値\\n\u3000以下になった場合は、パーティ全体の物理攻撃\\n\u3000力と魔法攻撃力を特大アップさせたあと、消滅\\n\u3000する。\\n・前方２キャラに魔法中ダメージを与える。\\n\u3000さらに、自分に物理無効バリアを展開する。\\n・前方２キャラにキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。');
insert into unit_enemy_data values (314402, 'アンチビースト・トリニティ', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】魔法少女たちのパワーを吸い取って進化\\nしたアンチビースト。ランドソルはこのまま魔の\\n手に堕ちてしまうのか！？負けるなノワールズ！\\n\\n・ユニオンバーストは、前方３キャラのうち、\\n\u3000ＨＰが80％以下のキャラを誘惑状態にする。\\n\u3000その後、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・アンチビーストの下僕を召喚し敵全体をノック\\n\u3000バックさせる。\\n\u3000アンチビーストの下僕は、一定時間経過すると\\n\u3000目の前の敵１キャラを誘惑状態にしたあと、消\\n\u3000滅する。\\n\u3000ただしアンチビーストの下僕のＨＰが一定値\\n\u3000以下になった場合は、パーティ全体の物理攻撃\\n\u3000力と魔法攻撃力を特大アップさせたあと、消滅\\n\u3000する。\\n・前方２キャラに魔法中ダメージを与える。\\n\u3000さらに、自分に物理無効バリアを展開する。\\n・前方２キャラにキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。');
insert into unit_enemy_data values (314403, 'アンチビースト・トリニティ', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】魔法少女たちのパワーを吸い取って進化\\nしたアンチビースト。ランドソルはこのまま魔の\\n手に堕ちてしまうのか！？負けるなノワールズ！\\n\\n・ユニオンバーストは、前方３キャラのうち、\\n\u3000ＨＰが80％以下のキャラを誘惑状態にする。\\n\u3000その後、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・アンチビーストの下僕を召喚し敵全体をノック\\n\u3000バックさせる。\\n\u3000アンチビーストの下僕は、一定時間経過すると\\n\u3000目の前の敵１キャラを誘惑状態にしたあと、消\\n\u3000滅する。\\n\u3000ただしアンチビーストの下僕のＨＰが一定値\\n\u3000以下になった場合は、パーティ全体の物理攻撃\\n\u3000力と魔法攻撃力を特大アップさせたあと、消滅\\n\u3000する。\\n・前方２キャラに魔法中ダメージを与える。\\n\u3000さらに、自分に物理無効バリアを展開する。\\n・前方２キャラにキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。\\n・アンチビースト・トリニティ自身のＨＰが\\n\u300030％を切ると、さらに攻撃が激しく凶暴にな\\n\u3000る。');
insert into unit_enemy_data values (314404, 'アンチビースト・トリニティ', 314405, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ１】闇の渦に囚われ希望を失いかけた\\n魔法少女たち―そのとき聞こえてきたのは大事\\nな人からのエールの声。立ち上がれ魔法少女よ！\\n\\n・ユニオンバーストは、前方３キャラのうち、\\n\u3000ＨＰが75%以下のキャラを誘惑状態にする。\\n\u3000その後、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・バトル開始時、敵全体を呪い状態にする。\\n\u3000このスキルにより付与された呪いのダメージ\\n\u3000では、ＴＰが回復しない。\\n\u3000さらに、何らかの効果でＨＰを回復しようと\\n\u3000した場合、本来の回復量の60%をダウンさせ\\n\u3000る。\\n・前方２キャラに魔法中ダメージを与える。');
insert into unit_enemy_data values (314405, 'アンチビースト・トリニティ', 314405, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ２】再び闇のパワーを蓄え出した仇敵。\\nしかし、暴走し始めていたのは敵だけではなかっ\\nた―！？もう誰も、この３人を止められない！\\n\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージ量に関係なく、攻撃を命中\\n\u3000させるたびに徐々に耐久性を失っていき、\\n\u3000490回攻撃を命中させるとバリアは破壊され\\n\u3000る。\\n・前方２キャラに魔法中ダメージを与える。');
insert into unit_enemy_data values (314406, 'アンチビースト・トリニティ', 314400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【ＭＯＤＥ３】戦いはついにクライマックスへ。\\nいとしき生徒の、弟くんの、ドＳさんのために\\n愛と希望と闇を抱いて、突き進めノワールズ！\\n\\n・ユニオンバーストは、前方３キャラのうち、\\n\u3000ＨＰが80％以下のキャラを誘惑状態にする。\\n\u3000その後、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・アンチビーストの下僕を召喚し敵全体をノック\\n\u3000バックさせる。\\n\u3000アンチビーストの下僕は、一定時間経過すると\\n\u3000目の前の敵１キャラを誘惑状態にしたあと、消\\n\u3000滅する。\\n\u3000ただしアンチビーストの下僕のＨＰが一定値\\n\u3000以下になった場合は、パーティ全体の物理攻撃\\n\u3000力と魔法攻撃力を特大アップさせたあと、消滅\\n\u3000する。\\n・前方２キャラに魔法中ダメージを与える。\\n\u3000さらに、自分に物理無効バリアを展開する。\\n・前方２キャラにキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。\\n・アンチビースト・トリニティ自身のＨＰが\\n\u300030％を切ると、さらに攻撃が激しく凶暴にな\\n\u3000る。');
insert into unit_enemy_data values (314500, 'ひとりぼっちの聖夜の妖精', 314500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314501, 'ひとりぼっちの聖夜の妖精', 314500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】遠い昔に人々から忘れられた悲しき妖精。\\n信仰を失い、寂しさを紛らわすかのように悪戯を\\n働き人目を集めようとする。コンテスト会場の混\\n乱を治め、再び信仰を取り戻せるのか！？\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・ひとりぼっちの聖夜の妖精自身の物理/魔法防\\n\u3000御力を極大アップ。');
insert into unit_enemy_data values (314502, 'ひとりぼっちの聖夜の妖精', 314500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】遠い昔に人々から忘れられた悲しき妖精。\\n信仰を失い、寂しさを紛らわすかのように悪戯を\\n働き人目を集めようとする。コンテスト会場の混\\n乱を治め、再び信仰を取り戻せるのか！？\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・ひとりぼっちの聖夜の妖精自身の物理/魔法防\\n\u3000御力を極大アップ。');
insert into unit_enemy_data values (314503, 'ひとりぼっちの聖夜の妖精', 314500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】遠い昔に人々から忘れられた悲しき妖精。\\n信仰を失い、寂しさを紛らわすかのように悪戯を\\n働き人目を集めようとする。コンテスト会場の混\\n乱を治め、再び信仰を取り戻せるのか！？\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・ひとりぼっちの聖夜の妖精自身の物理/魔法防\\n\u3000御力を極大アップ。\\n・ひとりぼっちの聖夜の妖精自身のＨＰが40％\\n\u3000を切ると、自身の物理/魔法防御力を大ダウン\\n\u3000させ、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (314504, 'ひとりぼっちの聖夜の妖精', 314500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】妖精がお菓子で形作ったミヤコた\\nちの甘い猛攻と妖精の悪戯が押し寄せる。聖夜に\\n育んだ輝く絆でニセモノたちを打ち砕け！\\n\\n・ミヤコ、マヒル、リノのシャドウを召喚。\\n・前から３キャラに魔法中ダメージを与え、物理\\n\u3000防御力を特大ダウン。このスキルの効果はダ\\n\u3000メージを無効化しても付与される。\\n\\n');
insert into unit_enemy_data values (314505, 'ひとりぼっちの聖夜の妖精', 314500, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【ＭＯＤＥ２】妖精が袋から取り出したるは魅惑\\nのお菓子。一瞬でも気を許したが最期、甘味な罠\\nに堕ちていく。プリンパワーで甘い幻想を打ち砕\\nけ！\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与え、キャラのＨＰが60%を切って\\n\u3000いる場合、誘惑状態にする。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。');
insert into unit_enemy_data values (314506, 'ひとりぼっちの聖夜の妖精', 314500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】聖夜に独り妖精の哀叫が鳴り響く。\\n傍若無人に暴れる妖精をなだめ、プリンの絆で皆\\nの幸せのクリスマスと妖精の笑顔を取り戻せ！\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・ひとりぼっちの聖夜の妖精自身の物理/魔法防\\n\u3000御力を極大アップ。\\n・ひとりぼっちの聖夜の妖精自身のＨＰが30％\\n\u3000を切ると、さらに攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (314600, '邪牛神モーモン', 314600, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314601, '邪牛神モーモン', 314600, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】縁起物を取り込み、願いの力を吸収して\\n猛り荒ぶる牛の魔物。怒りに身を落とした猛牛が\\n周囲の願いを打ち砕く。\\n\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・最も魔法攻撃力の高い敵１キャラに物理割合\\n\u3000ダメージを与え、ノックバックさせると同時に\\n\u3000スタンさせる。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。');
insert into unit_enemy_data values (314602, '邪牛神モーモン', 314600, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】縁起物を取り込み、願いの力を吸収して\\n猛り荒ぶる牛の魔物。怒りに身を落とした猛牛が\\n周囲の願いを打ち砕く。\\n\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・最も魔法攻撃力の高い敵１キャラに物理割合\\n\u3000ダメージを与え、ノックバックさせると同時に\\n\u3000スタンさせる。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。');
insert into unit_enemy_data values (314603, '邪牛神モーモン', 314600, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】縁起物を取り込み、願いの力を吸収して\\n猛り荒ぶる牛の魔物。怒りに身を落とした猛牛が\\n周囲の願いを打ち砕く。\\n\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・通常攻撃は、目の前の敵１キャラに邪牛神モー\\n\u3000モンの物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・最も魔法攻撃力の高い敵１キャラに物理割合\\n\u3000ダメージを与え、ノックバックさせると同時に\\n\u3000スタンさせる。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (314604, '邪牛神モーモン', 314600, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】力への渇望から魔物は子分を率\\nい、再び略奪へ踏みだす。迫り来るならず者た\\nちを打倒し、おせちの具材を守り抜け。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・邪牛神モーモンおよびハイオークから受けるす\\n\u3000べてのダメージで発生する、パーティキャラの\\n\u3000ＴＰ回復量を中ダウンさせる。\\n・バトル開始時、ハイオークを３体召喚する。\\n・ハイオークを１体倒すたびに、残りハイオーク\\n\u3000数が１減少する。その後、ハイオークが再度\\n\u3000召喚される。\\n・目の前の敵１キャラに魔法小ダメージを与え、\u3000物理防御力を大ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。');
insert into unit_enemy_data values (314605, '邪牛神モーモン', 314605, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】猛牛の強靭な肉体が爆ぜる。\\n怪腕から繰り出される殴打をまともに受けると\\n肉体と、そこに宿る全ての煩悩をも吹き飛ばす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・邪牛神モーモンから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・通常攻撃は、目の前の敵１キャラに邪牛神モー\\n\u3000モンの物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。\\n・敵全体のステータスアップ効果を解除し、一定\\n\u3000時間バトルフィールドを展開する。\\n【バトルフィールド効果】\\n・敵全体の物理攻撃力と魔法攻撃力を100％\\n\u3000ダウンした後、物理攻撃力と魔法攻撃力を極大\\n\u3000アップ。\\n・邪牛神モーモンの物理攻撃力を100％ダウン\\n\u3000した後、物理攻撃力を極大アップ。');
insert into unit_enemy_data values (314606, '邪牛神モーモン', 314605, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】猛牛は痛手を負おうとも、鼻息\\nを荒げ立ちはだかる。妄執に取りつかれた迷惑\\nな魔物を打ち倒し、謹賀新年を取り戻せ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・邪牛神モーモンから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・最も魔法攻撃力の高い敵１キャラに物理割合\\n\u3000ダメージを与え、ノックバックさせると同時に\\n\u3000スタンさせる。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。');
insert into unit_enemy_data values (314700, 'グレーターゴーレム', 314700, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314701, 'グレーターゴーレム', 314700, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】同族のゴーレムを次々に呼び寄せる\\n岩石の魔物。大地を揺さぶる巨腕が冒険者たちに\\n襲い掛かる。\\n\\n・主人公が目覚めていないため、本バトルでは\\n\u3000全キャラクターのユニオンバーストが発動不能。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・ユニオンバーストは、前方4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・敵全体をノックバックさせ、ゴーレムを召喚す\\n\u3000る。さらに自分の物理攻撃力を中アップさせ\\n\u3000る。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (314702, 'グレーターゴーレム', 314700, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】同族のゴーレムを次々に呼び寄せる\\n岩石の魔物。大地を揺さぶる巨腕が冒険者たちに\\n襲い掛かる。\\n\\n・主人公が目覚めていないため、本バトルでは\\n\u3000全キャラクターのユニオンバーストが発動不能。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・ユニオンバーストは、前方4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・敵全体をノックバックさせ、ゴーレムを召喚す\\n\u3000る。さらに自分の物理攻撃力を中アップさせ\\n\u3000る。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (314703, 'グレーターゴーレム', 314700, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】同族のゴーレムを次々に呼び寄せる\\n岩石の魔物。大地を揺さぶる巨腕が冒険者たちに\\n襲い掛かる。\\n\\n・主人公が目覚めていないため、本バトルでは\\n\u3000全キャラクターのユニオンバーストが発動不能。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・ユニオンバーストは、前方4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・敵全体をノックバックさせ、ゴーレムを召喚す\\n\u3000る。さらに自分の物理攻撃力を中アップさせ\\n\u3000る。このスキルの効果は発動するたびにアッ\\n\u3000プする。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (314704, 'グレーターゴーレム', 314704, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】巨岩の合図に隷属したゴーレムが\\n冒険者の前に立ち塞がる。岩の魔物たちは、ただ\\nひたすら大地を震わせ、侵攻する。\\n\\n・主人公が目覚めていないため、本バトルでは\\n\u3000全キャラクターのユニオンバーストが発動不能。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・バトル開始時、自分の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、前方4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。');
insert into unit_enemy_data values (314705, 'グレーターゴーレム', 314704, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】森の奥から突如、現れた数多の\\n虚像たち。自分たちの似姿の前に本当の絆が\\n試される。\\n\\n・主人公が目覚めていないため、本バトルでは\\n\u3000全キャラクターのユニオンバーストが発動不能。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・バトル開始時、自分の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・敵全体をノックバックさせ複数のシャドウを召\\n\u3000喚する。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (314706, 'グレーターゴーレム', 314706, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】ひび割れた巨岩の咆哮に岩々が\\n再び立ちはだかる。岩の躯体の奥から覗く紅き\\n瞳が敵を見据え、巨大な剛腕で全てを薙ぎ払う。\\n\\n・主人公が目覚めていないため、本バトルでは\\n\u3000全キャラクターのユニオンバーストが発動不能。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・バトル開始時、自分の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、前方4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・敵全体をノックバックさせ、ゴーレムを召喚す\\n\u3000る。さらに自分の物理攻撃力を中アップさせ\\n\u3000る。このスキルの効果は発動するたびにアッ\\n\u3000プする。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (314800, 'オーバーロードフォース', 314800, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (314801, 'オーバーロードフォース', 314800, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】『強さを求める願い』から生まれた力。\\n本当の強さとは何か？\u3000自分自身に問い続け答え\\nを見つけられるのか。絆を取り戻すべく立ち上が\\nれ。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。さらに、オーバーロードスフィアの\\n\u3000ターゲットがブレイクしていない場合、\\n\u3000ダメージがアップする。\\n・敵全体に物理中ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。さらに、オーバーロード\\n\u3000スフィアのターゲットがブレイクしていない場\\n\u3000合、ダメージとスキルの効果がアップする。こ\\n\u3000のスキルの効果はダメージを無効化しても付与\\n\u3000される。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。');
insert into unit_enemy_data values (314802, 'オーバーロードフォース', 314800, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】『強さを求める願い』から生まれた力。\\n本当の強さとは何か？\u3000自分自身に問い続け答え\\nを見つけられるのか。絆を取り戻すべく立ち上が\\nれ。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。さらに、オーバーロードスフィアの\\n\u3000ターゲットがブレイクしていない場合、\\n\u3000ダメージがアップする。\\n・敵全体に物理中ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。さらに、オーバーロード\\n\u3000スフィアのターゲットがブレイクしていない場\\n\u3000合、ダメージとスキルの効果がアップする。こ\\n\u3000のスキルの効果はダメージを無効化しても付与\\n\u3000される。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。');
insert into unit_enemy_data values (314803, 'オーバーロードフォース', 314800, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】『強さを求める願い』から生まれた力。\\n本当の強さとは何か？\u3000自分自身に問い続け答え\\nを見つけられるのか。絆を取り戻すべく立ち上が\\nれ。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。さらに、オーバーロードスフィアの\\n\u3000ターゲットがブレイクしていない場合、\\n\u3000ダメージがアップする。\\n・敵全体に物理中ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。さらに、オーバーロード\\n\u3000スフィアのターゲットがブレイクしていない場\\n\u3000合、ダメージとスキルの効果がアップする。こ\\n\u3000のスキルの効果はダメージを無効化しても付与\\n\u3000される。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。');
insert into unit_enemy_data values (314804, 'オーバーロードフォース', 314804, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】器から溢れ出した過負荷の力に\\nより創造された仮初の【美食殿】。再び繋がった\\nこの絆で、自分を超えていけ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オーバーロードフォースから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ペコリーヌ、コッコロ、キャル、シェフィのシ\\n\u3000ャドウを召喚。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。\\n');
insert into unit_enemy_data values (314805, 'オーバーロードフォース', 314805, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】溢れ出た力の球塊の脈動が変化し\\n殲滅の強襲をかける。剣の雨を突破し、思いの刃\\nは届くのか？\u3000全力を超越し、進むべき道を\\n示せ！\\n\\n・バトル開始時、オーバーロードスフィアが起動\\n\u3000し、本体のさらなる力を解放する。\\n\u3000敵全体のＨＰ吸収を特大ダウンさせ、さらに攻\\n\u3000撃が激しく強力になる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オーバーロードフォースから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理特大\\n\u3000ダメージを与える。\\n・敵全体に物理大ダメージを与え、物理防御力を\\n\u3000特大ダウンさせる。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。\\n');
insert into unit_enemy_data values (314806, 'オーバーロードフォース', 314804, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】溢れ出たもう一つの力は形を変え\\n蒼き剣閃となり、流星のごとく降り注ぐ。歩んだ\\n道と結んだ絆の証明。僕のつなぐ未来へ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オーバーロードフォースから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。さらに、オーバーロードスフィアの\\n\u3000ターゲットがブレイクしていない場合、\\n\u3000ダメージがアップする。\\n・敵全体に物理中ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。さらに、オーバーロード\\n\u3000スフィアのターゲットがブレイクしていない場\\n\u3000合、ダメージとスキルの効果がアップする。こ\\n\u3000のスキルの効果はダメージを無効化しても付与\\n\u3000される。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。');
insert into unit_enemy_data values (314901, 'ゴブリンロード＆ゴブミニオン', 314901, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ１】砂瀑一帯を根城にするゴブリン族\\nの首魁。居城までたどり着いた手練れの冒険者を\\n子分を引き連れ、一斉攻撃で迎え撃つ。\\n\\n▼ＭＯＤＥ１突破条件\\nダメージを与え、ゴブリンロード＆ゴブミニオン\\nのＨＰを8880万以下にすること。\\n\\n・バトル開始時、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果\\n\u3000で上昇した防御力は、バトル中に受ける防御\\n\u3000力ダウンスキルの影響を受けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て、一度の行動で与えるダメージの値が一定\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ゴブリンロード＆ゴブミニオンから受けるす\\n\u3000べてのダメージで発生する、パーティキャラ\\n\u3000のＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大き\\n\u3000く吹き飛ばす。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n・装甲車に乗っているゴブミニオンのターゲッ\\n\u3000トは、ブレイクすると消滅し、ゴブリンロー\\n\u3000ド＆ゴブミニオンの物理防御力と魔法防御力\\n\u3000が小ダウンする。\\n・装甲車のコアのターゲットは、ブレイクする\\n\u3000と、ゴブリンロード＆ゴブミニオンの物理防\\n\u3000御力と魔法防御力が小ダウンする。\\n・ゴブリンロード＆ゴブミニオンのターゲット\\n\u3000が全てブレイクした時、物理防御力と魔法防\\n\u3000御力が特大ダウンし、攻撃行動を変更する。\\n・行動変更後、コアにエネルギーを溜め始めて\\n\u3000一定時間経過すると、自身にＴＰ継続回復状\\n\u3000態を付与する。エネルギーを溜めている間に\\n\u3000一定ダメージを与えると、スキルが中断され、\\n\u3000自身を火傷状態にする。\\n・バトルがタイムアップすると、敵全体を戦闘\\n\u3000不能にする。');
insert into unit_enemy_data values (315001, 'ゴブリンロード', 315001, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ２】装甲車を木端に破壊され怒る首魁。\\nゴブリン族のつわものを配し、冒険者の次なる壁\\nとし、容易く突破を許さない。\\n\\n▼ＭＯＤＥ２突破条件\\nダメージを与え、ゴブリングレートとゴブリン\\nメイスターのＨＰを０にすること。\\n\\n・バトル開始時、自身を無敵状態にして攻撃を\\n\u3000受け付けなくする。\\n・ゴブリンロードから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの残り\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・バトルがタイムアップすると、敵全体を戦闘\\n\u3000不能にする。');
insert into unit_enemy_data values (315002, 'ゴブリンロード', 315002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【ＭＯＤＥ３】砂瀑に君臨するゴブリン族の首魁。\\n配下を屠られた怒りを武器にのせ、圧倒的な力で\\n眼前の全てを塵に変える。\\n\\n▼ＭＯＤＥ３突破条件\\nダメージを与え、ゴブリンロードのＨＰを０にす\\nること。\\n\\n・バトル開始時、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果\\n\u3000で上昇した防御力は、バトル中に受ける防御\\n\u3000力ダウンスキルの影響を受けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て、一度の行動で与えるダメージの値が一定\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ゴブリンロードから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの残り\\n\u3000ＨＰに応じた物理割合ダメージを与え、自身\\n\u3000の物理攻撃力を大アップさせる。自身の物理\\n\u3000攻撃力に応じて与えるダメージの割合が増加\\n\u3000する。\\n・敵全体に物理大ダメージを与え、スタンさせ\\n\u3000る。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・前方範囲内の敵に物理大ダメージを与え、大\\n\u3000きく吹き飛ばす。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・前方１キャラにキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・残りＨＰが1872万を下回ると、物理攻撃力\\n\u3000と行動速度が特大アップし、さらに攻撃が\\n\u3000激しく凶暴になる。\\n・バトルがタイムアップすると、敵全体を戦闘\\n\u3000不能にする。');
insert into unit_enemy_data values (315100, '讐鼠・怒髪天のチュウジ', 315100, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (315101, '讐鼠・怒髪天のチュウジ', 315100, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ネズミ一家の偉大な大親分。牧場で敗北\\nを喫し、救護院へと落ち延びた。今、時は満ち、\\n故郷を取り戻すためのリベンジを仕掛ける。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を中ダウンさせる。復讐の\\n\u3000炎に燃えている場合、物理防御力ダウンが無く\\n\u3000なる代わりに、与えるダメージがアップする。\\n・前から１番目のキャラを中心とした範囲内の敵\\n\u3000の物理防御力と魔法防御力を中ダウンさせる。\\n・味方全体の物理攻撃力を中アップさせ、自身の\\n\u3000TPを特大回復させる。\\n・前から１番目のキャラに物理小ダメージ。\\n・讐鼠・ステゴロのチュウザが討伐されていた場\\n\u3000合、バトルスタートの際、もしくは讐鼠・怒髪\\n\u3000天のチュウジが通常攻撃を行った際に、復讐の\\n\u3000炎に燃え、攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (315102, '讐鼠・怒髪天のチュウジ', 315100, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ネズミ一家の偉大な大親分。牧場で敗北\\nを喫し、救護院へと落ち延びた。今、時は満ち、\\n故郷を取り戻すためのリベンジを仕掛ける。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を中ダウンさせる。復讐の\\n\u3000炎に燃えている場合、物理防御力ダウンが無く\\n\u3000なる代わりに、与えるダメージがアップする。\\n・前から１番目のキャラを中心とした範囲内の敵\\n\u3000の物理防御力と魔法防御力を大ダウンさせる。\\n・味方全体の物理攻撃力を中アップさせ、自身の\\n\u3000TPを特大回復させる。\\n・前から１番目のキャラに物理小ダメージ。\\n・讐鼠・ステゴロのチュウザが討伐されていた場\\n\u3000合、バトルスタートの際、もしくは讐鼠・怒髪\\n\u3000天のチュウジが通常攻撃を行った際に、復讐の\\n\u3000炎に燃え、攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (315103, '讐鼠・怒髪天のチュウジ', 315100, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ネズミ一家の偉大な大親分。牧場で敗北\\nを喫し、救護院へと落ち延びた。今、時は満ち、\\n故郷を取り戻すためのリベンジを仕掛ける。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を中ダウンさせる。復讐の\\n\u3000炎に燃えている場合、物理防御力ダウンが無く\\n\u3000なる代わりに、与えるダメージがアップする。\\n・前から１番目のキャラを中心とした範囲内の敵\\n\u3000の物理防御力と魔法防御力を大ダウンさせる。\\n・味方全体の物理攻撃力を中アップさせ、自身の\\n\u3000TPを特大回復させる。\\n・前から１番目のキャラに物理小ダメージ。\\n・讐鼠・ステゴロのチュウザが討伐されていた場\\n\u3000合、バトルスタートの際、もしくは讐鼠・怒髪\\n\u3000天のチュウジが通常攻撃を行った際に、復讐の\\n\u3000炎に燃え、攻撃が激しく凶暴になる。');
insert into unit_enemy_data values (315104, '讐鼠・怒髪天のチュウジ', 315104, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】大親分の威光が、再び牧場に輝く。\\n舎弟ネズミが会場内を埋め尽くし、一家総出の\\n抗争の幕が切って落とされる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・怒髪天のチュウジから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・バトル開始時、舎弟ネズミを３体召喚し、敵全\\n\u3000体をノックバックさせる。\\n・舎弟ネズミを１体倒すたびに、残り舎弟ネズミ\\n\u3000数が１減少する。その後、舎弟ネズミが再度召\\n\u3000喚され、敵全体をノックバックさせる。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (315105, '讐鼠・怒髪天のチュウジ', 315104, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】次々倒される舎弟ネズミに、過去\\nの惨劇を重ねる。捲土重来、この劣勢を押し返さ\\nんと大親分自ら武器を取る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・怒髪天のチュウジから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を中ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (315106, '讐鼠・怒髪天のチュウジ', 315104, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】一家の暮らしを守らんと、赤鼠の\\n怒号が会場に響く。社会から除け者にされた悲し\\nき魔物は、家族の存続を懸けて全力の拳を振るう。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・怒髪天のチュウジから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を中ダウンさせる。復讐の\\n\u3000炎に燃えている場合、物理防御力ダウンが無く\\n\u3000なる代わりに、与えるダメージがアップする。\\n・前から１番目のキャラを中心とした範囲内の敵\\n\u3000の物理防御力と魔法防御力を大ダウンさせる。\\n・味方全体の物理攻撃力を中アップさせ、自身の\\n\u3000TPを特大回復させる。\\n・前から１番目のキャラに物理小ダメージ。\\n・讐鼠・ステゴロのチュウザが討伐されていた場\\n\u3000合、バトルスタートの際、もしくは讐鼠・怒髪\\n\u3000天のチュウジが通常攻撃を行った際に、復讐の\\n\u3000炎に燃え、攻撃が激しく凶暴になる。');
