insert into unit_enemy_data values (315201, '讐鼠・ステゴロのチュウザ', 315200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ネズミ一家の頼れる若頭。かつて拳一つ\\nで漢を見せた猛き闘鼠は、一家の危機を救うため、\\nヒカリモノに手を染めて抗争に身を投じる。\\n\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理小ダメージを与え、\\n\u3000物理防御力を小ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (315202, '讐鼠・ステゴロのチュウザ', 315200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ネズミ一家の頼れる若頭。かつて拳一つ\\nで漢を見せた猛き闘鼠は、一家の危機を救うため、\\nヒカリモノに手を染めて抗争に身を投じる。\\n\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理小ダメージを与え、\\n\u3000物理防御力を小ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (315203, '讐鼠・ステゴロのチュウザ', 315200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】ネズミ一家の頼れる若頭。かつて拳一つ\\nで漢を見せた猛き闘鼠は、一家の危機を救うため、\\nヒカリモノに手を染めて抗争に身を投じる。\\n\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理小ダメージを与え、\\n\u3000物理防御力を小ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (315204, '讐鼠・ステゴロのチュウザ', 315204, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, 'ネズミ一家随一の武闘派。再び一家総出で事を\\n構えることに血を滾らせ、好戦的な目を光らせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・ステゴロのチュウザから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (315205, '讐鼠・ステゴロのチュウザ', 315204, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '暴れ切り裂く一家の特攻隊長。常に前線に立ち、\\nその背中で若い衆を導いてきた。一刀入魂、気合\\nを入れた決死の一撃で相手の鎧を削ぎ落す。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・ステゴロのチュウザから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理小ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。\\n・讐鼠・ステゴロのチュウザ自身の残りＨＰが\\n\u300050%未満になると、気絶してしまい、行動し\\n\u3000なくなる。さらに、攻撃の対象にならなくなる。');
insert into unit_enemy_data values (315206, '讐鼠・ステゴロのチュウザ', 315206, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '恐れられながらも慕われる一家の兄貴分。家族の\\nため、散ることさえ厭わない熱き若頭は、自分た\\nちの未来を全身全霊の一刀で切り拓かんとする。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・ステゴロのチュウザから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理小ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (315300, '魂喰らいの凶蛇', 315300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】塔の魔力により顕現した、凶々しき霊蛇。\\n怨嗟に満ちたその咢で、冒険者の魂を貪り食う。\\n\\n・魂喰らいの凶蛇が保持している【吸魂】の数に\\n\u3000応じて、通常攻撃と各スキルの効果が強化され\\n\u3000る。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体に魂喰らいの凶蛇\\n\u3000が保持している【吸魂】の数に応じた魔法割合\\n\u3000ダメージを与え、さらに【吸魂】を５つ追加す\\n\u3000る。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを展\\n\u3000開する。ＴＰの減少量とフィールドの効果値は、\\n\u3000魂喰らいの凶蛇が保持している【吸魂】の数が\\n\u3000多い程強化される。\\n・攻撃するたびに魂喰らいの凶蛇に【吸魂】を１\\n\u3000つ追加する分身体を２体召喚し、さらに敵全体\\n\u3000を小さく吹き飛ばす。\\n・バトル開始時に、自身の物理攻撃力と魔法攻撃\\n\u3000力を中アップさせるが、ダメージを受けるたび\\n\u3000に、魂喰らいの凶蛇の【吸魂】が１つ減少する\\n\u3000状態にする。\\n・残りＨＰが30％を切ると、魔法攻撃力が大\\n\u3000アップし、さらに【吸魂】を20追加する。');
insert into unit_enemy_data values (315400, '大慾暴君・カジノ王', 315400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (315401, '大慾暴君・カジノ王', 315400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】利己心にまみれた、非道なる大慾暴君。\\n『龍の卵』による蛮力で対敵を排除せんとする。\\n\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バリアを張り、大慾暴君・カジノ王自身の\\n\u3000物理/魔法防御力を極大アップ。\\n・大慾暴君・カジノ王自身のＨＰが50％以下に\\n\u3000なると攻撃が激しく強力になる。\\n・サイコロを振り、大慾暴君・カジノ王自身の物\\n\u3000理攻撃力がアップする。出目によって物理攻撃\\n\u3000力アップの効果が変化する。\\n\u3000出目が１の場合、物理攻撃力を小アップ。\\n\u3000出目が２及び３の場合、物理攻撃力を中アップ。\\n\u3000出目が４及び５の場合、物理攻撃力を大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n\u3000大慾暴君・カジノ王のＨＰが50％以下の場合、\\n\u3000このスキルを使用する。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (315402, '大慾暴君・カジノ王', 315400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】利己心にまみれた、非道なる大慾暴君。\\n『龍の卵』による蛮力で対敵を排除せんとする。\\n\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バリアを張り、大慾暴君・カジノ王自身の\\n\u3000物理/魔法防御力を極大アップ。\\n・大慾暴君・カジノ王自身のＨＰが50％以下に\\n\u3000なると攻撃が激しく強力になる。\\n・サイコロを振り、大慾暴君・カジノ王自身の物\\n\u3000理攻撃力がアップする。出目によって物理攻撃\\n\u3000力アップの効果が変化する。\\n\u3000出目が１の場合、物理攻撃力を小アップ。\\n\u3000出目が２及び３の場合、物理攻撃力を中アップ。\\n\u3000出目が４及び５の場合、物理攻撃力を大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n\u3000大慾暴君・カジノ王のＨＰが50％以下の場合、\\n\u3000このスキルを使用する。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (315403, '大慾暴君・カジノ王', 315400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】利己心にまみれた、非道なる大慾暴君。\\n『龍の卵』による蛮力で対敵を排除せんとする。\\n\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バリアを張り、大慾暴君・カジノ王自身の\\n\u3000物理/魔法防御力を極大アップ。\\n・大慾暴君・カジノ王自身のＨＰが50％以下に\\n\u3000なると攻撃が激しく強力になる。\\n・サイコロを振り、大慾暴君・カジノ王自身の物\\n\u3000理攻撃力がアップする。出目によって物理攻撃\\n\u3000力アップの効果が変化する。\\n\u3000出目が１の場合、物理攻撃力を小アップ。\\n\u3000出目が２及び３の場合、物理攻撃力を中アップ。\\n\u3000出目が４及び５の場合、物理攻撃力を大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n\u3000大慾暴君・カジノ王のＨＰが50％以下の場合、\\n\u3000このスキルを使用する。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (315404, '大慾暴君・カジノ王', 315404, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】狂える無数の遊戯台が襲い来る。\\nリールが示すギャンブルの結末は、生か死か…？\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・大慾暴君・カジノ王及びスロットから受けるす\\n\u3000べてのダメージで発生する、パーティキャラの\\n\u3000ＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バトル開始時に、スロットを３体召喚し敵全体\\n\u3000をノックバックさせる。一定時間経過すると、\\n\u3000さらにスロットを召喚する。\\n\u3000スロットは前から１番目のキャラに物理中ダ\\n\u3000メージを与える。スロットのＨＰが一定値以下\\n\u3000になった時、味方全体の物理防御力と魔法防御\\n\u3000力を大ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。');
insert into unit_enemy_data values (315405, '大慾暴君・カジノ王', 315405, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】傲慢なる無頼漢は『龍の卵』の力\\nで少女たちを退け、その顔に嘲笑を浮かべる。\\n不屈の覚悟をもって、怪しく煌めく障壁を穿け。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージ量に関係なく、攻撃を命中\\n\u3000させるたびに徐々に耐久性を失っていき、\\n\u3000550回攻撃を命中させるとバリアは破壊され\\n\u3000る。\\n\\n\\n');
insert into unit_enemy_data values (315406, '大慾暴君・カジノ王', 315406, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】カジノ王は秘宝の真なる力を解放\\nし、肥大した我欲をもって邪魔者を葬らんとする\\n怪盗少女よ、今こそ暴君の野望を打ち砕け！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・大慾暴君・カジノ王から受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バリアを張り、大慾暴君・カジノ王自身の\\n\u3000物理/魔法防御力を極大アップ。\\n・大慾暴君・カジノ王自身のＨＰが50％以下に\\n\u3000なると攻撃が激しく強力になる。\\n・サイコロを振り、大慾暴君・カジノ王自身の物\\n\u3000理攻撃力がアップする。出目によって物理攻撃\\n\u3000力アップの効果が変化する。\\n\u3000出目が１の場合、物理攻撃力を小アップ。\\n\u3000出目が２及び３の場合、物理攻撃力を中アップ。\\n\u3000出目が４及び５の場合、物理攻撃力を大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n\u3000大慾暴君・カジノ王のＨＰが50％以下の場合、\\n\u3000このスキルを使用する。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (316000, '解放されし財宝の守護者', 316000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (316001, '解放されし財宝の守護者', 316000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】大海賊の財宝を守る高度な自動人形。\\n数多の試練を乗り越えた冒険者の前に立ち塞がる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・前方１キャラを中心にした小範囲内の敵すべて\\n\u3000に物理大ダメージを与え、物理防御力を大ダウ\\n\u3000ンさせる。\\n・自身の物理防御力と魔法防御力を極大アップさ\\n\u3000せる。財宝の守護者が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けていると、自身の物理防御力\\n\u3000と魔法防御力がアップする時間が短くなり、極\\n\u3000大アップではなく小アップさせる。\\n・財宝の守護者自身のＨＰが40％を切ると、自\\n\u3000身の物理攻撃力を大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。その後、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与え、一\\n\u3000定時間、ユニオンバーストのみ使用できない状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (316002, '解放されし財宝の守護者', 316000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】大海賊の財宝を守る高度な自動人形。\\n数多の試練を乗り越えた冒険者の前に立ち塞がる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・前方１キャラを中心にした小範囲内の敵すべて\\n\u3000に物理大ダメージを与え、物理防御力を大ダウ\\n\u3000ンさせる。\\n・自身の物理防御力と魔法防御力を極大アップさ\\n\u3000せる。財宝の守護者が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けていると、自身の物理防御力\\n\u3000と魔法防御力がアップする時間が短くなり、極\\n\u3000大アップではなく小アップさせる。\\n・財宝の守護者自身のＨＰが40％を切ると、自\\n\u3000身の物理攻撃力を大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。その後、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与え、一\\n\u3000定時間、ユニオンバーストのみ使用できない状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (316003, '解放されし財宝の守護者', 316000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】大海賊の財宝を守る高度な自動人形。\\n数多の試練を乗り越えた冒険者の前に立ち塞がる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・前方１キャラを中心にした小範囲内の敵すべて\\n\u3000に物理大ダメージを与え、物理防御力を大ダウ\\n\u3000ンさせる。\\n・自身の物理防御力と魔法防御力を極大アップさ\\n\u3000せる。財宝の守護者が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けていると、自身の物理防御力\\n\u3000と魔法防御力がアップする時間が短くなり、極\\n\u3000大アップではなく小アップさせる。\\n・財宝の守護者自身のＨＰが40％を切ると、自\\n\u3000身の物理攻撃力を大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。その後、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与え、一\\n\u3000定時間、ユニオンバーストのみ使用できない状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (316004, '解放されし財宝の守護者', 316004, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ１】侵入者を前にオートマタは再び動\\nき出す。使命を果たさんと機体の耐久限界を超え\\nて放たれる光線は、眼前の障害を全て焼き尽くす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・財宝の守護者から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・前方１キャラを中心にした小範囲内の敵すべて\\n\u3000に物理大ダメージを与え、物理防御力を大ダウ\\n\u3000ンさせる。\\n・前方３キャラに物理大ダメージを与える。さら\\n\u3000に自身にも物理ダメージを与え、物理防御力と\\n\u3000魔法防御力を一定時間極大ダウンさせ、機能停\\n\u3000止する。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (316005, '解放されし財宝の守護者', 316005, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ２】自動人形の咆哮に呼応し、暗き巌\\n窟の奥より頑強な魔物たちが姿を現す。不気味に\\n残響する堅岩の軋みが、冒険者を恐怖に陥れる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・財宝の守護者及びブルーゴーレム、ゲートキー\\n\u3000パーから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・前方１キャラを中心にした小範囲内の敵すべて\\n\u3000に物理大ダメージを与え、物理防御力を大ダウ\\n\u3000ンさせる。\\n・前から１番目のキャラに物理大ダメージ。');
insert into unit_enemy_data values (316006, '解放されし財宝の守護者', 316004, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【ＭＯＤＥ３】財宝を護り続けた躯体が最後の力\\nを解き放つ。リミッターを失ったマリオネットを\\n必殺の一撃で打ち倒せ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・財宝の守護者から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・前方１キャラを中心にした小範囲内の敵すべて\\n\u3000に物理大ダメージを与え、物理防御力を大ダウ\\n\u3000ンさせる。\\n・自身の物理防御力と魔法防御力を極大アップさ\\n\u3000せる。財宝の守護者が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けていると、自身の物理防御力\\n\u3000と魔法防御力がアップする時間が短くなり、極\\n\u3000大アップではなく小アップさせる。\\n・財宝の守護者自身のＨＰが30％を切ると、自\\n\u3000身の物理攻撃力を大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。その後、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与え、一\\n\u3000定時間、ユニオンバーストのみ使用できない状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・前から１番目のキャラに物理大ダメージ。');
